INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (132, 31492208, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: информация о процессоре не указана, поэтому невозможно оценить соответствие (0 баллов).\\n2. ОЗУ: информация о количестве ОЗУ отсутствует (0 баллов).\\n3. SSD: информация о SSD отсутствует (0 баллов).\\n4. Операционная система: информация об операционной системе отсутствует (0 баллов).\\n5. Гарантийный срок: информация о гарантийном сроке отсутствует (0 баллов).\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не является частью основных требований (2 балла).\\nИтоговая оценка: 2 из 10.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (133, 31489850, 'Продукты питания', 'Продукты питания', 'Продукты питания', 'https://eep.mitwork.kz/ru/publics/buy/43154', 4107200, 'лот', 'KZT', NULL, 0, '"\"Продукт не соответствует спецификациям, так как он не является шубатом, вырабатываемым из цельного пастеризованного верблюжьего молока. Также отсутствует информация о скашивании молока культурами молочнокислых бактерий и молочных дрожжей. Нет упоминания о соответствии стандарту МСТ 7176-2017.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (134, 31487234, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется, что это Intel Core i5. Это снижает оценку, так как нет точного соответствия спецификации. \\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Это прямое несоответствие спецификации. \\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. Это прямое несоответствие спецификации. \\n4. Операционная система: В описании продукта нет информации об операционной системе. Это прямое несоответствие спецификации. \\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Это прямое несоответствие спецификации. \\n6. Компактный корпус и достаточное количество портов соответствуют общим ожиданиям, но не являются частью предоставленных спецификаций.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (135, 31486610, 'Расчет стоимости — Проектное бюро РАССВЕТ', 'Укажите величину объекта: общую площадь, длину, объем или иную единицу измерения объекта, определяемую заданием на проектирование. Отметьте стадию проектирования, примените необходимые коэффициенты и выберите разделы проектной документации.', 'Стадия проектирования: ПП (предпроектное предложение) - +7,5%, П (проектная документация) - 40%, Р (рабочая документация) - 60%, Р+П (проектная и рабочая документация) - 100%. В случае сокращения сроков проектирования: +10% при сокращение сроков в 1,2 раза, +30% при сокращение сроков в 1,4 раза, +40% при сокращение сроков в 2 раза и более. Различные коэффициенты и скидки в зависимости от типа объекта и условий проектирования.', 'https://pbrassvet.ru/calculator/', 0, 'тыс.', 'руб', NULL, 7, '"\"Продукт находится на стадии проектирования П (проектная документация), что соответствует 40% готовности. Сроки проектирования не указаны, поэтому невозможно оценить сокращение сроков. Корпус 1 имеет 3 этажа, площадь постройки 1517.2 м2, общая площадь 2529.9 м2, объем здания 10822.8 м3, что соответствует спецификациям. Корпус 2 не имеет указания этажности, но площадь застройки 419.2 м2, общая площадь 624 м2, объем здания 3353.3 м3 соответствуют спецификациям. Отсутствие информации о сроках проектирования и этажности корпуса 2 снижает оценку.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (136, 31487234, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Компактный корпус: не указано в спецификациях, но можно считать плюсом. \\n2. Процессор: не указано, какой именно процессор, но ''неплохой процессор'' не является достаточной информацией для оценки соответствия. \\n3. Количество портов: не указано в спецификациях, но можно считать плюсом. \\n4. ОЗУ: не указано. \\n5. SSD: не указано. \\n6. Операционная система: не указано. \\n7. Гарантийный срок: не указано.\\n\\nИтог: Продукт не предоставляет достаточной информации для оценки соответствия спецификациям. Основные параметры, такие как процессор, ОЗУ, SSD, операционная система и гарантийный срок, не указаны.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (137, 31486610, 'Расчет стоимости — Проектное бюро РАССВЕТ', 'Укажите величину объекта: общую площадь, длину, объем или иную единицу измерения объекта, определяемую заданием на проектирование. Отметьте стадию проектирования, примените необходимые коэффициенты и выберите разделы проектной документации.', 'Стадия проектирования: ПП (предпроектное предложение) - +7,5%, П (проектная документация) - 40%, Р (рабочая документация) - 60%, Р+П (проектная и рабочая документация) - 100%. В случае сокращения сроков проектирования: +10% при сокращение сроков в 1,2 раза, +30% при сокращение сроков в 1,4 раза, +40% при сокращение сроков в 2 раза и более. Различные коэффициенты и скидки в зависимости от условий проектирования.', 'https://pbrassvet.ru/calculator/', 0, 'тыс.', 'руб', NULL, 8, '"\"Продукт находится на стадии проектирования П (проектная документация), что соответствует 40% готовности. Это соответствует спецификациям. \\n\\nСтадия проектирования: ПП (предпроектное предложение) - +7,5%, П (проектная документация) - 40%, Р (рабочая документация) - 60%, Р+П (проектная и рабочая документация) - 100%. \\n\\nСокращение сроков проектирования не указано, поэтому дополнительные проценты не добавляются. \\n\\nКорпус 1: \\n- Этажность: 3 этажа (соответствует спецификациям)\\n- Площадь постройки: 1517.2 м2 (соответствует спецификациям)\\n- Общая площадь: 2529.9 м2 (соответствует спецификациям)\\n- Объем здания: 10822.8 м3 (соответствует спецификациям)\\n\\nКорпус 2: \\n- Этажность: не указана (несоответствие спецификациям)\\n- Площадь застройки: 419.2 м2 (соответствует спецификациям)\\n- Общая площадь: 624 м2 (соответствует спецификациям)\\n- Объем здания: 3353.3 м3 (соответствует спецификациям)\\n\\nОбщая оценка соответствия: 8 из 10. Продукт в целом соответствует спецификациям, но отсутствует информация об этажности корпуса 2.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (138, 31497902, 'Бумага Снегурочка A4, 80г/м2, яркость ISO 96%, 500 листов', 'Бумага Снегурочка формата A4, плотностью 80г/м2 и яркостью ISO 96%. Упаковка содержит 500 листов.', 'Формат: A4, Плотность: 80г/м2, Яркость: ISO 96%, Количество листов: 500', 'https://www.foroffice.ru/products/description/134348.html', 360, 'упаковка', 'руб.', NULL, 6, '"\"1. Формат: Продукт соответствует спецификации (A4).\\n2. Плотность: Продукт соответствует спецификации (80 г/м2).\\n3. Яркость: Продукт имеет яркость ISO 96%, что выше требуемых 94%, что является плюсом.\\n4. Количество листов: Продукт соответствует спецификации (500 листов).\\n5. Класс бумаги: Информация отсутствует, что снижает оценку.\\n6. Белизна бумаги: Продукт имеет белизну 96%, что ниже требуемых 146%, что является минусом.\\n7. Количество упаковок в коробке: Информация отсутствует, что снижает оценку.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (139, 31497757, 'Мешки для мусора Avikomp, 7 мкм, 30 л, рулон 30 шт, черные', 'Практичная серия для экономных хозяек. Мусорные пакеты повышенной прочности, универсальные в применении. Предназначены для упаковки бытовых и производственных отходов, для хозяйственных целей.', 'Объем: 30 л; Количество в упаковке: 30 шт; Материал: полиэтилен; Плотность: 7 мкм; Цвет: черный; Упаковка: рулон.', 'https://vertical.ru/product/meshki-dlya-musora-avikomp-7-mkm-30-l-rulon-30-sht-chernye/', 390, 'шт', 'RUB', NULL, 7, '"\"1. Объем: соответствует (30 л).\\n2. Цвет: соответствует (черный).\\n3. Плотность: не соответствует (7 мкм вместо 30 мкм).\\n4. Количество в упаковке: соответствует (30 шт).\\n5. Материал: не указан в спецификациях, но это не является несоответствием.\\n6. Упаковка: не указана в спецификациях, но это не является несоответствием.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (140, 31497658, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: информация о процессоре не указана, поэтому невозможно оценить соответствие (0 баллов).\\n2. ОЗУ: информация отсутствует (0 баллов).\\n3. SSD: информация отсутствует (0 баллов).\\n4. Операционная система: информация отсутствует (0 баллов).\\n5. Гарантийный срок: информация отсутствует (0 баллов).\\n6. Компактный корпус: соответствует (1 балл).\\n7. Достаточное количество портов: соответствует (1 балл).\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (141, 31497632, 'Компьютер Core i5-6400 8GB 256GB SSD RX 580 Windows 10', 'Стационарный компьютер', 'Core i5-6400, 8GB RAM, 256GB SSD, RX 580, Windows 10', 'https://220.lv/ru/kompyuternaya-tehnika/personalnye-kompyutery/kompyuter-core-i5-6400-8gb-256gb-ssd-rx?id=28601621', 799, 'piece', 'EUR', NULL, 9, '"\"1. Процессор: Соответствует (Intel Core i5).\\n2. ОЗУ: Соответствует (8 ГБ).\\n3. SSD: Соответствует (256 ГБ).\\n4. Видеокарта: Не указана в спецификациях, но наличие RX 580 можно считать дополнительным плюсом.\\n5. Операционная система: Соответствует (Windows 10).\\n6. Гарантийный срок: Не указан в деталях продукта, что является недостатком.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (215, 31473456, 'Ватный матрас для рабочих CEXOL1', 'Ватный матрас для рабочих CEXOL1 - отличное решение для обеспечения комфортного отдыха на строительной площадке. Имеет все необходимые сертификаты качества и соответствия ГОСТу.', 'Ценовой диапазон: от 1000 до 5000 рублей. Гарантийный срок службы: от 1 до 5 лет.', 'https://matras-vatniy.ru/cexol1-70-190.html', 2500, 'штука', 'RUB', NULL, 7, '"\"Продукт соответствует ценовому диапазону от 1000 до 5000 рублей и имеет гарантийный срок службы от 1 до 5 лет. Однако, описание и требуемые функциональные, технические, качественные и эксплуатационные характеристики не предоставлены, что затрудняет полную оценку соответствия.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (142, 31497530, 'Кондиционер Ava ACT 12 QA', 'Сплит-система оснащена обычным надежным компрессором, который работает в режиме включения и отключения. ACT-12QA изготовлен в Китае компанией-заводом VA, которая является крупнейшим производителем кондиционеров в мире, ежегодно поставляет в разные страны более 30 млн. шт. Кондиционер AVA ACT-12QA обладает широким набором премиальных функций: фильтр высокой степени очистки; автоматический перезапуск; запоминание положения жалюзи; обнаружение утечки хладагента; режим комфортного сна; режим turbo производительности; автоматическое качание заслонки; два направления воздушного потока; функция «помни мои установки». Пульт кондиционера запоминает желаемые установки пользователя - установка режима работы, а скорость вращения вентилятора, положение заслонок и жалюзи. Режим «FAVORITE». При нажатии кнопки «FAV» (favorite - от англ. - «фаворитные» или «любимые») кондиционер (сплит-система) будетт работать в соответствии с этими параметрами. Режим «FOLLOW ME». Пульт управления оснащен датчиком температуры, согласно которого температура изменяется автоматически по выставленной. В комплект поставки входит инсталляция.', 'Артикул: ACT 12 QA
Цвет корпуса: Белый
Инвертор: Нет
Тип управления: Электронное
Количество режимов работы: 4
Автоматический режим работы: Да
Режим вентиляции: Да
Частота: 36/34/30(Гц)
Вес внутреннего блока: 13 (кг)
Вес внешнего блока: 45 (кг)
Инвертор: Нет
Тип: настенная сплит-система
Основные режимы: охлаждение/обогрев
Мощность в режиме охлаждения (Вт): 3250
Мощность в режиме обогрева (Вт): 3300
Потребляемая мощность при охлаждении (Вт): 1012
Потребляемая мощность при обогреве (Вт): 912
Рекомендуемая площадь обогрева (м2): 34
Рекомендуемая площадь охлаждения (м2): 36
Габариты внутреннего блока: 660х530х240
Гарантия: 1 год', 'https://tehnomag.kz/catalog/klimaticheskaya-tehnika/kondicionery/kondicioner-ava-act-12-qa', 84200, 'piece', 'KZT', NULL, 7, '"\"1. Цвет корпуса: Белый - соответствует.\\n2. Инвертор: Нет - соответствует.\\n3. Тип управления: Электронное - соответствует.\\n4. Количество режимов работы: 4 - соответствует.\\n5. Автоматический режим работы: Да - соответствует.\\n6. Режим вентиляции: Да - соответствует.\\n7. Частота: 36/34/30(Гц) - соответствует.\\n8. Вес внутреннего блока: 13 (кг) - соответствует.\\n9. Вес внешнего блока: 45 (кг) - соответствует.\\n10. Тип: настенная сплит-система - соответствует.\\n11. Основные режимы: охлаждение/обогрев - соответствует.\\n12. Мощность в режиме охлаждения (Вт): 3250 - соответствует.\\n13. Мощность в режиме обогрева (Вт): 3300 - соответствует.\\n14. Потребляемая мощность при охлаждении (Вт): 1012 - соответствует.\\n15. Потребляемая мощность при обогреве (Вт): 912 - соответствует.\\n16. Рекомендуемая площадь обогрева (м2): 34 - соответствует.\\n17. Рекомендуемая площадь охлаждения (м2): 36 - соответствует.\\n18. Габариты внутреннего блока: 660х530х240 - соответствует.\\n19. Гарантия: 1 год - соответствует.\\n20. Премиальные функции: отсутствуют - не соответствует.\\n21. В комплект поставки входит инсталляция: не указано - не соответствует.\\n22. Сопутствующие документы: не указано - не соответствует.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (143, 31497522, 'Рейтинг лучших ноутбуков до 50 000 рублей 2021', 'Список лучших ноутбуков, доступных по цене до 50 000 рублей в 2021 году.', 'Список характеристик и особенностей ноутбуков из рейтинга.', 'https://rutab.net/b/notebooks/2021/05/19/reyting-luchshih-noutbukov-do-50000-rubley-2021.html', 50000, 'piece', 'RUB', NULL, 0, '"\"Для оценки соответствия продукта спецификациям необходимо предоставить список характеристик и особенностей ноутбуков из рейтинга.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (144, 31497495, 'Лист горячекатаный 2×1250×2500мм (марка ст3)', 'Прокат листовой горячекатаный', 'Чёрная сталь (ст3), ГОСТ 19903-74, ГОСТ 16523-97, ГОСТ 14637-89', 'https://ms-gp.ru/catalog/flat/list-goryachekatanyy/2x1250x2500/', 3657, 'т', '₽', NULL, 4, '"\"Продукт выполнен из чёрной стали марки ст3, что соответствует ГОСТ 19903-74, ГОСТ 16523-97 и ГОСТ 14637-89. Однако, в спецификациях указано, что продукт должен соответствовать СТ РК 3310-2018, что не упомянуто в деталях продукта. Также отсутствует информация о толщине и размере листа, что является критически важным для соответствия спецификациям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (145, 31497361, 'Стул VN-22-01-F (черный)', 'Цвет: Черный
