INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (182, 31467113, 'Компьютер HP 290 G4', 'Хорошим вариантом для работы или учебы является компьютер HP 290 G4. Его преимущество заключается в компактном и прочном корпус, который значительно сэкономит место на рабочем столе. Данная модель оборудована процессором Intel Core i5 10500 с рабочей частотой 3,1 ГГц, а также оперативной памятью на 8 Гб и видеокартой Intel UHD Graphics 630. Накопитель SSD объемом 256 Гб позволяет хранить большое количество важной информации.', 'Процессор: Intel Core i5 10500, Оперативная память: DDR4 8ГБ, Жесткий диск: 256ГБ(SSD), Видеокарта: Intel UHD Graphics 630, Оптический привод: DVD-RW, Операционная система: Windows 10 Professional, Цвет: черный', 'https://www.citilink.ru/product/pk-hp-290-g4-mt-i5-10500-8gb-ssd256gb-dvdrw-w10pro64-kb-m-1406919/', 0, '', '', NULL, 8, '"\"1. Процессор: Соответствует (Intel Core i5 10500).\\n2. Оперативная память: Соответствует (DDR4 8ГБ).\\n3. Жесткий диск: Соответствует (256ГБ SSD).\\n4. Видеокарта: Не указана в спецификациях, но присутствует (Intel UHD Graphics 630).\\n5. Оптический привод: Не указан в спецификациях, но присутствует (DVD-RW).\\n6. Операционная система: Соответствует (Windows 10 Professional).\\n7. Цвет: Не указан в спецификациях, но присутствует (черный).\\n8. Гарантийный срок: Не указан в деталях продукта.\\n\\nОбщий вывод: Продукт в целом соответствует спецификациям, за исключением отсутствия информации о гарантийном сроке.\""');
