INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (187, 31459192, 'Bolt крепления ножа КРН 2.1 М14 с гайкой DIN 985, комплект 8 шт', 'Комплект болтов для крепления ножа КРН 2.1 М14 с гайкой DIN 985. В комплекте 8 штук.', 'Материал: сталь. Размер резьбы: М14. Тип гайки: DIN 985.', 'https://am.ozon.com/product/bolt-krepleniya-nozha-krn-2-1-m14-s-gaykoy-din-985-komplekt-8-sht-838662525/', 450, 'set', 'RUB', NULL, 4, '"\"Продукт представляет собой гайку типа DIN 985, а не болт. Материал соответствует спецификации (сталь), и размер резьбы также соответствует (М14). Однако, спецификация требует болт для ножа КРН 2.1 М14*2 (ПУ), что не соответствует предоставленному продукту.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (188, 31459470, 'Работы научно-исследовательские в области охраны окружающей среды Работы научно-исследовательские в области охраны окружающей среды в Карагандинской области', 'Тендер на проведение научно-исследовательских работ в области охраны окружающей среды в Карагандинской области.', 'Проведение научно-исследовательских работ в области охраны окружающей среды в соответствии с требованиями технического задания.', 'https://tenderplus.kz/zakupki/33333418', 89285714.28, 'единица', 'RUB', NULL, 8, '"\"Продукт представляет собой проведение научно-исследовательских работ в области охраны окружающей среды, что соответствует требованиям технического задания. Однако, спецификация требует обеспечения полного и надлежащего исполнения обязательств по Договору, что не было явно указано в деталях продукта.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (189, 31454671, 'О внесении изменений и дополнений в приказ Министра финансов Республики Казахстан от 11 декабря 2015 года № 648 «Об утверждении Правил осуществления государственных закупок»', 'Внесены изменения и дополнения в приказ Министра финансов Республики Казахстан от 11 декабря 2015 года № 648 «Об утверждении Правил осуществления государственных закупок»', 'Изменения и дополнения касаются различных аспектов проведения государственных закупок, включая техническую спецификацию, проектно-сметную документацию, экспертизу, критерии оценки участников конкурса и другие важные моменты.', 'https://tsnik.kz/normativno-pravovye-akty/134189/', 0, 'item', 'KZT', NULL, 0, '"\"Предоставленные детали продукта касаются изменений и дополнений в различных аспектах проведения государственных закупок, включая техническую спецификацию, проектно-сметную документацию, экспертизу и критерии оценки участников конкурса. Однако, спецификации требуют услуги по редизайну и техническому обслуживанию веб-сайта АО «СПК «Astana». В предоставленных деталях продукта отсутствует информация о редизайне и техническом обслуживании веб-сайта, а также о требованиях к поставщику, технических характеристиках и условиях к потенциальному поставщику. Таким образом, продукт не соответствует спецификациям.\""');
