INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (194, 31428518, 'Кран шар. фланцевый 32п ДУ-25 Ру-25', 'Кран шар. фланцевый 32п ДУ-25 Ру-25 в разделе Краны шаровые — из каталога «Водозапорная и трубопроводная арматура» от «САНТЕХАМУРТОРГ» — Текстильная ул.,120/а1, Благовещенск', 'по цене: 2 340 руб., доставка или самовывоз. Примечание к цене: Бесплатная доставка по Благовещенску при заказе от 5000 рублей.', 'https://tu.market/product/646825/kran-shar-flancevyj-32p-du-25-ru-25', 2340, 'шт', 'руб.', NULL, 9, '"\"1. Цена: Указана цена 2 340 руб., что соответствует требованиям.\\n2. Доставка или самовывоз: Указано, что возможна доставка или самовывоз, что соответствует требованиям.\\n3. Примечание к цене: Указано, что бесплатная доставка по Благовещенску при заказе от 5000 рублей, что является дополнительной информацией и не противоречит требованиям.\\n4. Тип крана: Указано, что кран шаровый приварной редуцированный, что соответствует требованиям.\\n5. Диаметр: Диаметр не указан, что является несоответствием.\\n6. Назначение: Указано, что кран для воды, что соответствует требованиям.\\n7. Условное давление: Указано, что Ру 25, что соответствует требованиям.\\n8. Материал уплотнения клапана: Указано, что PTFE, что соответствует требованиям.\\n9. Материал корпуса: Указано, что сталь, что соответствует требованиям.\\n10. Материал шара: Указано, что нержавеющая сталь, что соответствует требованиям.\\n11. Управление: Указано, что ручка-рычаг, что соответствует требованиям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (195, 31423817, 'Услуги по организации/проведению конференций/семинаров/форумов/конкурсов/корпоративных/спортивных/культурных/праздничных и аналогичных мероприятий', 'Услуги по организации/проведению конференций/семинаров/форумов/конкурсов/корпоративных/спортивных/культурных/праздничных и аналогичных мероприятий', 'Конференциялар, форумдар, семинарлар, конурстар, корпоративтік, спорттық, мәдени, мерекелік және балама іс-шараларды ұйымдастыру/өткізу бойынша қызметтер', 'https://eep.mitwork.kz/ru/publics/lot/355102', 250000, 'Услуги', 'KZT', NULL, 2, '"\"Предоставленные детали продукта описывают услуги по организации и проведению различных мероприятий, таких как конференции, форумы, семинары, конкурсы, корпоративные, спортивные, культурные, праздничные и альтернативные мероприятия. Однако спецификации указаны как ''Техническая'', что не соответствует описанию услуг, так как они относятся к сфере организации мероприятий, а не к техническим аспектам.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (196, 31412183, 'Втрое вырос объем ремонтных работ на улицах Тараза', 'Ремонт и строительство дорожной инфраструктуры продолжается в областном центре в рамках трехлетнего плана развития города Тараза. По данным пресс-службы акимата Жамбылской области, на 2024 год в Таразе планируется реализовать 40 проектов по дорожному ремонту, объем текущих ремонтных работ увеличился втрое.', 'Предстоит заасфальтировать 117 городских магистралей протяженностью 140 километров, отремонтировать пешеходные дорожки протяженностью 20,2 километра и отсыпать гравием 73,8 километра дорог (165 улиц, переулков, тупиков и проездов). Планируется также модернизация трех улиц длиной 10,8 километра.', 'https://ec-sport.kz/?p=33293', 4183030.83, 'км', 'тенге', NULL, 1, '"\"1. Сроки: В описании продукта не указаны сроки выполнения работ, что является критическим несоответствием. \\n2. ГОСТы и стандарты: Нет информации о соответствии выполняемых работ ГОСТам и стандартам. \\n3. График выполнения работ: Не предоставлен график выполнения работ с указанием видов, объемов и сроков движения рабочей силы. \\n4. Техника безопасности: Нет информации о предоставленных утвержденных мероприятиях по технике безопасности и технике пожарной безопасности. \\n5. Согласования и разрешения: Нет информации о согласии на получение необходимых согласований и разрешений. \\n6. Гарантийные обязательства: Нет информации о предоставленных гарантийных обязательствах по соответствию материалов ГОСТам. \\n7. Включение всех расходов: Нет информации о включении всех расходов в конкурсное ценовое предложение. \\n8. Смета: Нет информации о проведении работ согласно смете. \\n9. Условия расторжения договора: Нет информации о соблюдении условий расторжения договора в случае непроведения или приостановления работ. \\n\\nТаким образом, продукт не соответствует большинству спецификаций.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (197, 31410063, 'Аккумуляторная батарея NKB-301V Nihon Kohden', 'Аккумуляторная батарея NKB-301V Nihon Kohden совместима со следующими дефибрилляторами, , TEC-5521, TEC-5531, TEC- 7621, TEC-7631, TEC-7721, TEC-7731, ТурХ065', '384 000,00 KZT', 'https://eep.mitwork.kz/ru/publics/lots/200840020570', 384000, 'item', 'KZT', NULL, 0, '"\"Предоставленная информация о продукте содержит только цену (384 000,00 KZT) и не включает никаких технических характеристик, что делает невозможным оценку соответствия техническим спецификациям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (198, 31433999, 'Компьютер iRU 310H6ITF, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Компьютер iRU 310H6ITF с процессором Intel Core i5 12400, оперативной памятью DDR4 8ГБ, накопителем 256ГБ(SSD), графикой Intel UHD Graphics 730 и установленной операционной системой Windows 11 Professional. Цвет: черный.', 'Процессор: Intel Core i5 12400, Оперативная память: DDR4 8ГБ, Накопитель: 256ГБ(SSD), Графика: Intel UHD Graphics 730, Операционная система: Windows 11 Professional, Цвет: черный', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 0, '', '', NULL, 8, '"\"1. Процессор: Соответствует (Intel Core i5 12400).\\n2. Оперативная память: Соответствует (8 ГБ DDR4).\\n3. Накопитель: Соответствует (256 ГБ SSD).\\n4. Графика: Не указана в спецификациях, но наличие Intel UHD Graphics 730 не является несоответствием.\\n5. Операционная система: Несоответствие (Windows 11 Professional вместо Windows 10).\\n6. Цвет: Не указан в спецификациях, не влияет на оценку.\\n7. Гарантийный срок: Не указан в деталях продукта, что является несоответствием.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (199, 31443660, 'Chuwi HeroBook Pro', 'Модель от компании Chuwi базируется на процессоре базового уровня Celeron N4020, но 8 ГБ оперативной памяти позволяют ему «тянуть» предустановленную Windows 11, уверенно чувствуя себя при работе с десятком-другим вкладок в браузере. Вес менее 1,5 кг делает его подходящим вариантом для поездок. В стационарных условиях к устройству можно подключить внешний монитор через miniHDMI, а корпоративные ресурсы — через Wi-Fi 5.', 'Экран: 14.1″, 1920 × 1080, IPS, Процессор: Intel Celeron N4020 1,1 ГГц (2,8 ГГц, в режиме Turbo), Графический процессор: Intel UHD Graphics 600, Оперативная память: 8 ГБ, LPDDR4, Накопитель: SSD 256 ГБ, Операционная система: Windows 11 Home', 'https://journal.citilink.ru/articles/noutbuki-dlya-raboty-do-50-tysyach-rublej-eto-realno/', 1746087, 'piece', 'RUB', NULL, 5, '"\"1. Процессор: Продукт оснащен процессором Intel Celeron N4020, в то время как спецификации требуют Intel Core i5. Это значительное несоответствие.\\n2. Оперативная память: Продукт соответствует спецификации, так как имеет 8 ГБ ОЗУ.\\n3. Накопитель: Продукт соответствует спецификации, так как имеет SSD на 256 ГБ.\\n4. Операционная система: Продукт оснащен Windows 11 Home, в то время как спецификации требуют Windows 10. Это незначительное несоответствие, так как Windows 11 является более новой версией.\\n5. Гарантийный срок: Информация о гарантийном сроке отсутствует, что также снижает оценку.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (200, 31361653, 'Office Pro+', 'Intel-Core i5 – 10400 2.9 GHz | ОЗУ 8GB DDR4 | SSD 256 GB', 'Материнская плата: ASUS | PRIME | H510M-K | LGA 1200
