INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (202, 31380198, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Компактный корпус: не указано в спецификациях, но можно считать плюсом.\\n2. Процессор: не указано, какой именно процессор, но упомянут ''неплохой процессор''. Это не соответствует требованию Intel Core i5.\\n3. ОЗУ: не указано.\\n4. SSD: не указано.\\n5. Операционная система: не указана.\\n6. Гарантийный срок: не указан.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (203, 31386197, 'Установка тренировочных и игровых элементов на территории дворов ул.Ленина 5, Ленина 3', 'Установка тренировочных и игровых элементов на территории дворов ул.Ленина 5, Ленина 3', 'Международные ПР', 'https://tenmon.ru/1/230701710193566.html', 81086955, '0,00', 'KZT', NULL, 0, '"\"1. Наименование продукта: Международные ПР. Не соответствует требованию наименования ''Установка детских игровых и открытых спортивных площадок''.\\n2. Заказчик: Не указано. Не соответствует требованию ''Государственное учреждение «Аппарат акима района Тұран города Шымкент»''.\\n3. Место выполнения работ: Не указано. Не соответствует требованию ''Город Шымкент, район Тұран''.\\n4. Основные требования к работе: Не указаны. Не соответствует основным требованиям к работе.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (204, 31386196, 'Установка тренировочных и игровых элементов на территории дворов ул.Ленина 5, Ленина 3', 'Установка тренировочных и игровых элементов на территории дворов ул.Ленина 5, Ленина 3', 'Международные', 'https://tenmon.ru/1/230701710193566.html', 81086955, '0,00', 'KZT', NULL, 0, '"\"1. Наименование продукта не указано, что затрудняет оценку соответствия. 2. Заказчик не указан, что также затрудняет оценку. 3. Место выполнения работ не указано. 4. Основные требования к работе не указаны, что делает невозможным оценку соответствия по этому критерию.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (205, 31357988, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется модель. Спецификация требует Intel Core i5. Без точной информации невозможно подтвердить соответствие. \\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Спецификация требует 8 ГБ. \\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. Спецификация требует 256 ГБ. \\n4. Операционная система: В описании продукта нет информации об операционной системе. Спецификация требует Windows 10. \\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Спецификация требует 2 года. \\n6. Компактный корпус и достаточное количество портов соответствуют общим ожиданиям, но не являются частью предоставленных спецификаций.\""');
