INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (209, 31337534, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется, что это Intel Core i5. Это снижает оценку, так как нет точного соответствия спецификации. \\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Это прямое несоответствие спецификации. \\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. Это прямое несоответствие спецификации. \\n4. Операционная система: В описании продукта нет информации об операционной системе. Это прямое несоответствие спецификации. \\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Это прямое несоответствие спецификации. \\n6. Компактный корпус и достаточное количество портов соответствуют спецификации, но это не компенсирует отсутствие ключевых характеристик.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (210, 31497461, 'Ризолин самоклеющаяся гидроизоляция', 'Ризолин — самоклеящийся рулонный, кровельный, гидроизоляционный и шумоизоляционный материал нового поколения.', 'Рулон 10 м2, Толщина - 2,5 мм, Длина/ширина - 10/1 м, Вес - 25 кг, Армирующая основа - стеклоткань, Толщина фольги - 30 мкм, Укладка без применения огня, Незаменим на объектах, где исключено применение открытого пламени, Срок эксплуатации от 25 лет, Ризолин на 24%-33% выгоднее, чем использование обычных материалов, Температура эксплуатации от -50 до +60О, Сокращение слоев кровли и снижение материалоемкости на 30%, Самоклеящийся. Укладка на любую поверхность, Низкая стоимость монтажа: минимальное время работ и трудозатрат, Изготовлен на основе стеклоткани и уникального битумно-полимерного состава. Данный материал обладает прекрасными противопожарными и гидроизоляционными качествами. Он не токсичен и не содержит вредных веществ. Изготавливается по ГОСТу.', 'https://tagiyev.kz/p94488833-krovelnyj-rulonnyj-material.html', 23000, 'кв.м', '₸', NULL, 10, '"\"Продукт полностью соответствует предоставленным спецификациям. Все ключевые параметры, такие как площадь рулона, толщина, длина и ширина, вес, армирующая основа, толщина фольги, способ укладки, срок эксплуатации, экономическая выгода, температурный диапазон эксплуатации, сокращение слоев кровли, самоклеящиеся свойства, низкая стоимость монтажа, состав материала, противопожарные и гидроизоляционные качества, а также соответствие ГОСТу, полностью совпадают с указанными в спецификациях.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (211, 31497131, 'Труба электросварная тонкостенная стальная 25х2,0', 'Труба 25х2,0 электросварная прямошовная, марка стали 1-3сп/пс, ГОСТ 10705-80, ГОСТ 10704-91. Вес погонного метра трубы 1.134 кг. Производятся из листового проката углеродистой и низколегированной стали методом поперечной гибки. Электросварные трубы имеют круглое сечение и продольный шов на всю длину трубы. Стальные трубы широко применяются при строительстве различных конструкций и создании систем трубопроводов.', '25х2,0 электросварная прямошовная, марка стали 1-3сп/пс, ГОСТ 10705-80, ГОСТ 10704-91', 'https://om-ts.ru/truby/truba-svarnaya-(esv)/truby-elektrosvarnye-chernye/truby-elektrosvarnye-22-38/truba-elektrosvarnaya-25kh2,0/', 0, '', '', NULL, 3, '"\"1. Диаметр трубы: продукт имеет диаметр 25 мм, что не соответствует спецификации (273 мм). \\n2. Толщина стенки: продукт имеет толщину стенки 2,0 мм, что не соответствует спецификации (14 мм). \\n3. Марка стали: продукт имеет марку стали 1-3сп/пс, что частично соответствует спецификации (Ст3сп). \\n4. ГОСТ: продукт соответствует ГОСТ 10705-80 и ГОСТ 10704-91, что соответствует спецификации. \\n5. Метод производства: продукт произведен методом электросварки, что соответствует спецификации. \\n6. Сечение и шов: продукт имеет круглое сечение и продольный шов, что соответствует спецификации.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (212, 31474855, 'Принтер Epson L1300', 'Принтер Epson L1300 з оригінальною СБПЧ. Пьезоэлектрическая струйная технология печати. Поддержка печати на различных носителях, включая фотобумагу, глянцевую бумагу, матовую бумагу, карточки, конверты. Максимальное разрешение печати 5760x1440 dpi. Скорость печати до 30 стр/мин в ч/б и до 17 стр/мин в цвете. Поддержка операционных систем Windows и Mac OS X.', 'Цвет: черный, Бренд: Epson, Вес: 12,2 кг, Время выхода первой страницы: 12 сек, Емкость лотка вывода: 50 л, Емкость лотка подачи: 100 л, Интерфейсы подключения: USB 2.0, Количество цветов: 4, Максимальная потребляемая мощность: 20 Вт, Модель: L1300, Область применения: настольный, Поддерживаемая плотность бумаги: 64-255 г/м2, Поддерживаемые печатные носители: Печать на, Поддержка Операционных Систем: Windows, Mac OS, Поддержка фотопечати: да, Размеры: 705 x 322 x 215 мм, Разрешение монохромной печати: 5760x1440 dpi, Разрешение цветной печати: 5760x1440 dpi, Расходные материалы: черный C13T66414A, голубой C13T66424A, желтый C13T66444A, пурпурный C13T66434A, Скорость монохромной печати: 20 и менее стр/мин, Скорость цветной печати: 5,5 стр/мин, Совместимость по модели: L1300, Точная скорость монохромной печати: 15 стр/мин, Устройство подачи оригиналов (применительно к МФУ): Обычный лоток подачи, Формат печати: A3, Цвет корпуса: Чёрный', 'https://cmp24.by/p/32956-printer-epson-l1300', 20000, 'шт', 'BYN', NULL, 5, '"\"1. Тип оборудования: Продукт не является мобильным (переносным) принтером, а настольным. (-1)\\n2. Формат печати: Продукт поддерживает формат A3, а не A4. (-1)\\n3. Технология печати: Струйный принтер. (+1)\\n4. Цвет печати: Цветной. (+1)\\n5. Разрешение печати: 5760x1440 dpi, что выше минимального требования 4800x1200 dpi. (+1)\\n6. Размещение: Продукт не является портативным. (-1)\\n7. Объем памяти: Информация отсутствует. (-1)\\n8. Скорость цветной печати: 5,5 стр/мин, что ниже минимального требования 7 стр/мин. (-1)\\n9. Скорость монохромной печати: 15 стр/мин, что выше минимального требования 10 стр/мин. (+1)\\n10. Интерфейс: USB 2.0, но отсутствует WiFi. (-1)\\n11. Печать с USB носителей: Информация отсутствует. (-1)\\n12. Поддерживаемые типы USB накопителей, карт памяти: USB 2.0. (+1)\\n13. Типы печатных носителей: Информация отсутствует. (-1)\\n14. Лоток подачи бумаги: 100 листов, что выше минимального требования 50 листов. (+1)\\n15. Плотность бумаги: 64-255 г/м2, что частично соответствует требованию 60-300 г/м2. (0)\\n16. Индикация: Информация отсутствует. (-1)\\n17. Тип дисплея: Информация отсутствует. (-1)\\n18. Уровень шума: Информация отсутствует. (-1)\\n19. Питание: от сети. (+1)\\n20. ГОСТ 21776-87: Информация отсутствует. (-1)\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (213, 31474302, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: информация о процессоре не указана, поэтому невозможно оценить соответствие (0 баллов).\\n2. ОЗУ: информация о количестве ОЗУ отсутствует (0 баллов).\\n3. SSD: информация о SSD отсутствует (0 баллов).\\n4. Операционная система: информация об операционной системе отсутствует (0 баллов).\\n5. Гарантийный срок: информация о гарантийном сроке отсутствует (0 баллов).\\n6. Компактный корпус: соответствует спецификации (1 балл).\\n7. Достаточное количество портов: соответствует спецификации (1 балл).\""');
