INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (216, 31468354, 'Дизельный генератор G-Force RGF-180', 'Дизельные генераторы "G-Force" с двигателем Ricardo - это надежность, проверенная временем! Компания "G-Focrce Qazaqstan" официально представляет на территории Республики Казахстан дизель-генераторные установки фирмы "G-Force" производство КНР. На генераторы G-Force с двигателем RICARDO (KOFO) действует расширенная гарантия 18 месяцев или 1500 моточасов, что наступит раньше. Многие модели имеются в наличии на складе завода. Уточняйте пожалуйста наличие при заказе. С уважение "G-Force Qazaqstan"', 'Дизель-генераторные установки фирмы "G-Force" производства КНР. Гарантия 18 месяцев или 1500 моточасов. Многие модели в наличии на складе завода.', 'https://g-force.satu.kz/p57705300-dizelnyj-generator-force.html', 57705300, 'item', 'KZT', NULL, 2, '"\"1. Тип топлива: дизельное - соответствует.\\n2. Тип генератора: синхронный - соответствует.\\n3. Количество фаз: не указано - несоответствие.\\n4. Режим работы: не указан - несоответствие.\\n5. Время непрерывной работы: не указано - несоответствие.\\n6. Напряжение: не указано - несоответствие.\\n7. Номинальная мощность: не указана - несоответствие.\\n8. Частота тока: не указана - несоответствие.\\n9. Защита от перегрузки и от короткого замыкания: не указана - несоответствие.\\n10. Режимы запуска: не указаны - несоответствие.\\n11. Защитный кожух: не указан - несоответствие.\\n12. Температурный диапазон: не указан - несоответствие.\\n13. Габариты и масса: не указаны - несоответствие.\\n14. Тип альтернатора: синхронный - соответствует.\\n15. Датчик уровня масла: не указан - несоответствие.\\n16. ГОСТ 33115-201: не указан - несоответствие.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (217, 31468381, 'Перчатки нитриловые одноразовые c текстур. пальцами Puretech Neutrino, 24 см, голубой, размер S, 50 пар/упак', 'Одноразовые перчатки PURETECH® NEUTRINO нашли широкое применение в разных сферах. Они хорошо держат форму и повторяют изгиб руки. Высокая тактильная чувствительность помогает выполнять работу, требующую точности и аккуратности. Гиппоалергенность перчаток обеспечивает безопасность рук от раздражений, шелушений. Эффект механической памяти снижает степень усталости во время работы.', 'Одноразовые; Нестерильные; Неопудренные; Манжета с валиком; Форма плоская, неанатомическая; Текстурированная поверхность на пальцах; AQL - 1,5; Тип манжеты – с валиком; Прочность на разрыв: ≤ 18Мпа; Относительное удлинение при разрыве: ≤ 600%. Сферы использования: Фармацевтическая промышленность, Пищевая промышленность, Сфера общественного питания, Сфера услуг, Машиностроение, HoReCa, Клининговые компании, Коммунальные хозяйства. Соответствие стандартам: TP TC 019/2011. Состав материала: Нитрил. Тип: Неопудренные. Тип манжеты: С валиком. Длина перчатки (см): 24 см. AQL: 1.5. Поверхность: Текстурированная. Форма: Плоская, не анатомическая. Стерильность: Нестерильно. Толщина перчатки (мм): 0,07.', 'https://proficlean-dv.ru/magazin/product/perchatki-nitrilovye-odnorazovye-c-tekstur-palcami-safetech-neutrino-24-sm-goluboj-razmer-s-50-par-upak', 0, '', '', NULL, 7, '"\"1. Толщина: 0.07 мм - соответствует спецификации.\\n2. Длина: 24 см - соответствует спецификации.\\n3. Размер: S - информация отсутствует.\\n4. Цвет: голубой - информация отсутствует.\\n5. Форма: плоская, неанатомическая - соответствует спецификации.\\n6. Нестерильные - соответствует спецификации.\\n7. Одноразовые - соответствует спецификации.\\n8. Прочность на разрыв: ≤ 18Мпа - соответствует спецификации.\\n9. Тип манжеты: с валиком - соответствует спецификации.\\n10. Наличие подтверждающих сертификатов качества - информация отсутствует.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (218, 31466180, 'Компьютер Lenovo ThinkCentre M80t, Intel Core i5 10500, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 630, DVD-RW, Windows 10 Professional, черный [11cs0000uk]', 'Компьютер Lenovo ThinkCentre M80t с процессором Intel Core i5 10500, оперативной памятью DDR4 8ГБ, накопителем 256ГБ(SSD), графикой Intel UHD Graphics 630, оптическим приводом DVD-RW, предустановленной операционной системой Windows 10 Professional. Цвет черный.', 'Intel Core i5 10500, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 630, DVD-RW, Windows 10 Professional, черный', 'https://www.citilink.ru/product/kompyuter-lenovo-thinkcentre-m80t-intel-core-i5-10500-ddr4-8gb-256gb-s-1978508/', 0, '', '', NULL, 8, '"\"1. Процессор: Соответствует (Intel Core i5).\\n2. ОЗУ: Соответствует (8 ГБ DDR4).\\n3. SSD: Соответствует (256 ГБ).\\n4. Операционная система: Соответствует (Windows 10 Professional).\\n5. Гарантийный срок: Не указан.\\n6. Дополнительно: Указаны графика (Intel UHD Graphics 630) и DVD-RW, что не требовалось по спецификациям, но это не влияет на оценку.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (219, 31468380, 'Перчатки нитриловые одноразовые c текстур. пальцами Puretech Neutrino, 24 см, голубой, размер XL, 50 пар/упак', 'Одноразовые перчатки PURETECH® NEUTRINO нашли широкое применение в разных сферах. Они хорошо держат форму и повторяют изгиб руки. Высокая тактильная чувствительность помогает выполнять работу, требующую точности и аккуратности. Гиппоалергенность перчаток обеспечивает безопасность рук от раздражений, шелушений. Эффект механической памяти снижает степень усталости во время работы.', 'Одноразовые; Нестерильные; Неопудренные; Манжета с валиком; Форма плоская, неанатомическая; Текстурированная поверхность на пальцах; AQL - 1,5; Тип манжеты – с валиком; Прочность на разрыв: ≤ 18Мпа; Относительное удлинение при разрыве: ≤ 600%. Сферы использования: Фармацевтическая промышленность, Пищевая промышленность, Сфера общественного питания, Сфера услуг, Машиностроение, HoReCa, Клининговые компании, Коммунальные хозяйства. Соответствие стандартам: TP TC 019/2011. Состав материала: Нитрил. Тип: Неопудренные. Тип манжеты: С валиком. Длина перчатки (см): 24 см. AQL: 1.5. Поверхность: Текстурированная. Форма: Плоская, не анатомическая. Стерильность: Нестерильно. Толщина перчатки (мм): 0,07.', 'https://proficlean-dv.ru/magazin/product/perchatki-nitrilovye-odnorazovye-c-tekstur-palcami-safetech-neutrino-24-sm-goluboj-razmer-xl-50-par-upak', 0, '', '', NULL, 8, '"\"Продукт соответствует большинству спецификаций, включая толщину (0.07 мм), длину (24 см), форму (плоская, неанатомическая), нестерильность, одноразовость, прочность на разрыв (≤ 18Мпа) и тип манжеты (с валиком). Также продукт соответствует требованиям по AQL (1.5) и материалу (нитрил). Однако, в предоставленных деталях продукта отсутствует информация о размере (XL) и цвете (голубой). Также не указано наличие подтверждающих сертификатов качества, что является обязательным требованием.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (220, 31468385, 'Перчатки медицинские универсальные нитриловые SFM, нестерильные, неопудренные, размер M (7-8), голубые, 50 пар (100 штук) в упаковке', 'Медицинские перчатки из нитрила SFM предназначены для защиты рук медицинского персонала и пациентов от инфекций и других вредных воздействий. Не содержат латекса, что исключает риск аллергии. Перчатки универсального размера M (7-8) подходят для большинства взрослых. Голубого цвета. Не стерильные, неопудренные.', 'Размер: M (7-8)
Цвет: голубой
Количество: 50 пар (100 штук) в упаковке
Тип: нестерильные, неопудренные
Материал: нитрил', 'https://www.komus.ru/katalog/otraslevye-predlozheniya/meditsina/perchatki-meditsinskie/nitrilovye-perchatki/perchatki-meditsinskie-universalnye-nitrilovye-sfm-nesterilnye-neopudrennye-razmer-m-7-8-golubye-50-par-100-shtuk-v-upakovke-/p/1444105/?from=menu', 1200, 'упаковка', 'RUB', NULL, 5, '"\"1. Размер: Соответствует (M).\\n2. Цвет: Соответствует (голубой).\\n3. Количество: Соответствует (50 пар).\\n4. Тип: Соответствует (нестерильные, неопудренные).\\n5. Материал: Соответствует (нитрил).\\n6. Толщина: Не указана.\\n7. Длина: Не указана.\\n8. Форма: Не указана.\\n9. Прочность на разрыв: Не указана.\\n10. Утолщенная манжета с валиком: Не указана.\\n11. Наличие подтверждающих сертификатов качества: Не указано.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (222, 31463783, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется, что это Intel Core i5. Это снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Это снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. Это снижает оценку.\\n4. Операционная система: В описании продукта нет информации об установленной операционной системе. Это снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Это снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не компенсирует отсутствующую информацию по ключевым параметрам.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (223, 31463732, 'Перчатки трикотажные, с 2хПВХ точкой, 7 класс Россия (67824)', 'Трикотажные перчатки 67824 с 2-сторонней ПВХ-точкой, 7 класса вязки, предназначены для проведения ремонтных, строительных и механосборочных работ. Защищают руки мастера от травм и загрязнений. Изготовлены из пряжи 7 класса вязки, поэтому хорошо тянутся и легко надеваются. Перчатки будут полезны в промышленности, на строительной площадке, а также при выполнении погрузочно-разгрузочных и хозяйственных работ. Преимущества Хороший воздухообмен — благодаря хлопчатобумажной основе руки в перчатках не потеют. Высокий ресурс — полиэфирная нить в составе пряжи обеспечивает прочность и эластичность, нанесенное с 2 сторон точечное ПВХ-покрытие повышает устойчивость к истиранию. Нескользящее покрытие — ПВХ-точка хорошо сцепляется с рабочей поверхностью, что обеспечивает надежный захват материалов и инструментов. Надежная фиксация — эластичные манжеты плотно облегают запястья. Комфортная работа — перчатки не стесняют движений пальцев. Гипоаллергенность — благодаря натуральному материалу основы перчатками могут пользоваться люди с чувствительной кожей.', '- 4044996214177
- 0.07 кг
