INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (227, 31445866, 'Лампа светодиодная', 'Лампа светодиодная 10-15W, 24-36V AC/DC, E27 Товары должны быть новыми, соответствовать требованиям технических регламентов Таможенного союза. Условия поставки DDP, г.Нур-Султан, Объездная дорога 229, здание 8/1. Гарантийный срок на поставляемый товар не менее 1 (одного) года.', '10-15W, 24-36V AC/DC, E27', 'http://eep.mitwork.kz/ru/publics/lots/080540006922?page=45&per-page=50', 102500, 'шт', 'KZT', NULL, 0, '"\"Продукт не соответствует ни одной из предоставленных спецификаций. Указанные детали продукта (10-15W, 24-36V AC/DC, E27) не имеют никакого отношения к спецификациям, которые включают процессор, ОЗУ, SSD, операционную систему и гарантийный срок.\""');
