INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (229, 31455326, 'Световозвращающая пленка тип А Коммерческая', 'Цена за м2: 529,38р. Цена за рулон: 30 000,00р. На складе нашей компании теперь 6 цветов световозвращающей (светоотражающей) пленки PL3900 тип А ГОСТ 52290-2004', 'БЕЛЫЙ, КРАСНЫЙ, СИНИЙ, ЖЕЛТЫЙ, ЗЕЛЕНЫЙ, ОРАНЖЕВЫЙ', 'https://www.plasto.su/viewpage.php?page_id=247', 529.38, 'square meter', 'RUB', NULL, 8, '"\"Продукт представлен в шести цветах: белый, красный, синий, желтый, зеленый и оранжевый. Согласно спецификации СТ РК 1125-2002 «Знаки дорожные. Общие технические условия», дорожные знаки должны быть выполнены в определенных цветах, таких как белый, красный, синий, желтый и зеленый. Оранжевый цвет не является стандартным для дорожных знаков по данной спецификации.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (230, 31419160, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В спецификациях указан Intel Core i5, но в описании продукта процессор не уточнён, что снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти, что снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объёме SSD, что снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе, что снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке, что снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не основные параметры.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (231, 31422918, 'DCR 04813 S Фильтр осушитель Danfoss 023U7256', 'Фильтры-осушители со DCR сменным твердым сердечником (сердечниками) защищают холодильные установки и системы кондиционирования воздуха от влаги, кислот и твердых частиц. Твердый сердечник обеспечивает высокую производительность осушения и исключает образование кислот в системе. Фильтры-осушители DCR устанавливаются в жидкостной линии и линии всасывания систем охлаждения с одним или несколькими компрессорами', 'Фильтры-осушители со сменным твердым сердечником (сердечниками) DCR защищают холодильные установки и системы кондиционирования воздуха от влаги, кислот и твердых частиц. Могут использоваться в жидкостной линии и линии всасывания систем охлаждения с одним или несколькими компрессорами. Применение: холодильные установки с фторсодержащими хладагентами или CO2. Преимущества: высокая эффективность улавливания твердых частиц, установка в различных системах, удобная замена сердечников, возможность установки в любом положении. Варианты сердечников: 48-DM, 48-DC, 48-DA, сетчатый сердечник 48-DA.', 'https://sibagregat.ru/holod/komponent-linii/filtra/danfoss023u7256', 0, 'шт', 'по запросу', NULL, 6, '"\"1. Соответствие стандарту СТ РК ГОСТ Р 50553-2010: не указано в описании продукта. \\n2. Год выпуска - 2024: не указано в описании продукта. \\n3. Гарантийный срок (в месяцах) - 12: не указано в описании продукта. \\n4. Описание требуемых характеристик: \\n   - Защита холодильных установок и систем кондиционирования воздуха от влаги, кислот и твердых частиц: соответствует. \\n   - Возможность использования в жидкостной линии и линии всасывания систем охлаждения с одним или несколькими компрессорами: соответствует. \\n   - Применение с фторсодержащими хладагентами или CO2: соответствует. \\n   - Высокая эффективность улавливания твердых частиц: соответствует. \\n   - Установка в различных системах: соответствует. \\n   - Удобная замена сердечников: соответствует. \\n   - Возможность установки в любом положении: соответствует. \\n   - Варианты сердечников: 48-DM, 48-DC, 48-DA, сетчатый сердечник 48-DA: соответствует.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (432, 31502579, 'Office Pro+', 'Intel-Core i5 – 10400 2.9 GHz | ОЗУ 8GB DDR4 | SSD 256 GB', 'Материнская плата: ASUS | PRIME | H510M-K | LGA 1200
