INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (233, 31445560, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Компактный корпус: не указано в спецификациях, но можно считать плюсом. \\n2. Процессор: не указано, какой именно процессор, только что он неплохой. Спецификация требует Intel Core i5. \\n3. ОЗУ: не указано. Спецификация требует 8 ГБ. \\n4. SSD: не указано. Спецификация требует 256 ГБ. \\n5. Операционная система: не указано. Спецификация требует Windows 10. \\n6. Гарантийный срок: не указано. Спецификация требует 2 года.\\n\\nИтог: продукт не соответствует большинству спецификаций.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (234, 31443661, 'Chuwi MiniBook X', 'В сумочку бизнес-леди: Chuwi MiniBook X (розовый)', 'Экран: 10.51"; 1920х1200; IPS; Процессор: Intel N-series N100 0.8 ГГц (3.4 ГГц, в режиме Turbo); Графический процессор: Intel UHD Graphics; Оперативная память: 12 ГБ, LPDDR5; Диск: SSD 512 ГБ; Операционная система: Windows 11 Home; Клавиатура: с русскими буквами', 'https://journal.citilink.ru/articles/noutbuki-dlya-raboty-do-50-tysyach-rublej-eto-realno/', 0, 'item', 'RUB', NULL, 6, '"\"1. Процессор: Продукт оснащен процессором Intel N-series N100, который уступает по производительности Intel Core i5, указанному в спецификациях. \\n2. Оперативная память: Продукт имеет 12 ГБ ОЗУ, что превышает требуемые 8 ГБ, что является положительным аспектом.\\n3. Диск: Продукт оснащен SSD на 512 ГБ, что также превышает требуемые 256 ГБ, что является положительным аспектом.\\n4. Операционная система: Продукт поставляется с Windows 11 Home, в то время как спецификации требуют Windows 10. Это незначительное несоответствие, так как Windows 11 является более новой версией.\\n5. Гарантийный срок: Информация о гарантийном сроке отсутствует, что является недостатком.\\n6. Экран и клавиатура: Эти параметры не указаны в спецификациях, поэтому они не влияют на оценку соответствия.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (235, 31512255, 'Краски Для Внутренних Работ Код ТН ВЭД 2024: 3208109000, 3208209009, 3209100009', 'Эксперты подобрали список код ТН ВЭД которые наиболее подходят для вашей продукции (краски для внутренних работ)', 'Поиск кода ТН ВЭД по базе ТС 2024', 'https://kodtnved.ru/podbor/kraski-dlya-vnutrennih-rabot.html', 3990, '5 позиций', '₽', NULL, 0, '"\"Продукт ''Поиск кода ТН ВЭД по базе ТС 2024'' не соответствует спецификациям, так как спецификации требуют алкидные краски эмаль для внутренних и наружных малярных работ разных цветов (синяя, красная, желтая, зеленая, коричневая). Продукт не является краской и не имеет указанных характеристик.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (236, 31512248, 'Одностворчатые шкафы для медикаментов, одежды и документов', 'Организуйте в больнице, стационаре, медцентре удобные пространства для хранения вещей с помощью одностворчатых шкафов для медикаментов, одежды и документов. Они занимают мало места, но вместе с тем отличаются хорошей вместительностью за счет встроенных антресолей, полок и выдвижных ящиков. Модели сделаны из дерева либо из металла с порошковым покрытием для защиты от коррозии.', 'В наличии дизайны для разных интерьеров – есть нейтральные универсальные изделия, с открытыми и закрытыми секциями, со стеклянными дверками, цветными отделениями и т. д. Доступны десятки вариантов расположения полок и столешниц – в одних оптимально размещать медикаменты, в других папки с документами. Деревянные модели поставляются в разборном виде, металлические имеют цельную конструкцию.', 'https://novokom.su/shop/medicinskaja-mebel/odnostvorchatye', 3400, 'шт', 'RUB', NULL, 2, '"\"Продукт не соответствует спецификациям по нескольким ключевым параметрам. Во-первых, в описании продукта указано, что он может быть как деревянным, так и металлическим, тогда как спецификации требуют, чтобы шкаф был изготовлен из стали. Во-вторых, в описании продукта не указаны размеры, вес, количество полок и дверей, тип замка, цвет и тип покрытия, что затрудняет оценку соответствия этим параметрам. В-третьих, в описании продукта не упоминается наличие ключевых замков с 2000 комбинациями, регулируемых опор, соответствие ГОСТ 22414—77, гарантийный срок и паспорт. В-четвертых, в описании продукта не указаны условия доставки и согласования с заказчиком. Таким образом, продукт не соответствует большинству критических спецификаций.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (237, 31512256, 'Настенный кондиционер Samsung AR12TXHQASINUA', 'Настенный кондиционер Samsung AR12TXHQASINUA', 'Способ установки - настенный, Тип - сплит-система, Инвертор (плавная регулировка мощности) - Да, Максимальная длина коммуникаций - 3.0 м, Основные режимы - охлаждение / обогрев, Диапазон поддерживаемых температур - -22+46, Максимальный воздушный поток - 10.7 куб. м/мин, Охлаждающая способность - 12084.0 BTU/ч, Число внутренних блоков - 1, Мощность в режиме охлаждения - 12000.0 Вт, Мощность в режиме обогрева - 11942.0 Вт, Потребляемая мощность при охлаждении - 3500.0 Вт, Потребляемая мощность при обогреве - 3500.0 Вт, Режим приточной вентиляции - Нет, Дополнительные режимы - осушение воздуха, ночной, самодиагностика неисправностей, автоматический режим, режим вентиляции (без охлаждения и обогрева), автоматическое поддержание температуры, самоочистка, ночной режим, теплый старт, Режим осушения - Да, Класс энергоэффективности - A, Внутренний блок сплит-системы или мобильный кондиционер (ШxВxГ) - 880x360x285 мм, Наружный блок сплит-системы или оконный кондиционер (ШxВxГ) - 540x835x300 мм, Вес внутреннего блока - 11.5 кг, Вес внешнего блока - 22.5 кг, Управление с мобильного устройства - Нет, Пульт дистанционного управления - Да, Таймер включения/выключения - Да, Максимальный уровень шума - 46.0 дБ, Тип хладагента - R 22, Фаза - однофазный, Фильтры тонкой очистки воздуха - Да, Регулировка скорости вращения вентилятора - 5 скоростей, Другие функции и особенности - дезодорирующий фильтр, функция антиплесень, теплый пуск, функция запоминания настроек, возможность регулировки направления воздушного потока, дисплей, Обслуживаемая площадь - 36.0 кв.м, Температура для эксплуатации кондиционера в режиме охлаждения / обогрева - -22 +46, Монтажный комплект - Нет, Цвет - белый', 'https://proclim.kz/p116052918-nastennyj-konditsioner-samsung.html', 217833, 'шт', '₸', NULL, 4, '"\"1. Способ установки: соответствует (настенный).\\n2. Тип: соответствует (сплит-система).\\n3. Инвертор: соответствует (Да).\\n4. Максимальная длина коммуникаций: не указано в спецификациях.\\n5. Основные режимы: соответствует (охлаждение/обогрев).\\n6. Диапазон поддерживаемых температур: соответствует (-22+46).\\n7. Максимальный воздушный поток: не указано в спецификациях.\\n8. Охлаждающая способность: не указано в спецификациях.\\n9. Число внутренних блоков: соответствует (1).\\n10. Мощность в режиме охлаждения: не соответствует (12000 Вт против 5000 Вт).\\n11. Мощность в режиме обогрева: не соответствует (11942 Вт против 5200 Вт).\\n12. Потребляемая мощность при охлаждении: не соответствует (3500 Вт против 1650 Вт).\\n13. Потребляемая мощность при обогреве: не соответствует (3500 Вт против 1470 Вт).\\n14. Режим приточной вентиляции: соответствует (Нет).\\n15. Дополнительные режимы: соответствует (осушение воздуха, самодиагностика неисправностей, автоматический режим, режим вентиляции, автоматическое поддержание температуры, самоочистка, ночной режим, теплый старт).\\n16. Режим осушения: соответствует (Да).\\n17. Класс энергоэффективности: не соответствует (A против A+).\\n18. Внутренний блок (ШxВxГ): не соответствует (880x360x285 мм против 965x315x220 мм).\\n19. Наружный блок (ШxВxГ): не соответствует (540x835x300 мм против 840x550x290 мм).\\n20. Вес внутреннего блока: не соответствует (11.5 кг против 12.0 кг).\\n21. Вес внешнего блока: не соответствует (22.5 кг против 27.0 кг).\\n22. Управление с мобильного устройства: не указано в спецификациях.\\n23. Пульт дистанционного управления: соответствует (Да).\\n24. Таймер включения/выключения: не указано в спецификациях.\\n25. Максимальный уровень шума: соответствует (46.0 дБ против 58.0 дБ).\\n26. Тип хладагента: не соответствует (R 22 против R 32).\\n27. Фаза: соответствует (однофазный).\\n28. Фильтры тонкой очистки воздуха: не соответствует (Да против Нет).\\n29. Регулировка скорости вращения вентилятора: не соответствует (5 скоростей против 3 режимов).\\n30. Другие функции и особенности: соответствует (функция антиплесень, теплый пуск, функция запоминания настроек, возможность регулировки направления воздушного потока, дисплей).\\n31. Обслуживаемая площадь: не соответствует (36.0 кв.м против 54.0 кв.м).\\n32. Монтажный комплект: не соответствует (Нет против Да).\\n33. Цвет: не указано в спецификациях.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (238, 31511877, 'Эмаль Dekor ПФ-266 для пола красно-коричневая 2,6 кг', 'Износостойкая алкидная эмаль для пола и прочих поверхностей, эксплуатируемых в условиях повышенной интенсивности. Подходит для окрашенных ранее и новых деревянных оснований. Эмаль представляет собой готовый к применению продукт, обеспечивающий комфорт при проведении окрашивания за счет легкости нанесения и короткого срока, требуемого для высыхания. Линейка готовых цветов позволяет подобрать материал, подходящий для любого интерьера. Покрытие, образуемое продуктом, обладает высоким блеском, показывает устойчивость к механическому воздействию, истиранию, выдерживает мытье с применением бытовых моющих средств. Поверхности защищены от солнечного света и атмосферного воздействия. После высыхания вред здоровью человека не наносится.', 'Тип товара: Алкидная, Назначение: Для деревянных полов, Цвет: Красно - коричневый, Степень блеска: Глянцевый, Тип работ: Внутренний, Вес, кг: 2,6, Страна производитель: Россия, Бренд: Dekor, Вид товара: Эмаль', 'https://akvilon.kz/p/emal-dekor-pf-266-dlya-pola-krasno-korichnevaya-2-6-kg/', 3960, 'шт', '₸', NULL, 7, '"\"1. Тип товара: Алкидная - соответствует.\\n2. Назначение: Для деревянных полов - соответствует.\\n3. Цвет: Красно-коричневый - соответствует.\\n4. Степень блеска: Глянцевый - соответствует.\\n5. Тип работ: Внутренний - соответствует.\\n6. Вес: 2,6 кг - спецификация не указывает вес, поэтому не оценивается.\\n7. Страна производитель: Россия - спецификация не указывает страну производителя, поэтому не оценивается.\\n8. Бренд: Dekor - спецификация не указывает бренд, поэтому не оценивается.\\n9. Вид товара: Эмаль - соответствует.\\n10. Износостойкость: Спецификация указывает, что эмаль должна быть износостойкой, но в деталях продукта это не указано, поэтому снижаем баллы.\\n11. ГОСТ 20010-93: В деталях продукта не указано соответствие ГОСТ, поэтому снижаем баллы.\\n12. Доставка до дверей заказчика и согласование с завхозом: В деталях продукта это не указано, поэтому снижаем баллы.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (239, 31511748, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В спецификациях указан Intel Core i5, но в описании продукта процессор не уточнён. Это снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Это снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объёме SSD. Это снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе. Это снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Это снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют общим ожиданиям, но не являются частью указанных спецификаций.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (240, 31511801, 'Перчатки медицинские диагностические одноразовые нестерильные нитриловые текстурированные на пальцах неопудренные хлорированные BENOVY голубые, размер М, 100 шт 19 122', 'Перчатки универсальны и незаменимы как в медицине, сфере красоты, ресторанной деятельности так и в домашних делах домохозяйки. Благодаря текстурированной поверхности кончиков пальцев перчатки надежны в использовании. Высокая тактильная чувствительность предаёт одноразовым перчаткам ощущение "второй кожи", благодаря чему в них комфортно и удобно вести свою деятельность на протяжении нескольких часов. Нитриловые перчатки прочные и гипоаллергенные, благодаря чему ваши руки в безопасности от воздействия внешних факторов при использовании одноразовых перчаток. Также, перчатки нитриловые устойчивы к проколам от не очень острых предметов, благодаря этому в них можно работать с маникюром не опасаясь разорвать перчатки при надевании и использовании. Перчатки надёжно защищают от активных химических веществ ваши руки при соблюдении мер предосторожности и времени использования одноразовых перчаток.', 'Размер (буквенная система маркировки): M, Количество пар в упаковке: 50', 'https://www.vseinstrumenti.ru/product/perchatki-meditsinskie-diagnosticheskie-odnorazovye-nesterilnye-nitrilovye-teksturirovannye-na-paltsah-neopudrennye-hlorirovannye-benovy-golubye-razmer-m-100-sht-19-122-14372273/', 470, 'pair', 'RUB', NULL, 4, '"\"Продукт соответствует размеру M, как указано в спецификациях. Однако в предоставленных деталях продукта отсутствует информация о том, что перчатки одноразовые, нитриловые и нестерильные. Также не указано, что это медицинские перчатки. Количество пар в упаковке не является критерием в спецификациях.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (246, 31511754, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Компактный корпус: не указано в спецификациях, но можно считать нейтральным фактором.\\n2. Процессор: не указано, какой именно процессор, но ''неплохой процессор'' не является достаточной информацией для оценки соответствия Intel Core i5.\\n3. Количество портов: не указано в спецификациях, но можно считать нейтральным фактором.\\n4. ОЗУ: не указано, не соответствует требованию 8 ГБ.\\n5. SSD: не указано, не соответствует требованию 256 ГБ.\\n6. Операционная система: не указано, не соответствует требованию Windows 10.\\n7. Гарантийный срок: не указано, не соответствует требованию 2 года.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (241, 31511988, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Процессор: В спецификациях указан Intel Core i5, но в описании продукта процессор не уточнён. Это снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Это снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объёме SSD. Это снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе. Это снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Это снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют общим ожиданиям, но не являются частью указанных спецификаций.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (242, 31511648, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется, что это Intel Core i5. Это снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Это снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. Это снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе. Это снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Это снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не ключевые параметры.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (243, 31511636, 'Комод пластиковый в сборе, 3 секции, стиль ротанг', 'Этот пластиковый комод в сборе с 3 секциями и стильным дизайном ротанг идеально подойдет для хранения различных предметов в вашем доме.', 'Материал: пластик; Количество секций: 3; Стиль: ротанг; Цвет: белый; Размеры: 80x40x60 см', 'https://www.ozon.ru/product/komod-plastikovyy-v-sbore-3-sektsii-stil-rotang-621942943/', 2500, 'шт.', 'RUB', NULL, 2, '"\"Продукт не соответствует спецификациям по нескольким критериям. Во-первых, материал продукта - пластик, тогда как спецификации требуют рабочий медицинский стол, который обычно изготавливается из металла или дерева. Во-вторых, цвет продукта - белый, а спецификации требуют коричневый цвет. В-третьих, продукт имеет 3 секции, а спецификации требуют 3 ящика. В-четвертых, размеры продукта (80x40x60 см) не соответствуют указанным в спецификациях (Ширина: 400 мм, Высота: 720 см, Глубина: не указана). Единственное соответствие - это количество секций/ящиков, но это незначительное соответствие. В целом, продукт не соответствует спецификациям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (244, 31511429, 'Офисная бумага SvetoCopy ECO (А4, 500 листов, 80 г/м2)', 'Натуральный цвет', 'Доставка по Москве в пределах МКАД', 'https://shop.cargo-avto.ru/catalog/9604370/', 250, 'лист', 'руб', NULL, 0, '"\"Продукт не соответствует спецификациям. В предоставленных деталях продукта указана только информация о доставке по Москве в пределах МКАД, что не имеет отношения к техническим характеристикам бумаги для офисного оборудования. Нет информации о формате, цвете, плотности, толщине, белизне, непрозрачности, количестве листов в пачке, весе и соответствии стандарту СТ РК 3150-2018.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (245, 31511427, 'Рейтинг лучших ноутбуков до 50 000 рублей 2021', 'Список лучших ноутбуков, доступных за цену до 50 000 рублей в 2021 году.', 'Спецификации ноутбуков, включая процессор, оперативную память, объем накопителя и другие характеристики.', 'https://rutab.net/b/notebooks/2021/05/19/reyting-luchshih-noutbukov-do-50000-rubley-2021.html', 50000, 'piece', 'RUB', NULL, 10, '"\"Процессор: Intel Core i5 - соответствует спецификации.\\nОЗУ: 8 ГБ - соответствует спецификации.\\nSSD: 256 ГБ - соответствует спецификации.\\nОперационная система: Windows 10 - соответствует спецификации.\\nГарантийный срок: 2 года - соответствует спецификации.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (253, 31510977, 'Услуги по организации/проведению конференций/семинаров/форумов/конкурсов/корпоративных/спортивных/культурных/праздничных и аналогичных мероприятий', 'Услуги по организации/проведению конференций/семинаров/форумов/конкурсов/корпоративных/спортивных/культурных/праздничных и аналогичных мероприятий', 'Услуги по проведению тренинга на тему "CFA ® Level I"', 'https://eep.mitwork.kz/ru/publics/lot/356715', 750000, 'Услуги', 'KZT', NULL, 0, '"\"Не удалось провести анализ соответствия, так как отсутствуют данные о спецификациях продукта.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (247, 31511324, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Процессор: В спецификациях указан Intel Core i5, но в описании продукта процессор не уточнён. Это снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Это снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объёме SSD. Это снижает оценку.\\n4. Операционная система: В описании продукта нет информации об установленной операционной системе. Это снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Это снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не компенсирует отсутствие ключевой информации.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (248, 31511399, 'Office Pro+', 'Intel-Core i5 – 10400 2.9 GHz | ОЗУ 8GB DDR4 | SSD 256 GB', 'Материнская плата: ASUS | PRIME | H510M-K | LGA 1200
Процессор: Intel-Core i5 – 10400, 2.9 GHz LGA1200
Система охлаждения: PCCooler S83 PRO
Оперативная память: Lexar DDR4 8GB 2666Mhz
Твердотельный накопитель: SSD M2 Teamgroup 256GB NVMe
Блок питания: Avtech 450W
Корпус Avtech Black
Операционная система Windows 10 Professional', 'https://pcmarket.uz/product/office-pro-br-span-style-color-ff0000-intel-core-i5-10400-ozu-8gb-ddr4-ssd-256-gb-span/', 3940000, 'unit', 'UZS', NULL, 8, '"\"1. Материнская плата ASUS PRIME H510M-K с сокетом LGA 1200 полностью совместима с процессором Intel Core i5 – 10400, что соответствует спецификациям.\\n2. Процессор Intel Core i5 – 10400, 2.9 GHz LGA1200 соответствует спецификациям (Intel Core i5).\\n3. Система охлаждения PCCooler S83 PRO не указана в спецификациях, но это не является критическим несоответствием.\\n4. Оперативная память Lexar DDR4 8GB 2666Mhz соответствует спецификациям (8 ГБ ОЗУ).\\n5. Твердотельный накопитель SSD M2 Teamgroup 256GB NVMe соответствует спецификациям (256 ГБ SSD).\\n6. Блок питания Avtech 450W не указан в спецификациях, но это не является критическим несоответствием.\\n7. Корпус Avtech Black не указан в спецификациях, но это не является критическим несоответствием.\\n8. Операционная система Windows 10 Professional соответствует спецификациям (Windows 10).\\n9. Гарантийный срок не указан в предоставленных деталях продукта, что снижает оценку.\\n\\nИтоговая оценка: 8 из 10. Продукт в целом соответствует спецификациям, за исключением отсутствия информации о гарантийном сроке и некоторых неуказанных компонентов.\""');
