INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (251, 31511011, 'Шины', 'Позиции по лоту', 'Шина для легкового автомобиля, летняя, радиальная, диаметр обода 17', 'https://tenderplus.kz/zakupki/positions/34112883', 39910.71, 'Штука', 'KZT', NULL, 2, '"\"Продукт не соответствует спецификациям по нескольким параметрам. Во-первых, диаметр обода шины составляет 17 дюймов, тогда как в спецификациях указан размер 15 дюймов. Во-вторых, отсутствует информация о размере шины (185/65), а также о индексе скорости (не менее H). В-третьих, нет упоминания о соответствии ГОСТ 4754-97. Единственное соответствие - это то, что шина предназначена для легкового автомобиля и является летней.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (252, 31510992, 'Запрос предложений в Актау', 'Размер: 210*297 мм. Формат: A4. Цвет: Белый. Ширина: 210 мм. Белизна: 146% CIE. Плотность: 72-80 г/м2. Вес: 2,44 кг. Серия: Classic. Яркость: 94% ISO. Страна происхождения: Россия. Количество листов в пачке: 500 листов. Толщина: 104 мкм.', 'Размер: 210*297 мм. Формат: A4. Цвет: Белый. Ширина: 210 мм. Белизна: 146% CIE. Плотность: 72-80 г/м2. Вес: 2,44 кг. Серия: Classic. Яркость: 94% ISO. Страна происхождения: Россия. Количество листов в пачке: 500 листов. Толщина: 104 мкм.', 'https://yar.bt.su/tender/269513090.html', 0, '', '', NULL, 7, '"\"1. Размер: 210*297 мм. Соответствует формату A4. \\n2. Цвет бумаги: Белый. Соответствует. \\n3. Белизна: 146% CIE. Соответствует. \\n4. Плотность: 72-80 г/м2. Соответствует, но нижний предел плотности (72 г/м2) ниже требуемого (80 г/м2). \\n5. Количество листов в пачке: 500 листов. Соответствует. \\n6. Пачка зеленого цвета с белыми буквами черной окантовкой: Информация отсутствует. \\n7. Срок поставки: Информация отсутствует. \\n8. Вес: 2,44 кг. Не указано в спецификациях, но соответствует стандартному весу для пачки бумаги формата A4 и плотности 80 г/м2. \\n9. Серия: Classic. Не указано в спецификациях. \\n10. Яркость: 94% ISO. Не указано в спецификациях. \\n11. Страна происхождения: Россия. Не указано в спецификациях. \\n12. Толщина: 104 мкм. Не указано в спецификациях.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (254, 31510995, 'Запрос предложений в Актау', 'Размер: 210*297 мм. Формат: A4. Цвет: Белый. Ширина: 210 мм. Белизна: 146% CIE. Плотность: 72-80 г/м2. Вес: 2,44 кг. Серия: Classic. Яркость: 94% ISO. Страна происхождения: Россия. Количество листов в пачке: 500 листов. Толщина: 104 мкм.', 'Размер: 210*297 мм. Формат: A4. Цвет: Белый. Ширина: 210 мм. Белизна: 146% CIE. Плотность: 72-80 г/м2. Вес: 2,44 кг. Серия: Classic. Яркость: 94% ISO. Страна происхождения: Россия. Количество листов в пачке: 500 листов. Толщина: 104 мкм.', 'https://yar.bt.su/tender/269513090.html', 0, '', '', NULL, 7, '"\"1. Размер: 210*297 мм. Соответствует формату A4. \\n2. Цвет бумаги: Белый. Соответствует. \\n3. Белизна: 146% CIE. Соответствует. \\n4. Плотность: 72-80 г/м2. Соответствует, но нижний предел плотности (72 г/м2) ниже требуемого (80 г/м2). \\n5. Количество листов в пачке: 500 листов. Соответствует. \\n6. Пачка зеленого цвета с белыми буквами черной окантовкой: Нет информации о цвете пачки и дизайне. \\n7. Срок поставки: Нет информации о сроке поставки. \\n8. Вес: 2,44 кг. Не указано в спецификациях, но соответствует стандартному весу для пачки бумаги формата A4 с 500 листами. \\n9. Серия: Classic. Не указано в спецификациях. \\n10. Яркость: 94% ISO. Не указано в спецификациях. \\n11. Страна происхождения: Россия. Не указано в спецификациях. \\n12. Толщина: 104 мкм. Не указано в спецификациях.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (255, 31510927, 'Офисный компьютер', 'Базовый корпоративный компьютер для офиса, подходит для стандартных служебных задач рядового сотрудника. Подходит для работы с офисными приложениями, CRM-системами, делопроизводством, интернетом, графическими изображениями и медиафайлами.', 'Процессор: AMD Athlon II X2, Intel Celeron G, Intel Core i3 6xxx/7xxx, Intel Pentium G. Оперативная память: 8 Гб DDR4. Жесткие диски: SSD 250 Гб, HDD 500 Гб. Блок питания: 350-400 W. Монитор: 20-24 дюйма, IPS матрица, разрешение 1920x1080. Гарантия от производителя.', 'https://monobloki.com/catalog/kompyutery/', 500, 'unit', 'USD', NULL, 4, '"\"1. Процессор: Продукт предлагает процессоры AMD Athlon II X2, Intel Celeron G, Intel Core i3 6xxx/7xxx, Intel Pentium G, что не соответствует требуемому Intel Core i5. \\n2. Оперативная память: Продукт соответствует спецификации, предлагая 8 ГБ DDR4. \\n3. Жесткий диск: Продукт предлагает SSD 250 ГБ, что близко к требуемому 256 ГБ, но не полностью соответствует. \\n4. Операционная система: Информация о операционной системе отсутствует. \\n5. Гарантия: Информация о гарантии от производителя присутствует, но срок гарантии не указан, что не позволяет оценить соответствие требуемым 2 годам.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (256, 31510876, 'Ноутбук', 'мультимедиялық', 'Тип - Ноутбук; Операционная система - Win 11; Диагональ экрана не менее 14 дюйм; Разрешение экрана не менее 1920x1080, широкоформатный; Частота обновления экрана не менее 60 Гц; Покрытие экрана - матовое; Тип матрицы - IPS; Процессор - Максимальная частота процессора не менее 4000 МГц Базовая частота процессора не менее 2100 МГц; Тип видеоадаптера встроенная; Видеокарта - есть; Размер оперативной памяти не менее 8 ГБ; Тип памяти - DDR4; Частота памяти не менее 3200 МГц; Количество слотов памяти - 2; Тип жесткого диска - SSD; Общий объем накопителей не менее 512 ГБ; Устройство для чтения Flash-карт; Поддерживаемые карты памяти SD; Беспроводная связь и подключение; Стандарт Wi-Fi802.11ac; Версия Bluetooth 5.0; Количество интерфейсов USB 3.13; Интерфейсы USB Type-C, USB Type-A; Входы микрофонный/выход на наушники Combo; Выходы HDMI; Устройства позиционирования - Touchpad; Питание - Аккумулятор не менее - 41 Втч; Приблизительное время автономной работы не менее 9 ч; Габариты не менее (ДхШхТ) - 324x222x18 мм; Вес не более 1.3 кг; Цвет - серебристый; Камера есть.', 'https://satypalu.gov.kz/kz/subpriceoffer/index/8603882/22714750', 350000, 'Дана', 'KZT', NULL, 5, '"\"1. Диагональ экрана: 14 дюймов (не соответствует, требуется не менее 15.6 дюймов).\\n2. Частота обновления экрана: соответствует (не менее 60 Гц).\\n3. Яркость экрана: не указана (не соответствует, требуется не менее 220 кд/м2).\\n4. Покрытие экрана: соответствует (матовое).\\n5. Тип матрицы: соответствует (IPS лучше TN).\\n6. Максимальная частота процессора: 4000 МГц (не соответствует, требуется не менее 4100 МГц).\\n7. Базовая частота процессора: соответствует (не менее 1700 МГц).\\n8. Количество ядер процессора: не указано (не соответствует, требуется не менее 2 ядер).\\n9. Тип видеоадаптера: соответствует (встроенная видеокарта).\\n10. Видеокарта: не указана (не соответствует, требуется не менее Intel UHD Graphics).\\n11. Тип видеопамяти: не указана (не соответствует, требуется не менее SMA).\\n12. Размер оперативной памяти: соответствует (не менее 8 ГБ).\\n13. Тип жесткого диска: соответствует (SSD).\\n14. Общий объем накопителей: соответствует (512 ГБ).\\n15. Устройство для чтения Flash-карт: соответствует.\\n16. Стандарт Wi-Fi: соответствует (802.11ac).\\n17. Версия Bluetooth: соответствует (5.0).\\n18. Количество интерфейсов USB: соответствует (3 порта USB 3.1).\\n19. Входы: соответствует (микрофонный/выход на наушники Combo).\\n20. Выходы: не соответствует (нет RJ-45).\\n21. Устройства позиционирования: соответствует (Touchpad).\\n22. Подсветка клавиатуры: не указана (не соответствует).\\n23. Габариты: соответствует (324x222x18 мм).\\n24. Вес: соответствует (1.3 кг).\\n25. Цвет: не соответствует (серебристый, требуется темный).\\n26. Камера: соответствует.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (257, 31510476, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется, что это Intel Core i5. Это снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Это снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. Это снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе. Это снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Это снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не ключевые параметры.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (262, 31510281, 'Tarkett Melodia 2603', 'Линолеум коммерческий Tarkett «Melodia 2603»', 'Назначение: Коммерческий, Основа линолеума: Гомогенный, Бренд: Tarkett, Коллекция: Melodia, Цвет / декор: Серый, Класс пожаробезопасности: КМ2 (Г1, В2, Д2, Т2, РП1), Толщина линолеума: 2 мм, Толщина защитного слоя: 2 мм, Класс применения: 34/43', 'https://remontnick.ru/linoleum/kommercheskii/34_43/', 2068, 'square meter', 'RUB', NULL, 5, '"\"1. Назначение: Продукт соответствует назначению (Коммерческий).\\n2. Основа линолеума: Продукт соответствует (Гомогенный).\\n3. Бренд: Продукт соответствует (Tarkett).\\n4. Коллекция: Продукт соответствует (Melodia).\\n5. Цвет / декор: Продукт соответствует (Серый).\\n6. Класс пожаробезопасности: Продукт соответствует (КМ2 (Г1, В2, Д2, Т2, РП1)).\\n7. Толщина линолеума: Продукт не соответствует (2 мм вместо 3,2 мм).\\n8. Толщина защитного слоя: Продукт не соответствует (2 мм вместо 0,6 мм).\\n9. Класс применения: Продукт не соответствует (34/43 вместо 33).\\n10. Монтаж: Информация отсутствует.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (258, 31510441, 'Песок', 'Наша компания готова предложить Вам песок строительный с доставкой на ваши объекты. Мы гарантируем высочайшее качество продукции, песок строительный отвечает всем требованиям ГОСТ. Доставка осуществляется грузовыми самосвалами, что позволяет выполнять большие заказы за сравнительно небольшое время. Заказать доставку песка на Ваш объект вы можете обратившись по телефону  +7 (499) 393-37-37', 'Песок карьерный, Песок крупнозернистый мытый, Песок мелкозернистый, Песок намывной (мытый), Песок речной, Песок котлованный, Песок кварцевый', 'https://spec-tehnika.su/produktsiya/pesok-2/', 600, 'м3', 'RUB', NULL, 2, '"\"1. Песок карьерный: не соответствует, так как не указан как мытый.\\n2. Песок крупнозернистый мытый: не соответствует, так как не мелкий.\\n3. Песок мелкозернистый: не соответствует, так как не указан как мытый.\\n4. Песок намывной (мытый): соответствует, так как мытый и, вероятно, мелкий.\\n5. Песок речной: не соответствует, так как не указан как мытый.\\n6. Песок котлованный: не соответствует, так как не указан как мытый.\\n7. Песок кварцевый: не соответствует, так как не указан как мытый и не указан как мелкий.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (259, 31510385, 'Кондиционер настенный ALMACOM Standart ACH- 18QS', 'Сплит-система; Класс A; авторестарт; I-Feel; самоочистка; антиплесень; R410A; медная инсталляция;', 'Мощность охлаждения, БТЕ/ч: 18000
