INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (269, 31509836, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется, что это Intel Core i5. Это может быть как соответствие, так и несоответствие спецификации. 2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. 3. SSD: В описании продукта нет информации о наличии и объеме SSD. 4. Операционная система: В описании продукта нет информации об операционной системе. 5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. 6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не ключевые параметры.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (270, 31510193, 'Бумага SVETOCOPY Premium 500 л. 80 г/м2 А4 марка А', '«SvetoCopy Premium – известное имя, новый уровень качества. Премиальное предложение от SvetoCopy, бренда №1 в категории «Бумага для офиса»*. Премиальная белая бумага в абсолютно чёрной пачке. Производится в соответствии с ГОСТ Р 57641-2017 «Бумага ксерографическая для офисной техники» и относится к офисной бумаге марки «B». Не содержит элементарного хлора. При производстве SvetoCopy Premium используется технология ColorLok ®, что обеспечивает высокую контрастность и яркость изображения, качественные двухсторонние отпечатки и безупречный внешний вид документов. Благодаря повышенному уровню белизны 160% ± 3 % (CIE) SvetoCopy Premium можно доверить важные документы и договоры. Соответствие ГОСТ Р ИСО 9706-2000 гарантирует многолетнее хранение. Система менеджмента сертифицирована на соответствие ГОСТ Р ИСО 45001−2020. Бумага предназначена для работы в принтерах и копировальных аппаратах. Обеспечивает высокое качество отпечатков, которое поможет поддержать имидж и престиж вашего бизнеса.SvetoCopy Premium – бумага для ваших достижений!', 'Формат: А4, Марка бумаги: А, Количество листов: 500, Непрозрачность, % не менее: 93, Плотность бумаги, г/кв.м: 80 ± 1,5-2, Белизна CIE: 160 ± 3%', 'https://www.informat.ru/catalog/ofisnye-tovary/bumaga-dlya-ofisnoy-tekhniki/bumaga-dlya-printerov-i-kopirov/filter/listnost-is-500/formatlist-is-%D0%B04/apply/', 500, 'sheets', 'RUB', NULL, 10, '"\"Продукт соответствует спецификациям по формату (А4) и количеству листов (500). Дополнительные параметры продукта, такие как марка бумаги, непрозрачность, плотность и белизна, не указаны в спецификациях, поэтому они не могут быть оценены на соответствие.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (271, 31509816, 'Компьютер DELL Vostro 3681, Intel Core i5 10400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 630, DVD-RW, CR, Windows 10 Home, черный [3681-9962]', 'Откройте для себя мир безграничных возможностей вместе с компьютером DELL Vostro 3681 черного цвета. SSD-накопитель объемом 256 Гб в сочетании с шестиядерным процессором Intel Core i5 10400 гарантируют превосходную производительность и высокую скорость передачи данных, бесшумную работу. Поскольку компьютер DELL Vostro 3681 поддерживает Wi-Fi, у вас не возникнет трудностей с подключением к сети. Встроенный кард-ридер читает карты памяти формата SD. На задней и передней панелях представленной модели имеются разъемы HDMI, D-Sub, USB 3.0, USB 2.0 и разъемы для наушников и микрофона. В комплекте идут проводные периферийные устройства - мышь и клавиатура. Вес в 4.66 кг упрощает транспортировку. Надежность компьютера подтверждает годовая гарантия от производителя.', 'SSD-накопитель 256 Гб, процессор Intel Core i5 10400, Wi-Fi поддержка, кард-ридер SD, разъемы HDMI, D-Sub, USB 3.0, USB 2.0, разъемы для наушников и микрофона, вес 4.66 кг, годовая гарантия', 'https://www.citilink.ru/product/pk-dell-vostro-3681-sff-i5-10400-8gb-ssd256gb-uhdg-630-dvdrw-cr-w10-kb-1412305/', 49990, 'piece', 'RUB', NULL, 5, '"\"1. Процессор: Соответствует (Intel Core i5).\\n2. ОЗУ: Не указано, не соответствует (требуется 8 ГБ).\\n3. SSD: Соответствует (256 ГБ).\\n4. Операционная система: Не указано, не соответствует (требуется Windows 10).\\n5. Гарантийный срок: Не соответствует (1 год вместо 2 лет).\\n6. Дополнительные характеристики (Wi-Fi, кард-ридер, разъемы HDMI, D-Sub, USB 3.0, USB 2.0, разъемы для наушников и микрофона, вес 4.66 кг): Не требуются по спецификации, но являются дополнительными преимуществами.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (272, 31509778, 'Компьютер DELL Vostro 3681, Intel Core i5 10400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 630, DVD-RW, CR, Windows 10 Home, черный [3681-9962]', 'Откройте для себя мир безграничных возможностей вместе с компьютером DELL Vostro 3681 черного цвета. SSD-накопитель объемом 256 Гб в сочетании с шестиядерным процессором Intel Core i5 10400 гарантируют превосходную производительность и высокую скорость передачи данных, бесшумную работу. Поскольку компьютер DELL Vostro 3681 поддерживает Wi-Fi, у вас не возникнет трудностей с подключением к сети. Встроенный кард-ридер читает карты памяти формата SD. На задней и передней панелях представленной модели имеются разъемы HDMI, D-Sub, USB 3.0, USB 2.0 и разъемы для наушников и микрофона. В комплекте идут проводные периферийные устройства - мышь и клавиатура. Вес в 4.66 кг упрощает транспортировку. Надежность компьютера подтверждает годовая гарантия от производителя.', 'SSD-накопитель 256 Гб, Intel Core i5 10400, DDR4 8ГБ, Intel UHD Graphics 630, DVD-RW, CR, Windows 10 Home, черный, вес 4.66 кг', 'https://www.citilink.ru/product/pk-dell-vostro-3681-sff-i5-10400-8gb-ssd256gb-uhdg-630-dvdrw-cr-w10-kb-1412305/', 49990, 'piece', 'RUB', NULL, 8, '"\"Продукт соответствует следующим спецификациям: процессор Intel Core i5, ОЗУ 8 ГБ, SSD 256 ГБ, операционная система Windows 10. Однако в спецификациях не указаны графический процессор, наличие DVD-RW и CR, цвет и вес устройства, а также гарантийный срок. Отсутствие информации о гарантийном сроке снижает оценку.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (273, 31509781, 'Системный блок ( intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W )', 'Офисный компьютер для дома и офиса. Цена: 18415 ₽.', 'intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W', 'https://boxberry.ru/market/product/sistemnyy-blok-royal-office-i58gb240gb-2440026333/', 18415, 'шт', '₽', NULL, 7, '"\"1. Процессор: Intel Core i5 2400 соответствует требованию Intel Core i5.\\n2. ОЗУ: 8 ГБ соответствует требованию 8 ГБ.\\n3. SSD: 512 ГБ превышает требование 256 ГБ.\\n4. Операционная система: информация отсутствует.\\n5. Гарантийный срок: информация отсутствует.\""');
