ийном сроке.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (275, 31509773, 'Product Name', 'Product Description', 'Product Specifications', 'https://market.otc.ru/ProductRequestGroup/Index/260968', 0, '', '', NULL, 8, '"\"1. Сертификат соответствия ф. СТ KZ: отсутствует.\\n2. Плотность бумаги: 80 г/м2 - соответствует.\\n3. Толщина бумаги: 104 микрон - соответствует.\\n4. Количество листов в пачке: 500 - соответствует.\\n5. Белизна бумаги: 146% - соответствует.\\n6. Использование для черно-белой и цветной печати: соответствует.\\n7. Доставка до объекта за счет Поставщика: соответствует.\""');
