INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (455, 31511614, 'Рейтинг лучших ноутбуков до 50 000 рублей 2021', 'Список лучших ноутбуков, доступных за цену до 50 000 рублей в 2021 году.', 'Список характеристик и особенностей каждого ноутбука из рейтинга.', 'https://rutab.net/b/notebooks/2021/05/19/reyting-luchshih-noutbukov-do-50000-rubley-2021.html', 50000, 'piece', 'RUB', NULL, 0, '"\"Не предоставлены данные о конкретных ноутбуках для анализа.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (279, 31509740, 'Тест-полоски Labstrip U11 plus для анализа мочи', 'Тест-полоски Labstrip U11 plus – основной расходный материал для анализаторов мочи. Используются в анализаторах DocUReader и HandUreader. В одной упаковке содержится 150 тест-полосок LabStrip U11 Plus. Тест-полоски для анализаторов мочи помогают определить билирубин, уробилиноген, кетоны (ацетоуксусная кислота), аскорбиновая кислота, глюкоза, протеин (альбумин), кровь, уровень рН, нитриты, лейкоциты, удельный вес мочи.', 'Характеристика: Значение', 'https://medik-dom.ru/shop/goods/testpoloski_labstrip_u11_plus_dlya_analiza_mochi.html', 1800, 'шт.', 'RUB', NULL, 0, '"\"Предоставленные детали продукта не содержат конкретной информации о характеристиках и значениях, что делает невозможным оценку соответствия спецификациям для изделий медицинского назначения.\""');
