INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (284, 31509013, 'Компьютер для дома и офиса / Офисный компьютер / Системный блок ( intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W )', 'Компьютер для дома и офиса с процессором Intel Core i5 2400, 8 ГБ оперативной памяти, SSD накопителем на 512 ГБ и блоком питания на 400W.', 'Процессор: Intel Core i5 2400, ОЗУ: 8 ГБ, Накопитель: SSD 512 ГБ, Блок питания: 400W', 'https://boxberry.ru/market/product/sistemnyy-blok-royal-office-i58gb240gb-2440026333/', 18415, 'шт', '₽', NULL, 7, '"\"1. Процессор: Соответствует (Intel Core i5).\\n2. ОЗУ: Соответствует (8 ГБ).\\n3. Накопитель: Превышает требования (512 ГБ вместо 256 ГБ).\\n4. Блок питания: Не указан в спецификациях, не оценивается.\\n5. Операционная система: Не указана в деталях продукта, несоответствие.\\n6. Гарантийный срок: Не указан в деталях продукта, несоответствие.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (285, 31509006, 'Офисный компьютер', 'Базовый корпоративный компьютер для офиса, который справляется со стандартными служебными задачами рядового сотрудника.', 'Процессор: AMD Athlon II X2, Intel Celeron G, Intel Core i3 6xxx/7xxx, Intel Pentium G. Оперативная память: 8 Гб DDR4. Накопители: SSD 250 Гб, HDD 500 Гб. Блок питания: 350-400 W. Монитор: 20-24 дюйма, IPS матрица, разрешение 1920x1080 пикселей.', 'https://monobloki.com/catalog/kompyutery/', 500, 'piece', 'USD', NULL, 4, '"\"1. Процессор: Продукт предлагает процессоры AMD Athlon II X2, Intel Celeron G, Intel Core i3 6xxx/7xxx, Intel Pentium G, что не соответствует требуемому Intel Core i5. \\n2. Оперативная память: Продукт соответствует требованию 8 ГБ ОЗУ.\\n3. Накопители: Продукт предлагает SSD 250 ГБ, что близко к требуемому 256 ГБ, но не полностью соответствует. \\n4. Операционная система: Информация о операционной системе отсутствует.\\n5. Гарантийный срок: Информация о гарантийном сроке отсутствует.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (286, 31508919, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется модель. Спецификация требует Intel Core i5. Без точной информации невозможно подтвердить соответствие. \\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Спецификация требует 8 ГБ. \\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. Спецификация требует 256 ГБ. \\n4. Операционная система: В описании продукта нет информации об операционной системе. Спецификация требует Windows 10. \\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Спецификация требует 2 года. \\n6. Компактный корпус и достаточное количество портов соответствуют общим ожиданиям, но не являются частью указанных спецификаций.\""');
