INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (317, 31507712, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется, что это Intel Core i5. Это снижает оценку.\\n2. ОЗУ: В описании продукта не указано количество оперативной памяти. Это снижает оценку.\\n3. SSD: В описании продукта не указано наличие и объем SSD. Это снижает оценку.\\n4. Операционная система: В описании продукта не указана операционная система. Это снижает оценку.\\n5. Гарантийный срок: В описании продукта не указан гарантийный срок. Это снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не компенсирует отсутствие ключевой информации.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (318, 31507731, 'Office Pro+', 'Intel-Core i5 – 10400 2.9 GHz | ОЗУ 8GB DDR4 | SSD 256 GB', 'Материнская плата: ASUS | PRIME | H510M-K | LGA 1200
