INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (319, 31507756, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В спецификациях указан Intel Core i5, но в описании продукта процессор не уточнён, что снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти, что снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объёме SSD, что снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе, что снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке, что снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не компенсирует отсутствие ключевой информации.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (320, 31507602, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется модель. Спецификация требует Intel Core i5. Без точной информации невозможно подтвердить соответствие. \\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Спецификация требует 8 ГБ. \\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. Спецификация требует 256 ГБ. \\n4. Операционная система: В описании продукта нет информации об операционной системе. Спецификация требует Windows 10. \\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Спецификация требует 2 года. \\n6. Компактный корпус и достаточное количество портов не противоречат спецификациям, но и не подтверждают их выполнение.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (321, 31507363, 'Компьютер для дома и офиса / Офисный компьютер / Системный блок ( intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W )', 'Компьютер для дома и офиса с процессором Intel Core i5 2400, 8 ГБ оперативной памяти, SSD накопителем на 512 ГБ и блоком питания на 400W.', 'Процессор: Intel Core i5 2400
Оперативная память: 8 ГБ
Накопитель: SSD 512 ГБ
