INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (324, 31507299, 'Услуги по предоставлению лицензий на право использования программного обеспечения', 'Услуги по предоставлению лицензий на право использования программного обеспечения', '395 970,00 KZT', 'https://eep.mitwork.kz/ru/publics/lots/110540007572?page=2&per-page=50', 582950.000000001, 'DLP2', 'KZT', NULL, 0, '"\"Цена продукта составляет 395 970,00 KZT. Однако, информация о процессоре, ОЗУ, SSD, операционной системе и гарантийном сроке отсутствует. Без этих данных невозможно оценить соответствие продукта спецификациям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (325, 31507158, 'ПО транслятор текста в Брайль "Duxbury Braille Translator (DBT)"', 'Duxbury BrailleTranslator (DBT) – это программа, которая осуществляет двунаправленный перевод: обыкновенный шрифт переводится в азбуку Брайля и обратно. Также DBT - это полнофункциональный текстовый редактор, при помощи которого можно подготовить любой документ к печати по брайлю на нескольких десятках языков, в самых разнообразных кодировках.', 'Позволяет импортировать файлы в формате MS Word, WordPerfect, HTML. Текст можно создавать непосредственно в редакторе DBT. Ввод текста как обычным способом, так и азбукой Брайля. Программа содержит большое количество «ключей форматирования». Комбинации ключей форматирования позволяют создавать «стили». Включает в себя орфографический словарь на 300000 слов. Программа поддерживает практически все существующие модели брайлевских принтеров.', 'https://dostupnaya-sreda.pro/catalog/inklyuzivnoe-obrazovanie/komp-yutery-i-programmnoe-obespechenie/po-translyator-teksta-v-brajl-duxbury-braille-translator-dbt/', 10000, 'шт', 'RUB', NULL, 8, '"\"Продукт позволяет импортировать файлы в формате MS Word, WordPerfect, HTML, что соответствует спецификациям. Текст можно создавать непосредственно в редакторе DBT, что также соответствует требованиям. Ввод текста возможен как обычным способом, так и азбукой Брайля, что полностью соответствует спецификациям. Программа содержит большое количество «ключей форматирования», что также соответствует требованиям. Комбинации ключей форматирования позволяют создавать «стили», что является дополнительным плюсом. Включение орфографического словаря на 300000 слов соответствует требованию о функции для быстрого обнаружения орфографических ошибок и их устранения. Программа поддерживает практически все существующие модели брайлевских принтеров, что соответствует спецификациям. Однако, в предоставленных деталях продукта отсутствует информация о поддержке казахского языка и двунаправленном переводе (обыкновенный шрифт в азбуку Брайля и обратно), что является важным требованием спецификаций.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (342, 31506087, 'Кресло для актовых и конференц залов Соната со столиком', 'Кресла для актовых залов «Соната» отличаются эргономичностью и надежностью. Отличное стилевое решение кресла для актовых залов «Соната» и невысокая стоимость – главные преимущества данной модели. Фигурная спинка и форма сиденья подчеркнут изысканность и стилевое оформление каждого зала. Установка кресла «Соната» в зале возможна без крепления к полу. Деревянный подлокотник кресла может быть выполнен в нескольких вариантах. В зависимости от освещенности актового или конференционного зала может быть подобран цвет ткани, подлокотников и покрытия металлических стоек. Кресло «Соната» может быть изготовлено с пюпитром. По желанию заказчика можно подобрать вариант номерков и конфигурацию стоек.', 'Дизайн кресел современный и лаконичный. Конструкция кресел разработана с учетом эргономики и максимально комфортна, выдерживает высокие эксплуатационные нагрузки. Кресла стационарные с креплением к полу, собираются в секции. Конструкция кресел предусматривает оперативную замену сиденья и спинки при необходимости. Габаритные размеры: Высота – 900 мм. Ширина в осях – 500-520 мм. Глубина в сложенном виде – 440 мм. Глубина в разложенном виде – 660 мм. Металлический каркас: Стальной, цельносварной, окрашен стойкой порошковой эмалью, базовый цвет – «черный бархат». Металлическая несущая опора (нога) кресла приварена под углом к специализированной штампованной объёмной пластине, через которую осуществляется крепление конструкции к полу. Крайние металлические опоры задекорированы глухими декоративными заглушками с помощью скрытых крепежных элементов. Спинка и сиденье кресла: Подушка спинки кресла мягкая, не менее 50 мм. толщиной, прямоугольной формы с закругленными углами. Каркас спинки жестко крепится к металлическому каркасу кресла. Спинка подушки кресла имеет рельефный объемный геометрический узор в виде 4-х параллельных линий. Подушка сиденья кресла мягкая, не менее 50 мм. толщиной, прямоугольной формы с закругленными углами. Сиденье оснащено гравитационным механизмом опрокидывания, принимает автоматически нерабочее поднятое положение без предварительного воздействия внешних направленных усилий, не снижает удобства прохода между рядами. Поднятие - опускание откидного сиденья не сопровождается какими-либо посторонними шумами. Деревянные подлокотники кресел изготавливаются из массива твердых пород древесины и покрываются специальным износостойким лаком с высокой степенью кристаллизации. Возможен выбор различной тонировки деревянных подлокотников. Влажность деталей из древесины и деревоматериалов, прочность клеевого крепления при облицовке кромкой деталей кресел соответствует ГОСТ 16371-93. Сборка и монтаж кресел осуществляется на месте.', 'https://pinsk.deal.by/p6701628-kreslo-dlya-aktovyh.html', 900, 'piece', 'USD', NULL, 5, '"\"1. Дизайн кресел современный и лаконичный, что соответствует требованиям. 2. Конструкция кресел эргономична и комфортна, выдерживает высокие нагрузки, что также соответствует требованиям. 3. Кресла стационарные с креплением к полу и собираются в секции, что соответствует требованиям. 4. Оперативная замена сиденья и спинки предусмотрена, что соответствует требованиям. 5. Габаритные размеры кресел соответствуют требованиям: высота 900 мм (требуется 910 мм), ширина в осях 500-520 мм (требуется 500 мм), глубина в сложенном виде 440 мм (требуется 440 мм), глубина в разложенном виде 660 мм (требуется 660 мм). 6. Металлический каркас стальной, цельносварной, окрашен стойкой порошковой эмалью, что соответствует требованиям. 7. Металлическая несущая опора кресла приварена под углом к специализированной штампованной пластине, что соответствует требованиям. 8. Крайние металлические опоры задекорированы заглушками, что соответствует требованиям. 9. Спинка и сиденье кресла мягкие, не менее 50 мм толщиной, что не соответствует требованиям (требуется 60 мм). 10. Спинка подушки кресла имеет рельефный узор, что не соответствует требованиям (требуется отстрочка в трех линиях). 11. Сиденье оснащено гравитационным механизмом опрокидывания, что соответствует требованиям. 12. Деревянные подлокотники изготавливаются из массива твердых пород древесины и покрываются износостойким лаком, что соответствует требованиям. 13. Влажность деталей из древесины и деревоматериалов соответствует ГОСТ 16371-93, что соответствует требованиям. 14. Обивка из гобелена не указана, что не соответствует требованиям. 15. Задняя часть спинки не обшита винилкожей, что не соответствует требованиям. 16. Внутреннее наполнение поролон толщиной 50 мм, что не соответствует требованиям (требуется 60 мм). 17. Боковой шов кресла спинки не указан, что не соответствует требованиям. 18. Составляющие часть каркаса подлокотника не указаны, что не соответствует требованиям. 19. Гарантийный срок не указан, что не соответствует требованиям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (326, 31507242, 'Рычаг передний верхний левый для Ssang Yong Actyon Sports 2012-2016 новый', 'Новый Лидер продаж', 'Номер: Metaco 4310011L Деталь на схеме
