INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (327, 31507149, 'Рейтинг лучших ноутбуков до 50 000 рублей 2021', 'Список лучших ноутбуков, доступных по цене до 50 000 рублей в 2021 году.', 'Список характеристик и особенностей ноутбуков из рейтинга.', 'https://rutab.net/b/notebooks/2021/05/19/reyting-luchshih-noutbukov-do-50000-rubley-2021.html', 50000, 'piece', 'RUB', NULL, 0, '"\"Отсутствуют данные о конкретных моделях ноутбуков и их характеристиках. Невозможно провести анализ соответствия спецификациям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (328, 31507085, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется модель. Спецификация требует Intel Core i5. Без точной информации невозможно подтвердить соответствие. \\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Спецификация требует 8 ГБ. \\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. Спецификация требует 256 ГБ. \\n4. Операционная система: В описании продукта нет информации об операционной системе. Спецификация требует Windows 10. \\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Спецификация требует 2 года. \\n6. Компактный корпус и достаточное количество портов соответствуют общим ожиданиям, но не являются частью указанных спецификаций.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (329, 31507086, 'Чехол для домбры', 'Чехол для домбры с утеплением. Цвет черный. Размер – стандарт; Материал – полиэстер водонепроницаемый, утепленный; Имеет 1 наружный карман, ручку и плечевой ремень.', 'Страна производитель: Казахстан', 'https://music-room.kz/p4858037-chehol-dlya-dombry.html', 4000, 'шт', '₸', NULL, 1, '"\"1. Страна производитель: Казахстан - информация предоставлена, соответствует требованиям.\\n2. Тип: полужесткий - информация отсутствует, невозможно оценить соответствие.\\n3. Материал: полиэстер - информация отсутствует, невозможно оценить соответствие.\\n4. Особенности: водонепроницаемый, утепленный, с ручкой - информация отсутствует, невозможно оценить соответствие.\\n5. Длина: 105 см - информация отсутствует, невозможно оценить соответствие.\\n6. Ширина: 25 см - информация отсутствует, невозможно оценить соответствие.\\n7. ГОСТ 16965-71 - информация отсутствует, невозможно оценить соответствие.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (330, 31506693, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Компактный корпус: не указано в спецификациях, но можно считать плюсом. 2. Процессор: не указано, какой именно процессор, поэтому неясно, соответствует ли он Intel Core i5. 3. ОЗУ: не указано, поэтому неясно, соответствует ли оно 8 ГБ. 4. SSD: не указано, поэтому неясно, соответствует ли он 256 ГБ. 5. Операционная система: не указано, поэтому неясно, соответствует ли она Windows 10. 6. Гарантийный срок: не указан, поэтому неясно, соответствует ли он 2 годам.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (352, 31505653, 'Офисная бумага А4 - 131 предложение в России, сравнить цены и купить', 'Каталог товаров и услуг, где вы можете купить офисная бумага А4 среди 131 предложения поставщиков в России. Уточняйте оптовые и розничные цены на офисная бумага А4, наличие на складе, стоимость доставки в ваш регион у компании поставщика.', '2 января 2024', 'http://www.regtorg.ru/goods/ofisnaya_bumaga_a4.html', 300000, 'т.', 'RUB', NULL, 0, '"\"Продукт не соответствует спецификациям. Указана только дата ''2 января 2024'', что не является характеристикой бумаги для офисного оборудования формата А4. Нет информации о формате, количестве листов в пачке и других важных характеристиках.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (331, 31506786, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В спецификациях указан Intel Core i5, но в описании продукта процессор не уточнён, что снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти, что снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объёме SSD, что снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе, что снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке, что снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не ключевые параметры.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (332, 31507144, 'Office Pro+', 'Intel-Core i5 – 10400 2.9 GHz | ОЗУ 8GB DDR4 | SSD 256 GB', 'Материнская плата: ASUS | PRIME | H510M-K | LGA 1200
Процессор: Intel-Core i5 – 10400, 2.9 GHz LGA1200
Система охлаждения: PCCooler S83 PRO
Оперативная память: Lexar DDR4 8GB 2666Mhz
Твердотельный накопитель: SSD M2 Teamgroup 256GB NVMe
Блок питания: Avtech 450W
Корпус Avtech Black
Операционная система Windows 10 Professional', 'https://pcmarket.uz/product/office-pro-br-span-style-color-ff0000-intel-core-i5-10400-ozu-8gb-ddr4-ssd-256-gb-span/', 3940000, 'unit', 'UZS', NULL, 8, '"\"1. Процессор: Соответствует (Intel Core i5 – 10400, 2.9 GHz LGA1200).\\n2. Оперативная память: Соответствует (Lexar DDR4 8GB 2666Mhz).\\n3. Твердотельный накопитель: Соответствует (SSD M2 Teamgroup 256GB NVMe).\\n4. Операционная система: Соответствует (Windows 10 Professional).\\n5. Гарантийный срок: Не указан, что снижает оценку.\\n6. Дополнительные компоненты (материнская плата, система охлаждения, блок питания, корпус): Не указаны в спецификациях, но соответствуют стандартам для сборки ПК.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (333, 31506691, 'Офисный компьютер', 'Базовый корпоративный компьютер для офиса, подходит для стандартных служебных задач рядовых сотрудников. Подбор компьютера учитывает рабочие задачи и нагрузки сотрудников.', 'Видеокарта: Интегрированная видеокарта достаточна для работы с офисными приложениями. Процессор: Бюджетные 2-ядерные процессоры подойдут для офисных задач. Оперативная память: Оптимальный объем оперативной памяти - 8 Гб. Накопители: Рекомендуется установка SSD и HDD накопителей. Блок питания: Блок питания на 350-400 W достаточен для базового офисного компьютера. Монитор: Монитор с диагональю 20-24 дюйма, матрицей IPS и разрешением 1920х1080 пикселей.', 'https://monobloki.com/catalog/kompyutery/', 500, 'piece', 'USD', NULL, 6, '"\"1. Видеокарта: Интегрированная видеокарта достаточна для работы с офисными приложениями. Спецификации не указывают требования к видеокарте, поэтому считаем, что соответствие есть.\\n2. Процессор: В спецификациях указан Intel Core i5, что превышает требование бюджетного 2-ядерного процессора для офисных задач. Соответствие есть.\\n3. Оперативная память: Оптимальный объем оперативной памяти - 8 Гб. Спецификации указывают 8 ГБ ОЗУ, что соответствует требованию. Соответствие есть.\\n4. Накопители: Рекомендуется установка SSD и HDD накопителей. В спецификациях указан только SSD на 256 ГБ. Частичное соответствие.\\n5. Блок питания: В спецификациях не указан блок питания, поэтому оценить соответствие невозможно. Отсутствие информации.\\n6. Монитор: В спецификациях не указан монитор, поэтому оценить соответствие невозможно. Отсутствие информации.\\n7. Операционная система: В спецификациях указана Windows 10. В требованиях не указана операционная система, поэтому считаем, что соответствие есть.\\n8. Гарантийный срок: В спецификациях указан гарантийный срок 2 года. В требованиях не указан гарантийный срок, поэтому считаем, что соответствие есть.\\n\\nИтоговая оценка: 6 из 10. Продукт частично соответствует спецификациям, но отсутствует информация по блоку питания и монитору, а также не полностью соответствует требованию по накопителям.\""');
