INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (355, 31505653, 'Офисная бумага А4 - 131 предложение в России, сравнить цены и купить', 'Каталог товаров и услуг, где вы можете купить офисная бумага А4 среди 131 предложения поставщиков в России. Уточняйте оптовые и розничные цены на офисная бумага А4, наличие на складе, стоимость доставки в ваш регион у компании поставщика.', '2 января 2024', 'http://www.regtorg.ru/goods/ofisnaya_bumaga_a4.html', 300000, 'т.', 'RUB', NULL, 0, '"\"Продукт не соответствует спецификациям. Указана только дата, нет информации о формате бумаги, количестве листов в пачке и предназначении для офисного оборудования.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (356, 31505599, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Процессор: не указано, соответствует ли он Intel Core i5. \\n2. ОЗУ: не указано. \\n3. SSD: не указано. \\n4. Операционная система: не указана. \\n5. Гарантийный срок: не указан. \\n6. Компактный корпус: дополнительное соответствие. \\n7. Достаточное количество портов: дополнительное соответствие.\""');
