INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (359, 31505531, 'Production of fish mince Neopress', 'Neopress is a modern high-performance equipment for the production of fish mince. It is designed for the production of high-quality fish mince from various types of fish.', 'Capacity: 500-1000 kg/h; Power: 7.5 kW; Material: Stainless steel; Dimensions: 1200x800x1300 mm', 'https://voltekgroup.com/catalog/rybopererabatyvayushchee_oborudovanie/proizvodstvo_rybnogo_farsha_neopress/375/', 12500, 'piece', 'USD', NULL, 6, '"\"1. Производительность: продукт имеет производительность 500-1000 кг/ч, что значительно превышает требуемые 180 кг/ч. Это соответствует спецификациям.\\n2. Потребляемая мощность: продукт потребляет 7.5 кВт, что также превышает минимально требуемые 1.8 кВт. Это соответствует спецификациям.\\n3. Материал: продукт изготовлен из нержавеющей стали, что является положительным аспектом, хотя материал не указан в спецификациях.\\n4. Габариты: продукт имеет размеры 1200x800x1300 мм, что превышает минимально требуемые 770x600x900 мм. Это соответствует спецификациям.\\n5. Напряжение: информация о напряжении отсутствует, что является несоответствием.\\n6. Размеры мяльной ленты, ширина рабочей поверхности и диаметр отверстий барабана: информация отсутствует, что является несоответствием.\\n7. Масса: информация о массе отсутствует, что является несоответствием.\""');
