INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (364, 31504892, 'Система радиочастотной коагуляции Closure Fast', 'Катетер внутривенный для радиочастотной абляции Closure Fast', 'Система радиочастотной коагуляции Closure Fast предназначена для проведения радиочастотной абляции вен нижних конечностей. Катетер Closure Fast обеспечивает быстрое и эффективное лечение варикозного расширения вен без необходимости общей анестезии.', 'https://medstore.kz/83-koagulyatoryekhvch-apparaty/12365-kateter-vnutrivennyi-dlya-radiocastotnoi-ablyacii-closure-fast', 150000, 'шт', 'KZT', NULL, 7, '"\"Продукт ''Система радиочастотной коагуляции Closure Fast'' предназначен для проведения радиочастотной абляции вен нижних конечностей, что соответствует спецификации. Катетер Closure Fast обеспечивает быстрое и эффективное лечение варикозного расширения вен без необходимости общей анестезии, что также соответствует спецификации. Однако в предоставленных деталях продукта не указано, что в комплект входит игла пункционная типа Стерикан, гель для ультразвуковых исследований, интрадьюсер и магистраль для насоса, совместимая с насосом MediolaPump. Также не указан диаметр катетера (7F).\""');
