INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (368, 31504983, 'Марля медицинская отбеленная, рулон 0,9х200 м, плотность 52 (±2) г/м2, LAIMA, 630078', 'Нужно больше?', 'Под заказ со склада производителя от 1 шт. Срок поставки сообщит оператор', 'https://www.officemag.ru/catalog/goods/630078/', 300, 'шт.', 'RUB', NULL, 1, '"\"Продукт не содержит информации о плотности марли, составе ткани, воздухопроницаемости, отбеленной поверхности и других характеристиках, указанных в спецификациях. Единственная предоставленная информация касается условий поставки, что не соответствует техническим спецификациям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (369, 31504717, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: не указано, соответствует ли он Intel Core i5. \\n2. ОЗУ: не указано. \\n3. SSD: не указано. \\n4. Операционная система: не указана. \\n5. Гарантийный срок: не указан. \\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (370, 31505312, 'Сплит-система Ballu LAGOON BSD-09HN1 26 m2', 'Моющийся воздушный фильтр в комплекте', 'Мощность в режиме охлаждения: 2640 Вт, Мощность в режиме обогрева: 2,78 квт, Wi-Fi управление – опция, Габариты внешнего блока: 815*615*325 мм, Таймер включения/выключения: есть, Фильтры тонкой очистки воздуха: нет, Глубина внешнего блока (см): 24, Минимальная t для режима обогрева: -7 °C, Энергоэффективность / класс: A, Диаметр труб жидкость/газ, мм (дюймы): 6,35 / 9,52 (1/4-3/8), Диаметр трубок (газ), (дюйм): 3/8, Теплопроизводительность, btu: 9500, Дистанционное беспроводное: Удаленное управление wi-fi, Вес внутреннего блока, кг: 7.5, Диапазон t на охлаждение, с: +18...+43, Макс. производ-ность обогрева: 2.78 кВт, Функция интенсивного охлаждения: Да, Ширина упаковки внешнего блока: 78 см, Производительность вентилятора, м3/час: 452, Потребляемая мощность на охлаждение: 0.82 кВт, Минимальный уровень шума: 26 дБ, Регулировка температуры нагрева: нет, Размеры внешнего блока (шxвxг): 700x550x275 мм, Класс энергоэффективности охлаждения: А, Размеры внутреннего блока вхшхг: 285х715х194, Производительность по воздуху: 452 м³/ч, Основные режимы кондиционирования: ночной режим, вентиляция, обогрев, осушение, охлаждение', 'https://ballu-market.ru/p/split-sistema-ballu-lagoon-bsd-09hn1-26-m2/details', 28500, 'шт', '₽', NULL, 6, '"\"1. Мощность в режиме охлаждения: 2640 Вт (соответствует спецификации).\\n2. Мощность в режиме обогрева: 2,78 кВт (соответствует спецификации).\\n3. Wi-Fi управление – опция (несоответствие, в спецификации указано, что поддержка Wi-Fi отсутствует).\\n4. Габариты внешнего блока: 815*615*325 мм (несоответствие, в спецификации указаны другие размеры: 700x550x275 мм).\\n5. Таймер включения/выключения: есть (соответствует спецификации).\\n6. Фильтры тонкой очистки воздуха: нет (соответствует спецификации).\\n7. Глубина внешнего блока (см): 24 (несоответствие, в спецификации указана толщина 27 см).\\n8. Минимальная t для режима обогрева: -7 °C (соответствует спецификации).\\n9. Энергоэффективность / класс: A (соответствует спецификации).\\n10. Диаметр труб жидкость/газ, мм (дюймы): 6,35 / 9,52 (1/4-3/8) (соответствует спецификации).\\n11. Диаметр трубок (газ), (дюйм): 3/8 (соответствует спецификации).\\n12. Теплопроизводительность, btu: 9500 (соответствует спецификации).\\n13. Дистанционное беспроводное: Удаленное управление wi-fi (несоответствие, в спецификации указано, что поддержка Wi-Fi отсутствует).\\n14. Вес внутреннего блока, кг: 7.5 (несоответствие, в спецификации указано 8.5 кг).\\n15. Диапазон t на охлаждение, с: +18...+43 (соответствует спецификации).\\n16. Макс. производ-ность обогрева: 2.78 кВт (соответствует спецификации).\\n17. Функция интенсивного охлаждения: Да (соответствует спецификации).\\n18. Ширина упаковки внешнего блока: 78 см (не указано в спецификации).\\n19. Производительность вентилятора, м3/час: 452 (соответствует спецификации).\\n20. Потребляемая мощность на охлаждение: 0.82 кВт (несоответствие, в спецификации указано 2640 Вт).\\n21. Минимальный уровень шума: 26 дБ (соответствует спецификации).\\n22. Регулировка температуры нагрева: нет (соответствует спецификации).\\n23. Размеры внешнего блока (шxвxг): 700x550x275 мм (соответствует спецификации).\\n24. Класс энергоэффективности охлаждения: А (соответствует спецификации).\\n25. Размеры внутреннего блока вхшхг: 285х715х194 (соответствует спецификации).\\n26. Производительность по воздуху: 452 м³/ч (соответствует спецификации).\\n27. Основные режимы кондиционирования: ночной режим, вентиляция, обогрев, осушение, охлаждение (соответствует спецификации).\\n28. Рекомендуемая площадь помещения 25 м² (соответствует спецификации).\\n29. Тип Настенная сплит-система (соответствует спецификации).\\n30. Хладагент R 410A (не указано в деталях продукта).\\n31. Инверторный Нет (не указано в деталях продукта).\\n32. Монтажный комплект Да (не указано в деталях продукта).\\n33. Максимальный уровень шума 54 дБ (не указано в деталях продукта).\\n34. Площадь обслуживаемого помещения 27 м² (не указано в деталях продукта).\\n35. Цвет корпуса белый (не указано в деталях продукта).\\n36. Вес наружнего блока 26 кг (не указано в деталях продукта).\\n37. Высота наружнего блока 49.5 см (не указано в деталях продукта).\\n38. Ширина наружнего блока 72 см (не указано в деталях продукта).\\n39. Толщина наружнего блока 27 см (не указано в деталях продукта).\\n40. Срок гарантии 12 мес (не указано в деталях продукта).\\n41. Пульт дистанционного управления Да (не указано в деталях продукта).\\n42. Режимы работы Быстрое охлаждение; Ночной режим работы; Осушение воздуха; Турбо; Вентиляция (соответствует спецификации).\\n43. Дисплей Да (не указано в деталях продукта).\\n44. Максимальная рабочая температура в режиме охлаждения 43 °C (соответствует спецификации).\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (371, 31504879, 'Рейтинг лучших ноутбуков до 50 000 рублей 2021', 'Список лучших ноутбуков, доступных за цену до 50 000 рублей в 2021 году.', 'Список характеристик и особенностей ноутбуков из рейтинга.', 'https://rutab.net/b/notebooks/2021/05/19/reyting-luchshih-noutbukov-do-50000-rubley-2021.html', 50000, 'piece', 'RUB', NULL, 0, '"\"Для оценки соответствия продукта спецификациям необходимо предоставить список характеристик и особенностей ноутбуков из рейтинга.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (372, 31504880, 'Рейтинг лучших ноутбуков до 50 000 рублей 2021', 'Список лучших ноутбуков, доступных по цене до 50 000 рублей в 2021 году.', 'Список характеристик и особенностей ноутбуков из рейтинга.', 'https://rutab.net/b/notebooks/2021/05/19/reyting-luchshih-noutbukov-do-50000-rubley-2021.html', 50000, 'piece', 'RUB', NULL, 0, '"\"Для оценки соответствия продукта спецификациям необходимо предоставить список характеристик и особенностей ноутбуков из рейтинга.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (373, 31504469, 'Футляр-укладка врача скорой медпомощи УМСП-01-П 520х310х390мм (без вложений)', 'Футляр-укладка УМСП-01-П 520х310х390 врача скорой медицинской помощи (ТУ 9437-004-18585567-2002) предназначена для комплектования, хранения, и транспортировки медицинских вложений. Область применения укладки: службы скорой медицинской помощи, медицина катастроф, ГО и ЧС, военная и экстремальная медицина; медпункты и здравпункты предприятий, школ, гостиниц, санаториев и домов отдыха; амбулаторные учреждения. Чаще всего данную продукцию покупают специально для врачей скорой помощи и служб спасения.', 'Материал: высокопрочный холодо- и тепло-стойкий пищевой пластик; Габаритные размеры (мм): 520х310х390; Масса (кг): 3,5; Рабочий диапазон температур (°C): -30..40; Номинальная нагрузка (кг) 12; Кол-во мест для ампул (шт): 176', 'https://www.medrk.kz/shop/reanimaciya-anesteziya-ivl-kislorodnoe-oborudovanie/sumki-ukladki_dlya_skoroj_pomoshhi/id-19088', 0, 'item', 'KZT', NULL, 5, '"\"1. Материал: указано, что используется высокопрочный холодо- и тепло-стойкий пищевой пластик, но не уточнено, что это АБС пластик. Также не указано, что материал ложемента - ''изолон''.\\n2. Габаритные размеры: соответствуют спецификации (520х310х390 мм).\\n3. Масса: соответствует спецификации (3,5 кг).\\n4. Рабочий диапазон температур: не указан в спецификации, поэтому не оценивается.\\n5. Номинальная нагрузка: соответствует спецификации (12 кг).\\n6. Кол-во мест для ампул: не указано в спецификации, поэтому не оценивается.\\n7. Внутреннее устройство: не указано наличие четырех лотков-футляров с мягкими стенками из ''изолона'', а также пазов для установки жестких пластин-перегородок.\\n8. Комплектация: не указано наличие наклейки (аппликации) с перечнем медицинских и лекарственных препаратов.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (374, 31504672, 'Системный блок ( intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W )', 'Компьютер для дома и офиса / Офисный компьютер', 'характеристики, описание, фото', 'https://boxberry.ru/market/product/sistemnyy-blok-royal-office-i58gb240gb-2440026333/', 18415, 'шт', '₽', NULL, 0, '"\"Продукт не был предоставлен для анализа.\""');
