INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (376, 31504953, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 1, '"\"1. Процессор: информация о процессоре не указана, поэтому невозможно оценить соответствие (0 баллов).\\n2. ОЗУ: информация о количестве ОЗУ отсутствует (0 баллов).\\n3. SSD: информация о SSD отсутствует (0 баллов).\\n4. Операционная система: информация об операционной системе отсутствует (0 баллов).\\n5. Гарантийный срок: информация о гарантийном сроке отсутствует (0 баллов).\\n6. Компактный корпус и достаточное количество портов соответствуют общим ожиданиям, но не являются частью указанных спецификаций (1 балл).\\nИтоговая оценка: 1 из 10.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (377, 31504980, 'Стиральный порошок', 'Синтетическое моющее средство для использования в стиральных машинах. Подходит для машинной стирки цветных и темных вещей. Удаляет пятна и сильные загрязнения. Содержит специальные компоненты, помогающие сохранить яркость цветных вещей, а также придает вещам приятный аромат. Сохраняет цвета яркими как новые. Помогает предотвратить образование накипи и известкового налета на спирали стиральной машины. Состав: содержит смягчающие воду вещества, защищающие стиральную машину от образования известкового налета, фосфаты, цеолиты, лимонная кислота, позволяющие защитить стиральную машину от накипи, менее 5% - катионные и неионогенные ПАВ, поликарбокислоты, фосфонаты, 5-15% - анионные ПАВ, кислород-содержащие отбеливатели, 15-30% - фосфаты. Дополнительно: энзимы, оптический отбеливатель. Фасовка не менее 3 кг', 'Синтетическое моющее средство для использования в стиральных машинах. Подходит для машинной стирки цветных и темных вещей. Удаляет пятна и сильные загрязнения. Содержит специальные компоненты, помогающие сохранить яркость цветных вещей, а также придает вещам приятный аромат. Сохраняет цвета яркими как новые. Помогает предотвратить образование накипи и известкового налета на спирали стиральной машины. Состав: содержит смягчающие воду вещества, защищающие стиральную машину от образования известкового налета, фосфаты, цеолиты, лимонная кислота, позволяющие защитить стиральную машину от накипи, менее 5% - катионные и неионогенные ПАВ, поликарбокислоты, фосфонаты, 5-15% - анионные ПАВ, кислород-содержащие отбеливатели, 15-30% - фосфаты. Дополнительно: энзимы, оптический отбеливатель. Фасовка не менее 3 кг', 'https://zakupki.kontur.ru/0351300064614000025', 500, 'kg', 'RUB', NULL, 0, '"\"Продукт не соответствует предоставленным техническим спецификациям. Техническая спецификация описывает моющее средство для кухни, предназначенное для чистки различных кухонных поверхностей и принадлежностей, без содержания хлора. В то время как предоставленный продукт является синтетическим моющим средством для использования в стиральных машинах, предназначенным для стирки цветных и темных вещей, удаления пятен и сильных загрязнений, а также защиты стиральной машины от накипи и известкового налета. Продукт содержит фосфаты и другие компоненты, которые не соответствуют требованиям спецификации.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (378, 31504218, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется модель. Спецификация требует Intel Core i5. Это несоответствие.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Спецификация требует 8 ГБ. Это несоответствие.\\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. Спецификация требует 256 ГБ. Это несоответствие.\\n4. Операционная система: В описании продукта нет информации об операционной системе. Спецификация требует Windows 10. Это несоответствие.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Спецификация требует 2 года. Это несоответствие.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не компенсирует отсутствующую информацию по ключевым параметрам.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (379, 31504138, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 1, '"\"1. Процессор: информация о процессоре не указана, поэтому невозможно оценить соответствие (0 баллов).\\n2. ОЗУ: информация о количестве ОЗУ отсутствует (0 баллов).\\n3. SSD: информация о SSD отсутствует (0 баллов).\\n4. Операционная система: информация об операционной системе отсутствует (0 баллов).\\n5. Гарантийный срок: информация о гарантийном сроке отсутствует (0 баллов).\\n6. Компактный корпус и достаточное количество портов соответствуют общим ожиданиям, но не являются частью указанных спецификаций (1 балл).\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (380, 31503939, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется, что это Intel Core i5. Это снижает оценку.\\n2. ОЗУ: В описании продукта не указано количество оперативной памяти. Это снижает оценку.\\n3. SSD: В описании продукта не указано наличие и объем SSD. Это снижает оценку.\\n4. Операционная система: В описании продукта не указана операционная система. Это снижает оценку.\\n5. Гарантийный срок: В описании продукта не указан гарантийный срок. Это снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не основные параметры.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (392, 31503827, 'Гидрооқшаулаушы мастика', 'Тауардың, жұмыстың, қызметтің сипаттамасы', 'Тауарлардың, жұмыстардың және қызметтердің қосымша сипаттамасы (сипаттауы) (мемлекеттік тілде)', 'https://satypalu.gov.kz/kz/registry/show_plan/53676027/2714856', 0, 'бірлік', 'тенге', NULL, 0, '"\"1. Рукав гидравлический, высокого давления (РВД под ключ 32) (L=1400мм, М27х1,5): Не указано в описании продукта.\\n2. ГОСТ 6286-2017: Не указано в описании продукта.\\n3. Год выпуска – Не ранее 2023 года: Не указано в описании продукта.\\n4. Гарантийный срок (в месяцах) - 12 месяцев с момента поставки товара: Не указано в описании продукта.\\n5. Товар должен быть новым, не бывшим в эксплуатации, поставляется в заводской упаковке: Не указано в описании продукта.\\n6. На заводской упаковке должно быть указано наименование товара, технические характеристики товара, завод изготовитель: Не указано в описании продукта.\\n7. Поставщик обязуется осуществлять разгрузку товаров в пункте назначения за счет собственных сил и средств: Не указано в описании продукта.\\n8. Поставщик обязан согласовать с Заказчиком дату и время поставки товаров за 3 (три) рабочих дня до отгрузки товаров: Не указано в описании продукта.\\n9. По техническим вопросам обращаться к начальнику УТТиМ Нурсеитову Г.М. тел. + 7(705)-751-3109, механику УТТиМ Плаксину Н.В.тел. +7(777)-354-6706: Не указано в описании продукта.\""');
