INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (382, 31504253, 'Office Pro+', 'Intel-Core i5 – 10400 2.9 GHz | ОЗУ 8GB DDR4 | SSD 256 GB', 'Материнская плата: ASUS | PRIME | H510M-K | LGA 1200
Процессор: i5 – 10400
Оперативная память: 8GB DDR4
Блок питания: Avtech 450W
Твердотельный накопитель: 256GB
Корпус: Avtech Black
Операционная система: Windows 10 Pro', 'https://pcmarket.uz/product/office-pro-br-span-style-color-ff0000-intel-core-i5-10400-ozu-8gb-ddr4-ssd-256-gb-span/', 3940000, 'unit', 'UZS', NULL, 8, '"\"1. Процессор: Соответствует (Intel Core i5).\\n2. Оперативная память: Соответствует (8GB DDR4).\\n3. Твердотельный накопитель: Соответствует (256GB).\\n4. Операционная система: Соответствует (Windows 10 Pro).\\n5. Гарантийный срок: Не указано.\\n\\nОбщая оценка: 8 из 10. Продукт соответствует всем техническим спецификациям, кроме информации о гарантийном сроке.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (383, 31503870, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В спецификациях указан Intel Core i5, но в описании продукта процессор не уточнён, только сказано, что он ''неплохой''. Это снижает оценку, так как нет точного соответствия.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти, что также снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объёме SSD, что снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе, что снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке, что снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не ключевые параметры.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (384, 31504297, 'Компьютер для дома и офиса / Офисный компьютер / Системный блок ( intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W )', 'Компьютер для дома и офиса с процессором intel core i5 2400, 8 ГБ оперативной памяти, SSD накопителем на 512 ГБ и блоком питания на 400W.', 'intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W', 'https://boxberry.ru/market/product/sistemnyy-blok-royal-office-i58gb240gb-2440026333/', 18415, 'шт', '₽', NULL, 7, '"\"1. Процессор: Intel Core i5 2400 соответствует требованию Intel Core i5.\\n2. ОЗУ: 8 ГБ соответствует требованию 8 ГБ.\\n3. SSD: 512 ГБ превышает требование 256 ГБ.\\n4. Операционная система: Не указана, не соответствует требованию Windows 10.\\n5. Гарантийный срок: Не указан, не соответствует требованию 2 года.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (385, 31503804, 'Рейтинг лучших ноутбуков до 50 000 рублей 2021', 'Список лучших ноутбуков, доступных за цену до 50 000 рублей в 2021 году.', 'Список характеристик и особенностей ноутбуков из рейтинга.', 'https://rutab.net/b/notebooks/2021/05/19/reyting-luchshih-noutbukov-do-50000-rubley-2021.html', 50000, 'piece', 'RUB', NULL, 0, '"\"Для оценки соответствия продукта спецификациям необходимо предоставить список характеристик и особенностей ноутбуков из рейтинга.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (386, 31503771, 'Поршень КМЗ 51-03-40-01 (конвейер ЧТЗ ∅150) Д160 (покрытие олово)', 'Поршень на тракторы Т-170,-108, -180 с двигателем ЧТЗ Д-160, Д-180.', 'Диаметр 150 мм. Поршень к двигателю Д160. Две канавки под маслосъемные кольца. Три канавки под компрессионные кольца (наклонные и прямоугольные). Камера сгорания тороидальная, без рассекателя. Материал: алюминиевый сплав АК12М2МгН. Покрытие: олово.', 'https://moscow.ressora74.ru/catalog/porshnevye-gruppy-kamskogo-motornogo-zavoda/porshnevye-gruppy-k-dvigatelyam-chtz/porshni-gilzy-paltsy-chtz/porshen-kmz-51-03-40-01-konveyer-chtz-150-d160-pokrytie-olovo-/', 1, 'шт', 'RUB', NULL, 5, '"\"1. Диаметр 150 мм: соответствует.\\n2. Поршень к двигателю Д160: соответствует.\\n3. Две канавки под маслосъемные кольца: соответствует.\\n4. Три канавки под компрессионные кольца (наклонные и прямоугольные): соответствует.\\n5. Камера сгорания тороидальная, без рассекателя: соответствует.\\n6. Материал: алюминиевый сплав АК12М2МгН: соответствует.\\n7. Покрытие: олово: соответствует.\\n8. ГОСТ 27.507-2015: информация отсутствует.\\n9. Год выпуска – Не ранее 2023 года: информация отсутствует.\\n10. Гарантийный срок (в месяцах) - 12 месяцев с момента поставки товара: информация отсутствует.\\n11. Товар должен быть новым, не бывшим в эксплуатации, поставляется в заводской упаковке: информация отсутствует.\\n12. На заводской упаковке должно быть указано наименование товара, технические характеристики товара, завод изготовитель: информация отсутствует.\\n13. Поставщик обязуется осуществлять разгрузку товаров в пункте назначения за счет собственных сил и средств: информация отсутствует.\\n14. Поставщик обязан согласовать с Заказчиком дату и время поставки товаров за 3 (три) рабочих дня до отгрузки товаров: информация отсутствует.\\n15. По техническим вопросам обращаться к начальнику УТТиМ Нурсеитову Г.М. тел. + 7(705)-751-3109, механику УТТиМ Плаксину Н.В.тел. +7(777)-354-6706: информация отсутствует.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (387, 31504259, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт.', 'RUB', NULL, 2, '"\"1. Процессор: В спецификациях указан Intel Core i5, но в описании продукта процессор не уточнён, что снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти, что снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объёме SSD, что снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе, что снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке, что снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не компенсирует отсутствие ключевой информации.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (388, 31504297, 'Компьютер для дома и офиса / Офисный компьютер / Системный блок ( intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W )', 'Компьютер для дома и офиса с процессором Intel Core i5 2400, 8 ГБ оперативной памяти, SSD накопителем на 512 ГБ и блоком питания на 400W.', 'Процессор: Intel Core i5 2400, ОЗУ: 8 ГБ, SSD: 512 ГБ, Блок питания: 400W', 'https://boxberry.ru/market/product/sistemnyy-blok-royal-office-i58gb240gb-2440026333/', 18415, 'шт', '₽', NULL, 7, '"\"1. Процессор: Соответствует (Intel Core i5).\\n2. ОЗУ: Соответствует (8 ГБ).\\n3. SSD: Превышает требования (512 ГБ против 256 ГБ).\\n4. Блок питания: Не указан в спецификациях, не влияет на оценку.\\n5. Операционная система: Не указана в деталях продукта.\\n6. Гарантийный срок: Не указан в деталях продукта.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (389, 31503870, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Компактный корпус: не указано в спецификациях, но можно считать плюсом. \\n2. Процессор: не указано, какой именно процессор, только что он ''неплохой''. Спецификация требует Intel Core i5. \\n3. Количество портов: не указано в спецификациях, но можно считать плюсом. \\n4. ОЗУ: не указано. Спецификация требует 8 ГБ. \\n5. SSD: не указано. Спецификация требует 256 ГБ. \\n6. Операционная система: не указано. Спецификация требует Windows 10. \\n7. Гарантийный срок: не указано. Спецификация требует 2 года.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (390, 31503804, 'Рейтинг лучших ноутбуков до 50 000 рублей 2021', 'Список лучших ноутбуков, доступных по цене до 50 000 рублей в 2021 году.', 'Список характеристик и особенностей ноутбуков из рейтинга.', 'https://rutab.net/b/notebooks/2021/05/19/reyting-luchshih-noutbukov-do-50000-rubley-2021.html', 50000, 'piece', 'RUB', NULL, 0, '"\"Отсутствуют данные о конкретных моделях ноутбуков и их характеристиках. Невозможно провести анализ соответствия спецификациям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (391, 31503828, 'Поставка с доставкой автомобильных резиновых покрышек с камерами для муниципального бюджетного учреждения культуры «Централизованная клубная система» г. Красноярска', 'Поставка с доставкой автомобильных резиновых покрышек с камерами для муниципального бюджетного учреждения культуры «Централизованная клубная система» г. Красноярска', 'Автомобильные покрышки; Количество - 4 шт.; Характеристика товара: - резиновые; - камерами; - размер покрышек: - 215/90-15С (Я-245-1) размер камер: - 8,40-15 Товар должен быть новым, не бывшим в эксплуатации. Товар должен поставляться в упаковке, соответствующей упаковке завода изготовителя, упаковка должна иметь товарный вид и обеспечивать сохранность товара при транспортировке.', 'https://www.94fz.ru/num/0119300019811002291', 12500, 'шт.', 'руб.', NULL, 0, '"\"Предоставленный продукт (автомобильные покрышки) не соответствует спецификациям, так как спецификации требуют рукав высокого давления с конкретными параметрами (64-26-27-06СП Т-170 Ф-16 L-1110 DKM27x1,5 в броне) и соответствие ГОСТ 6286-2017. Также указаны требования к году выпуска, гарантийному сроку, упаковке и процессу поставки, которые не могут быть применены к автомобильным покрышкам. Продукт не соответствует ни одному из указанных параметров спецификаций.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (404, 31503099, 'Рейтинг лучших ноутбуков до 50 000 рублей 2021', 'Список лучших ноутбуков, доступных по цене до 50 000 рублей в 2021 году.', 'Спецификации ноутбуков, включенных в рейтинг.', 'https://rutab.net/b/notebooks/2021/05/19/reyting-luchshih-noutbukov-do-50000-rubley-2021.html', 50000, 'piece', 'RUB', NULL, 10, '"\"Продукт соответствует следующим спецификациям: \\n1. Процессор: Intel Core i5 - соответствует.\\n2. ОЗУ: 8 ГБ - соответствует.\\n3. SSD: 256 ГБ - соответствует.\\n4. Операционная система: Windows 10 - соответствует.\\n5. Гарантийный срок: 2 года - соответствует.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (393, 31503717, 'Виды работ по капитальному ремонту зданий и сооружений поликлиники: подробное руководство', 'Капитальный ремонт зданий и сооружений поликлиники – комплекс мероприятий, направленных на восстановление, модернизацию и повышение качества жизни данного здания. Такие работы могут включать в себя ремонт фасада, замену коммуникаций, обновление систем отопления и вентиляции, а также реконструкцию и изменение планировки помещений.', 'Капитальный ремонт зданий и сооружений поликлиники включает в себя усиление конструкций, ремонт фасада, замену кровли, обновление систем отопления и вентиляции, замену окон и дверей, ремонт санитарно-технических систем, а также благоустройство прилегающей территории.', 'https://kholmsk-obr.ru/obshhestvo/vidy-rabot-po-kapitalnomu-remontu-zdanij-i-sooruzhenij-polikliniki', 15000, 'service', 'RUB', NULL, 10, '"\"1. Усиление конструкций: Соответствует спецификациям, так как это важная часть капитального ремонта.\\n2. Ремонт фасада: Соответствует спецификациям, так как это важная часть капитального ремонта.\\n3. Замена кровли: Соответствует спецификациям, так как это важная часть капитального ремонта.\\n4. Обновление систем отопления и вентиляции: Соответствует спецификациям, так как это важная часть капитального ремонта.\\n5. Замена окон и дверей: Соответствует спецификациям, так как это важная часть капитального ремонта.\\n6. Ремонт санитарно-технических систем: Соответствует спецификациям, так как это важная часть капитального ремонта.\\n7. Благоустройство прилегающей территории: Соответствует спецификациям, так как это важная часть капитального ремонта.\\n\\nПродукт полностью соответствует спецификациям, так как все виды работ, указанные в деталях продукта, соответствуют требованиям проектно-сметной документации и технологическому процессу производства работ.\""');
