INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (441, 31500997, 'Колбаса Идель мусульманская халяль п/к катв вес Россия', 'Мусульманская колбаса Идель производится по ГОСТу и ГОСТу России. Состав: говядина, баранина, вода питьевая, соль, пряности, сахар, стабилизатор Е450, антиокислитель Е300, консервант Е250. Пищевая ценность на 100 г продукта: белки - 12 г, жиры - 25 г. Энергетическая ценность: 280 ккал.', 'Вес: указан на упаковке', 'https://lenta.com/product/kolbasa-idel-musulmanskaya-halyal-pk-katv-ves-rossiya-696127/', 349.9, 'kg', 'RUB', NULL, 3, '"\"Продукт соответствует спецификации по весу, так как вес указан на упаковке. Однако, нет информации о том, что это колбаса полукопченая 1 категории, говяжья и без добавок свинины (мусульманская).\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (442, 31500613, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Компактный корпус: не указано в спецификациях, но можно считать нейтральным фактором.\\n2. Процессор: не указано, какой именно процессор, но упомянуто, что он неплохой. Неясно, соответствует ли он Intel Core i5.\\n3. ОЗУ: не указано.\\n4. SSD: не указано.\\n5. Операционная система: не указано.\\n6. Гарантийный срок: не указано.\\n\\nИтог: Продукт не предоставляет достаточно информации для оценки соответствия спецификациям. Основные параметры, такие как процессор, ОЗУ, SSD, операционная система и гарантийный срок, не указаны.\""');
