INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (444, 31353114, 'Встраиваемый OPS компьютер Interwrite Intel i5-8300H/8G/256G SSD', 'OPS-компьютер Interwrite Intel i5-8300H/8G/256G SSD предназначен для встраивания в интерактивные панели и обеспечивает высокую производительность и надежность.', 'Процессор: Intel Core i5-8300H
Оперативная память: 8 ГБ
Жесткий диск: 256 ГБ SSD', 'https://school-room.ru/shop/interaktivnoe-oborudovanie/aksessuary-dlya-interaktivnyh-panelej/ops-kompyutery/vstraivaemyj-ops-kompyuter-interwrite-intel-i5-8300h-8g-256g-ssd/', 0, 'item', 'RUB', NULL, 8, '"\"Процессор соответствует спецификации (Intel Core i5-8300H). Оперативная память соответствует спецификации (8 ГБ). Жесткий диск соответствует спецификации (256 ГБ SSD). Отсутствует информация об операционной системе и гарантийном сроке.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (445, 31271288, 'Настольный компьютер с процессором Intel Core i5 и оперативной памятью 8 ГБ с объемом накопителей SSD 256 ГБ с операционной системой Windows 10 Pro', 'Настольный компьютер с процессором Intel Core i5 и оперативной памятью 8 ГБ. Объем накопителей SSD 256 ГБ. Операционная система Windows 10 Pro.', 'Процессор: Intel Core i5, Оперативная память: 8 ГБ, Накопители: SSD 256 ГБ, Операционная система: Windows 10 Pro', 'https://market.yandex.ru/search?text=%D0%9D%D0%B0%D1%81%D1%82%D0%BE%D0%BB%D1%8C%D0%BD%D1%8B%D0%B5%20%D0%BA%D0%BE%D0%BC%D0%BF%D1%8C%D1%8E%D1%82%D0%B5%D1%80%D1%8B%20%D1%81%20%D0%BF%D1%80%D0%BE%D1%86%D0%B5%D1%81%D1%81%D0%BE%D1%80%D0%BE%D0%BC%20Intel%20Core%20i5%20%D0%B8%20%D0%BE%D0%BF%D0%B5%D1%80%D0%B0%D1%82%D0%B8%D0%B2%D0%BD%D0%BE%D0%B9%20%D0%BF%D0%B0%D0%BC%D1%8F%D1%82%D1%8C%D1%8E%208%20%D0%93%D0%91%20%D1%81%20%D0%BE%D0%B1%D1%89%D0%B8%D0%BC%20%D0%BE%D0%B1%D1%8A%D0%B5%D0%BC%D0%BE%D0%BC%20%D0%BD%D0%B0%D0%BA%D0%BE%D0%BF%D0%B8%D1%82%D0%B5%D0%BB%D0%B5%D0%B9%20SSD%20256%20%D0%93%D0%91%20%D1%81%20%D0%BE%D0%BF%D0%B5%D1%80%D0%B0%D1%86%D0%B8%D0%BE%D0%BD%D0%BD%D0%BE%D0%B9%20%D1%81%D0%B8%D1%81%D1%82%D0%B5%D0%BC%D0%BE%D0%B9%20Windows%2010%20Pro', 50000, 'piece', 'RUB', NULL, 8, '"\"1. Процессор: Соответствует (Intel Core i5).\\n2. Оперативная память: Соответствует (8 ГБ).\\n3. Накопители: Соответствует (SSD 256 ГБ).\\n4. Операционная система: Частично соответствует (Windows 10 Pro вместо Windows 10).\\n5. Гарантийный срок: Отсутствует информация.\\n\\nИтог: Продукт в целом соответствует спецификациям, за исключением операционной системы и отсутствия информации о гарантийном сроке.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (446, 31496723, 'Ботинки рабоче летние BESTORG', 'Универсальная модель для работы в производственных помещениях различных отраслей промышленности, в период летнего и демисезонного периода. Верхняя часть выполнена из натуральной кожи. Мужские ботинки, полностью выполненные из плотной натуральной кожи с защитными пропитками (ВО, МБС). Широкая колодка, высокий подъем. С светоотражающий. Гигроскопичная, стойкая к истиранию подкладка. Износостойкая двухслойная ПУ подошва. Внешний «ходовой» слой из полиуретана (ПУ) обладает стойкостью к агрессивным веществам (МБС, КЩС — 20%), механическим воздействиям. Специальное рифление на подошве препятствует скольжению. Металлический подносок ударной прочностью 200 Дж и металлический стелька. Устойчивая к проколам стелька. ГОСТ 12.4.072-79. Материал верха: натуральная кожа. Подошва: ПУ. Метод крепления: литье. Цвет: черный. Размер: 36 — 46. Высота: 14.5см', 'Материал верха: натуральная кожа. Подошва: ПУ. Метод крепления: литье. Цвет: черный. Размер: 36 — 46. Высота: 14.5см', 'https://specroba.kz/p108197768-botinki-rabochie-letnie.html', 0, '', '', NULL, 4, '"\"1. Материал верха: соответствует (натуральная кожа).\\n2. Подошва: соответствует (ПУ).\\n3. Метод крепления: соответствует (литье).\\n4. Цвет: соответствует (черный).\\n5. Размер: частично соответствует (указан диапазон 36-46, но не указаны конкретные размеры, как в спецификации).\\n6. Высота: не указана в спецификациях.\\n7. Комбинированный материал: не соответствует (указан только натуральная кожа).\\n8. Неутепленные: не указано.\\n9. Широкая колодка, высокий подъем: не указано.\\n10. Гигроскопичная, стойкая к истиранию подкладка: не указано.\\n11. Износостойкая двухслойная ПУ подошва: не указано.\\n12. Внешний слой подошвы стойкий к агрессивным веществам и механическим воздействиям: не указано.\\n13. Специальное рифление на подошве: не указано.\\n14. Металлический подносок ударной прочностью 200 Дж: не указано.\\n15. Металлическая стелька: не указано.\\n16. Устойчивая к проколам стелька: не указано.\\n17. ГОСТ 12.4.072-79: не указано.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (447, 31473372, 'Труба полипропиленовая 50 мм PPR PN25, SDR6 (50x8.3), DN32, армированная стекловолокном', 'Труба полипропиленовая 50 мм PN25 армированная стекловолокном предназначена для использования в системах водоснабжения и отопления. Имеет диаметр 32 мм и толщину стенки 8.3 мм. Рабочее давление 25 атмосфер. Длина трубы - 4 метра.', 'Диаметр: 50 мм, Толщина стенки: 8.3 мм, Диаметр наружный: 50 мм, Диаметр внутренний: 33.4 мм, Длина: 4 м', 'https://mnogo-tepla.ru/product/truba-polipropilenovaya-50-mm-pn25-armirovannaya-steklovoloknom/', 450, 'шт', 'RUB', NULL, 2, '"\"Продукт не соответствует спецификациям по нескольким параметрам. Во-первых, наружный диаметр продукта составляет 50 мм, тогда как спецификация требует 57 мм. Во-вторых, внутренний диаметр продукта составляет 33.4 мм, тогда как спецификация требует 50 мм. Эти два параметра являются критическими для соответствия продукта спецификациям.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (448, 31473275, 'Женский костюм с коротким рукавом', 'Женский костюм с коротким рукавом - стильный и удобный вариант для повседневной носки. Изготовлен из высококачественных материалов.', 'Материал: хлопок, полиэстер; Рукав: короткий; Тип застежки: молния; Цвет: разноцветный.', 'https://aliexpress.ru/popular/%D0%B6%D0%B5%D0%BD%D1%81%D0%BA%D0%B8%D0%B9-%D0%BA%D0%BE%D1%81%D1%82%D1%8E%D0%BC-%D1%81-%D0%BA%D0%BE%D1%80%D0%BE%D1%82%D0%BA%D0%B8%D0%BC-%D1%80%D1%83%D0%BA%D0%B0%D0%B2%D0%BE%D0%BC.html', 1500, 'шт.', 'RUB', NULL, 6, '"\"1. Материал: хлопок, полиэстер - соответствует спецификации.\\n2. Рукав: короткий - соответствует спецификации.\\n3. Тип застежки: молния - соответствует спецификации.\\n4. Цвет: разноцветный - не соответствует спецификации (требуется сине-зеленый цвет).\\n5. Костюм состоит из блузки и юбки - информация отсутствует.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (449, 31459909, 'Полог брезентовый огнеупорный 3 х 4 тент универсальный с люверсами для туризма защитный полог', 'Универсальный брезентовый тент с огнеупорными свойствами и люверсами, предназначенный для использования в туризме. Обеспечивает надежную защиту от внешних факторов.', 'Размер: 3 х 4 метра', 'https://ozon.kz/product/polog-brezentovyy-ogneupornyy-3-h-4-tent-universalnyy-s-lyuversami-dlya-turizma-zashchitnyy-polog-894484958/', 894484958, 'шт.', 'KZT', NULL, 4, '"\"1. Размер: Соответствует (3 х 4 метра).\\n2. Материал: Не указано, из какого материала сделан тент. Спецификация требует брезентовую ткань.\\n3. Рабочая температура: Не указана. Спецификация требует от -30 до +90 С.\\n4. Стойкость к прожиганию: Не указана. Спецификация требует 30-40 сек.\\n5. Состояние: Соответствует (новое).\\n\\nИтог: Продукт частично соответствует спецификациям. Отсутствует информация о материале, рабочей температуре и стойкости к прожиганию.\""');
