page=103', 0, '', '', NULL, 0, '"\"Предоставленные детали продукта не соответствуют технической спецификации, так как они касаются тендеров на промышленное оборудование, а не на услуги по техническому обслуживанию и ремонту медицинского оборудования. В информации о продукте отсутствуют данные о медицинском оборудовании и услугах по его обслуживанию и ремонту.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (451, 31511734, 'AGNESINA GRAPHITE POLISHED 600*1200 керамогранит полированный', 'Назначение: универсальная
Дизайн: Для ванной, Для кухни, Коридор, Коммерческие помещения', 'Длина: 1200 мм
Ширина: 600 мм', 'https://topsa-market.kz/product/agnesina-graphite-polished-6001200-%D0%BA%D0%B5%D1%80%D0%B0%D0%BC%D0%BE%D0%B3%D1%80%D0%B0%D0%BD%D0%B8%D1%82-%D0%BF%D0%BE%D0%BB%D0%B8%D1%80%D0%BE%D0%B2%D0%B0%D0%BD%D0%BD%D1%8B%D0%B9/', 14490, 'шт.', '₸', NULL, 2, '"\"Продукт соответствует следующим спецификациям: \\n- Длина: 1200 мм (соответствует)\\n- Ширина: 600 мм (соответствует)\\n\\nОтсутствует информация о следующих спецификациях: \\n- Вид товара\\n- Назначение\\n- Цвет\\n- Дизайн\\n- Поверхность\\n- Тип плитки\\n- Рельеф\\n- Рисунок\\n- Ректификат\\n- Высота\\n- Вес\\n\\nТаким образом, продукт соответствует только двум из требуемых спецификаций.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (452, 31511842, 'Урна для мусора с качающейся крышкой DDSTYLE, 23.5х19х36 см (10 л.) БЕЛЫЙ', 'Информация о цене и наличии товара представлена для размещения онлайн-заказов на текущем сайте и является действительной на текущую дату. Цены и наличие товара, указанные на сайте, могут отличаться от цен и наличия в гипермаркетах. При покупке товара непосредственно в гипермаркете, пожалуйста, уточняйте стоимость и наличие товаров в конкретном гипермаркете. Все цены указаны в рублях, с учетом НДС. Все характеристики и изображения товаров предоставлены производителями. Производитель оставляет за собой право изменить характеристики/внешний вид товара без предварительного уведомления, в связи с чем на дату приобретения товара они могут отличаться от представленных на настоящем сайте. Возможны изменения и текстовые опечатки. Проверяйте наличие необходимых характеристик и комплектации в момент приобретения товара. При расчете учитывается необходимое целое количество упаковок для покрытия указанной площади. При расчете площади учитывается наибольшая площадь, покрываемая целым количеством упаковок.', 'Все цены указаны в рублях, с учетом НДС. Все характеристики и изображения товаров предоставлены производителями. Производитель оставляет за собой право изменить характеристики/внешний вид товара без предварительного уведомления, в связи с чем на дату приобретения товара они могут отличаться от представленных на настоящем сайте. Возможны изменения и текстовые опечатки. Проверяйте наличие необходимых характеристик и комплектации в момент приобретения товара. При расчете учитывается необходимое целое количество упаковок для покрытия указанной площади. При расчете площади учитывается наибольшая площадь, покрываемая целым количеством упаковок.', 'https://obi.ru/products/urna-dlja-musora-s-kachajuschejsja-kryshkoj-ddstyle-23-5h19h36-sm-10-l-belyj-4721304', 399, 'шт.', 'руб.', NULL, 2, '"\"Продукт не соответствует спецификациям по следующим параметрам: 1. Объем урны не указан. 2. Материал урны не указан. 3. Форма урны не указана. 4. Длина, ширина и высота урны не указаны. Продукт соответствует спецификациям по следующим параметрам: 1. Урна для мусора с качающейся крышкой.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (453, 31511640, 'Парта/стол', 'офисный, каркас металлический, обивка из ткани, мягкий', 'Размер авансового платежа: 512 000,00 KZT', 'https://eep.mitwork.kz/ru/publics/lot/250802', 512000, 'шт', 'KZT', NULL, 0, '"\"Предоставленные детали продукта не соответствуют спецификациям. В спецификациях указаны характеристики стула (материал, цвет, основа), а в деталях продукта указана сумма авансового платежа, что не имеет отношения к характеристикам стула.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (454, 31511758, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В спецификациях указан Intel Core i5, но в описании продукта процессор не уточнён. Это снижает оценку.\\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. Это снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объёме SSD. Это снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе. Это снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. Это снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не компенсирует отсутствие ключевой информации.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (456, 31511107, 'Броня-360 СК белый-черный + KAMISU T 9.9 BMS (комплект лодка + мотор)', 'Вы можете купить Броня-360 СК белый-черный + KAMISU T 9.9 BMS (комплект лодка + мотор) в интернет-магазине Лодки ПВХ и Резиновые по доступной цене 145 680 р.', 'Регистрация в ГИМС: Не требуется, Вместительность: 4 чел., Тип лодки: Моторно-гребная, Тип дна: Жесткая слань с килем, Усиление баллонов: Да, Грузоподъемность: 600 кг, Длина лодки: 360 см, Ширина: 165 см, Диаметр баллона: 45 см, Высота транца: 381 см, Ширина кокпита: 75 см, Вес комплекта: 50 кг, Крепление банок: Передвежные, Плотность ткани: 900 гр. на м2, Толщина слани: 9 мм, Толщина транца: 18 мм, Кол-во надувных отсеков: 3+киль, Макс. мощность мотора: 15 л.с., Габариты упаковки лодки: 127х67х25 см, Габариты упаковки слань: 112х62х10 см, Комплектация: Лодка, слань-книжка, 2 стрингера, 2 сиденья, 2 весла разборных, ножной насос 5 литров, рем. набор, сумка для лодки, сумка для слани, паспорт изделия, Максимальное количество оборотов мотора: 4500~5500 об. мин, Рабочий объем: 246 куб.см., Высота транца мотора: 381 мм, Объем топливного бака: 24 л (внешний), Передаточное число редуктора: 27/13, Тип мотора: Бензиновый, Завод: Pioneer, Бренд: Kamisu, Система управления: Румпель, Переключение передач: F/N/R, Система зажигания: CDI, Вес мотора: 41 кг, Количество цилиндров: 2, Охлаждение: Водяное, Мощность: 9,9 л.с.', 'https://lodki-lodki.ru/product/bronya-360-sk-belyy-chernyy-kamisu-t-9-9-bms-komplekt-lodka-motor', 145680, 'set', 'RUB', NULL, 10, '"\"Продукт полностью соответствует предоставленным спецификациям. Вместительность – 4 человека, тип лодки – моторно-гребная, тип дна – жесткая слань с килем, усиление баллонов – да, грузоподъемность – 600 кг, длина лодки – 360 см, ширина – 165 см, диаметр баллона – 45 см, высота транца – 381 см, ширина кокпита – 75 см, вес комплекта – 50 кг, крепление банок – передвижные, плотность ткани – 900 гр. на м2, толщина слани – 9 мм, толщина транца – 18 мм, количество надувных отсеков – 3+киль, максимальная мощность мотора – 15 л.с., габариты упаковки лодки – 127х67х25 см, габариты упаковки слани – 112х62х10 см, комплектация – лодка, слань-книжка, 2 стрингера, 2 сиденья, 2 весла разборных, ножной насос 5 литров, рем. набор, сумка для лодки, сумка для слани, паспорт изделия.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (457, 31511196, 'Стул Классик 5 (Хром) Рустика Лайм', 'Современный и удобный стул выглядит стильным и легким. Это ощущение создается за счет интересной конструкции спинки, созданной из металлических хромированных элементов, расположенных веером. Приятный цвет обивки рустика лайм привносит с собой нотки свежести и интересно смотрится в интерьере. Конструкция стула изготовлена из металла. Материал имеет антикоррозийное покрытие, износостойкий, прочный и надежный в использовании. Ножки, слегка разведенные в стороны, для жесткости соединены вогнутыми дугообразными деталями. Снизу имеются накладки для защиты напольного покрытия. Сиденье обито кожзаменителем, наполнитель – поролон. Вы можете заказать кухонный стул "Классик 5" от производителя СВ Мебель/Россия по доступной цене в интернет-магазине Евромебель.', 'Материал: металл, обивка: кожзаменитель, наполнитель: поролон', 'https://e-commerce-ala.kz/p116944608-stul-klassik-hrom.html', 0, 'шт', 'KZT', NULL, 3, '"\"1. Материал: металл - соответствует спецификации.\\n2. Обивка: кожзаменитель - соответствует спецификации.\\n3. Наполнитель: поролон - соответствует спецификации.\\n4. Каркас: металлический, цвет серебро - соответствует спецификации.\\n5. Антикоррозийное покрытие - не указано, возможно несоответствие.\\n6. Ножки: четыре, круглой формы, слегка расширяющиеся от царги к полу - не указано, возможно несоответствие.\\n7. Хромированная спинка, продолжение задних ножек - не указано, возможно несоответствие.\\n8. Тонкие трубчатые рельефные планки на спинке - не указано, возможно несоответствие.\\n9. Изогнутая форма спинки - не указано, возможно несоответствие.\\n10. Полужесткое сиденье трапециевидной формы - не указано, возможно несоответствие.\\n11. Веерная конструкция спинки - не указано, возможно несоответствие.\\n12. Ножки соединены вогнутыми дугообразными деталями - не указано, возможно несоответствие.\\n13. Накладки для защиты напольного покрытия - не указано, возможно несоответствие.\\n14. Цвет светло-бежевый - не указано, возможно несоответствие.\\n15. Размеры (ширина, высота, глубина, высота от пола до сиденья) - не указаны, возможно несоответствие.\\n16. Согласование деталей с Заказчиком - не указано, возможно несоответствие.\\n17. Предоставление документов подтверждающих соответствие - не указано, возможно несоответствие.\\n18. Сборка мебели в помещении Заказчика - не указано, возможно несоответствие.\\n19. Включение всех затрат в стоимость товара - не указано, возможно несоответствие.\\n20. Гарантийный срок 12 месяцев - не указано, возможно несоответствие.\\n21. Соответствие ГОСТ 12029-93 (ИСО 7173-89) - не указано, возможно несоответствие.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (458, 31510221, 'Kia Sorento 2024', 'Новый Kia Sorento 2024г. Вы будете первым владельцем🙌', 'Комплектация: Luxe. Автомобиль от Официального дилера! Меню все на русском языке! Привезем для вас любую другую комплектацию/цвет!', 'https://auto.drom.ru/omsk/kia/sorento/208982155.html', 6240000, 'шт', 'руб', NULL, 3, '"\"1. Комплектация: Luxe - соответствует требованиям. 2. Автомобиль от Официального дилера - соответствует требованиям. 3. Меню на русском языке - соответствует требованиям. 4. Возможность выбора другой комплектации/цвета - соответствует требованиям. 5. Соответствие СТ РК ГОСТ Р 51709-2004 - не указано, снижаем баллы. 6. Новый, неиспользованный автомобиль - не указано, снижаем баллы. 7. Год выпуска не ранее 2023 - не указано, снижаем баллы. 8. Гарантийный срок 60 месяцев - не указано, снижаем баллы. 9. Расположение двигателя: переднее, поперечное - не указано, снижаем баллы. 10. Количество мест для сидения: 5 - не указано, снижаем баллы. 11. Длина×Ширина×Высота, не менее мм 4810 / 1900 / 1695 - не указано, снижаем баллы. 12. Колесная база, не менее мм 2815 - не указано, снижаем баллы. 13. Рабочий объем двигателя, не менее см3 2497 - не указано, снижаем баллы. 14. Тип привода 4 WD (полный) - не указано, снижаем баллы. 15. Тип коробки передач: автомат - не указано, снижаем баллы. 16. Максимальная мощность, л.с.: не менее 179 - не указано, снижаем баллы. 17. Цвет кузова: По соглашению с заказчиком - соответствует требованиям. 18. Подогрев передних сидений - не указано, снижаем баллы. 19. Подогрев задних сидений - не указано, снижаем баллы. 20. Подогрев рулевого колеса - не указано, снижаем баллы. 21. Боковые зеркала заднего вида с электроприводом и подогревом - не указано, снижаем баллы. 22. Воздуховоды для второго ряда сидений - не указано, снижаем баллы. 23. Индикатор низкого уровня омывающей жидкости - не указано, снижаем баллы. 24. Электропривод складывания зеркал заднего вида - не указано, снижаем баллы. 25. Рейлинги на крыше - не указано, снижаем баллы. 26. Легкосплавные диски 18\\\" с шинами 235/60R - не указано, снижаем баллы. 27. Рефлекторные трехячеечные светодиодные (LED) фары - не указано, снижаем баллы. 28. Светодиодные (LED) противотуманные фары - не указано, снижаем баллы. 29. Глубокая тонировка стекол задних дверей и стекла пятой двери - не указано, снижаем баллы. 30. Сиденья с отделкой кожей - не указано, снижаем баллы. 31. Элементы передней панели со вставками «под дерево» - не указано, снижаем баллы. 32. Подрулевые лепестки переключения передач - не указано, снижаем баллы. 33. Цифровая приборная панель приборов с дисплеем 4\\\" - не указано, снижаем баллы. 34. Передние и задние датчики парковки - не указано, снижаем баллы. 35. Полноразмерное легкосплавное запасное колесо - не указано, снижаем баллы. 36. Электрический Child Lock - не указано, снижаем баллы. 37. Электрический стояночный тормоз (EPB) c функцией Autohold - не указано, снижаем баллы. 38. Электронный селектор КПП - не указано, снижаем баллы. 39. Передние и задние стеклоподъёмники с функцией Auto - не указано, снижаем баллы. 40. Электрический привод багажника - не указано, снижаем баллы. 41. Система бесключевого доступа Smartkey и запуск двигателя кнопкой - не указано, снижаем баллы. 42. Мультимедиа система 12,3\\\" с поддержкой Apple Carplay / Android Auto - не указано, снижаем баллы. 43. Аудиосистема с 6 динамиками - не указано, снижаем баллы. 44. Электрохромное зеркало заднего вида (ECM) - не указано, снижаем баллы. 45. 10 электрорегулировок сиденья водителя (включая 2 направления поясницы) - не указано, снижаем баллы. 46. Дистанционное складывание сидений 2-го ряда со стороны багажника (для автомобилей с 6- и 7-местным салоном) - не указано, снижаем баллы. 47. Складывание 50/50 сидений 3-го ряда (7-местным салоном) - не указано, снижаем баллы. 48. Гарантия на крупные узлы и агрегаты 5 лет или 100 000 км - не указано, снижаем баллы.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (459, 31509942, 'Компьютер Lenovo ThinkCentre M80t, Intel Core i5 10500, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 630, DVD-RW, Windows 10 Professional, черный [11cs0000uk]', 'Компьютер Lenovo ThinkCentre M80t с процессором Intel Core i5 10500, оперативной памятью DDR4 8ГБ, накопителем 256ГБ(SSD), графикой Intel UHD Graphics 630, оптическим приводом DVD-RW, предустановленной операционной системой Windows 10 Professional. Цвет: черный.', 'Intel Core i5 10500, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 630, DVD-RW, Windows 10 Professional, черный', 'https://www.citilink.ru/product/kompyuter-lenovo-thinkcentre-m80t-intel-core-i5-10500-ddr4-8gb-256gb-s-1978508/', 0, 'шт.', 'RUB', NULL, 8, '"\"1. Процессор: Соответствует (Intel Core i5 10500).\\n2. ОЗУ: Соответствует (8 ГБ DDR4).\\n3. SSD: Соответствует (256 ГБ).\\n4. Операционная система: Соответствует (Windows 10 Professional).\\n5. Гарантийный срок: Не указан.\\n6. Дополнительно: В спецификациях не указаны графика, оптический привод и цвет, но они присутствуют в описании продукта.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (460, 31509798, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Компактный корпус: не указано в спецификациях, но можно считать плюсом. \\n2. Процессор: не указано, какой именно процессор, но ''неплохой процессор'' не является достаточной информацией для оценки соответствия. \\n3. Количество портов: не указано в спецификациях, но можно считать плюсом. \\n4. ОЗУ: не указано. \\n5. SSD: не указано. \\n6. Операционная система: не указано. \\n7. Гарантийный срок: не указано.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (461, 31509902, 'Компьютер DELL Vostro 3681, Intel Core i5 10400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 630, DVD-RW, CR, Windows 10 Home, черный [3681-9962]', 'Откройте для себя мир безграничных возможностей вместе с компьютером DELL Vostro 3681 черного цвета. SSD-накопитель объемом 256 Гб в сочетании с шестиядерным процессором Intel Core i5 10400 гарантируют превосходную производительность и высокую скорость передачи данных, бесшумную работу. Поскольку компьютер DELL Vostro 3681 поддерживает Wi-Fi, у вас не возникнет трудностей с подключением к сети. Встроенный кард-ридер читает карты памяти формата SD. На задней и передней панелях представленной модели имеются разъемы HDMI, D-Sub, USB 3.0, USB 2.0 и разъемы для наушников и микрофона. В комплекте идут проводные периферийные устройства - мышь и клавиатура. Вес в 4.66 кг упрощает транспортировку. Надежность компьютера подтверждает годовая гарантия от производителя.', 'SSD-накопитель 256 Гб, Intel Core i5 10400, DDR4 8ГБ, Intel UHD Graphics 630, DVD-RW, CR, Windows 10 Home, черный, вес 4.66 кг', 'https://www.citilink.ru/product/pk-dell-vostro-3681-sff-i5-10400-8gb-ssd256gb-uhdg-630-dvdrw-cr-w10-kb-1412305/', 49990, 'piece', 'RUB', NULL, 9, '"\"1. Процессор: Intel Core i5 10400 - соответствует спецификации (Intel Core i5).\\n2. ОЗУ: 8 ГБ DDR4 - соответствует спецификации (8 ГБ).\\n3. SSD: 256 ГБ - соответствует спецификации (256 ГБ).\\n4. Операционная система: Windows 10 Home - соответствует спецификации (Windows 10).\\n5. Гарантийный срок: не указан - несоответствие спецификации.\\n6. Дополнительно: Intel UHD Graphics 630, DVD-RW, CR, черный цвет, вес 4.66 кг - дополнительная информация, не влияющая на оценку соответствия.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (462, 31509801, 'Уличный cветильник на солнечной панели Solar Light IP 67 120 ватт', 'Уличный светильник на солнечной панели Solar Light IP 67 мощностью 120 ватт. Отличается высокой степенью защиты от влаги и пыли.', 'Мощность: 120 ватт
Степень защиты: IP 67
Тип светодиодов: SMD
Цветовая температура: 5000K
Материал корпуса: алюминий
Гарантия: 2 года', 'https://ledshop.kz/osveshhenie-na-solnechnih-paneljah/ulichnij-cvetilnik-na-solnechnoj-paneli-solar-light-ip-67-120-vatt', 25000, 'шт', 'KZT', NULL, 4, '"\"1. Мощность: 120 ватт - соответствует спецификации.\\n2. Степень защиты: IP 67 - превышает требуемую IP65, что является плюсом.\\n3. Тип светодиодов: SMD - соответствует спецификации.\\n4. Цветовая температура: 5000K - соответствует спецификации.\\n5. Материал корпуса: алюминий - не соответствует требуемому ABS-пластику.\\n6. Гарантия: 2 года - не указано в спецификации, нейтральный параметр.\\n7. Отсутствует информация о солнечной батарее, датчике движения, дистанционном управлении, таймере, режиме день/ночь, закалённом стекле, времени работы и зарядки, температурном диапазоне, площади освещения, паспорте, сертификате соответствия, инструкции по эксплуатации и герметичной заводской упаковке.\\n\\nИтог: продукт частично соответствует спецификациям, но имеет значительные недостатки и отсутствующую информацию.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (463, 31509820, 'Офисный компьютер', 'Базовый корпоративный компьютер для офиса, подходит для стандартных служебных задач рядового сотрудника.', 'Процессор: AMD Athlon II X2, Intel Celeron G, Intel Core i3 6xxx/7xxx, Intel Pentium G. Оперативная память: 8 Гб DDR4. Жесткие диски: SSD 250 Гб, HDD 500 Гб. Блок питания: 350-400 W. Монитор: 20-24 дюйма, IPS матрица, разрешение 1920x1080. Гарантия от производителя.', 'https://monobloki.com/catalog/kompyutery/', 500, 'unit', 'USD', NULL, 4, '"\"1. Процессор: Продукт предлагает процессоры AMD Athlon II X2, Intel Celeron G, Intel Core i3 6xxx/7xxx, Intel Pentium G, что не соответствует требуемому Intel Core i5. \\n2. Оперативная память: Продукт соответствует спецификации, предлагая 8 ГБ DDR4. \\n3. Жесткий диск: Продукт предлагает SSD 250 ГБ, что близко к требуемому 256 ГБ, но не полностью соответствует. \\n4. Операционная система: Информация о операционной системе отсутствует. \\n5. Гарантия: Информация о гарантии от производителя присутствует, но срок гарантии не указан, что не позволяет оценить соответствие требуемым 2 годам.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (464, 31510065, 'Office Pro+', 'Intel-Core i5 – 10400 2.9 GHz | ОЗУ 8GB DDR4 | SSD 256 GB', 'Материнская плата: ASUS | PRIME | H510M-K | LGA 1200
