INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (473, 31508765, 'Кондиционер AVA ACTN-18TG (+инст. комплект)', 'Характеристики: Уровень шума внешнего блока - 52 дБ, Мин. уровень шума внутреннего блока - 32 дБ, Потребляемая мощность - 1500 Вт, Мощность при обогреве - 5422 Вт, Диапазон рабочих температур - 16° ~ 31°, Теплопроизводительность - 18000 БТЕ/ч, Потребляемая мощность - 1645 Вт, Мощность при охлаждении - 5275 Вт, Холодопроизводительность - 18000 БТЕ/ч, Обслуживаемая площадь - 54 м², Инсталляция (трубки) в комплекте - Да, Класс энергоэффективности - A, Вид кондиционера - Настенный, Кронштейн в комплекте для установки внешнего блока - Нет, Кронштейн в комплекте для установки внутренного блока - Да, Управление воздушными потоками - Автоматическая регулировка воздушных потоков, Ночной режим работы - Обогрев', 'Обслуживаемая площадь, м²: 54', 'https://www.technodom.kz/aktobe/p/kondiczioner-ava-actn-18tg-276025', 6147, 'шт', '₸', NULL, 1, '"\"1. Обслуживаемая площадь: соответствует (54 м²).\\n2. Потребляемая мощность при охлаждении: не указана.\\n3. Мощность при охлаждении: не указана.\\n4. Холодопроизводительность: не указана.\\n5. Диапазон температуры окружающей среды: не указана.\\n6. Инсталляция (трубки) в комплекте: не указана.\\n7. Класс энергоэффективности: не указан.\\n8. Хладагент: не указан.\\n9. Количество компрессоров: не указано.\\n10. Тип компрессора: не указан.\\n11. Тип: не указан.\\n12. Вид кондиционера: не указан.\\n13. Потребляемая мощность при обогреве: не указана.\\n14. Мощность при обогреве: не указана.\\n15. Диапазон рабочих температур: не указан.\\n16. Теплопроизводительность: не указана.\\n17. Уровень шума внешнего блока: не указан.\\n18. Мин. уровень шума внутреннего блока: не указан.\\n19. Длина трубок: не указана.\\n20. Автоматическая регулировка воздушных потоков: не указана.\\n21. Режимы работы: не указаны.\\n22. Управление: не указано.\\n23. Поставка и установка: не указаны.\\n\\nИтог: Продукт соответствует только одному параметру из спецификаций (обслуживаемая площадь).\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (474, 31509782, 'Системный блок ( intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W )', 'Офисный компьютер для дома и офиса', 'Характеристики: intel core i5 2400, 8 ГБ ОЗУ, SSD 512 ГБ, 400W', 'https://boxberry.ru/market/product/sistemnyy-blok-royal-office-i58gb240gb-2440026333/', 18415, 'шт', '₽', NULL, 8, '"\"1. Процессор: Соответствует (Intel Core i5).\\n2. ОЗУ: Соответствует (8 ГБ).\\n3. SSD: Превышает требования (512 ГБ вместо 256 ГБ).\\n4. Операционная система: Не указана.\\n5. Гарантийный срок: Не указан.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (475, 31508018, 'Линия по производству клееного щита производительностью 90-100 м3', 'Линия по производству мебельного щита производительностью 90-100 м3 готового щита в месяц при 8 часовом режиме работы. Размеры помещения - оборудование для изготовления мебельного щита: 48х18 м (ДхШ). Производство клееных деревянных щитов стоимость от 107.500 у.е.', '1. Четырехсторонний станок с пильным шпинделем V-HOLD VH-M521SAW

Предназначен для четырехсторонней плоскостной и профильной обработки заготовок с последующей распиловкой дисковыми пилами.

Технические характеристики

- Количество шпинделей: 5
- Длина обрабатываемой заготовки: от 200 мм
- Ширина обработки: 18-210 мм
- Высота обработки: 8-140 мм
- Скорость подачи: 6-36 м/мин
- Частота вращения шпинделей: 6500 об/мин
- Мощность двигателя подачи: 4 КВт
- Мощность нижнего шпинделя: 5,5 КВт
- Мощность правого шпинделя: 5,5 КВт
- Мощность левого шпинделя: 5,5 КВт
- Мощность верхнего шпинделя: 7,5 КВт
- Мощность пильного шпинделя: 15,0 КВт
- Мощность двигателя подъема траверсы: 0,75 КВт
- Суммарная мощность: 43,75 КВт
- Диаметр шпинделей: 40 мм
- Диаметр инструмента на 1-ом шпинделе: 125 мм
- Диаметр инструмента на вертикальных шпинделях: 125-180 мм
- Диаметр инструмента на горизонтальных шпинделях: 125-180 мм
- Диаметр подающего ролика: 140 мм
- Диаметр вытяжного патрубка: 140 мм
- Габаритные размеры: 3500х1620х1850 мм
- Масса станка: 3400 кг', 'https://www.v-hold.ru/katalog/mini_zavody/kleenyy-shchit-oborudovanie-dlya-proizvodstva-mebelnogo-shchita/mebelnyy-shchit-oborudovanie-proizvoditelnostyu-90-100-m3-mesyats/', 107500, 'месяц', 'у.е.', NULL, 1, '"\"Продукт, представленный как четырехсторонний станок с пильным шпинделем V-HOLD VH-M521SAW, не соответствует спецификациям поперечного настольного станка. Основные несоответствия включают: \\n1. Назначение: Четырехсторонний станок предназначен для плоскостной и профильной обработки, а не для поперечной и угловой распиловки. \\n2. Технические характеристики: \\n- Количество шпинделей: 5 (не указано в спецификациях)\\n- Длина обрабатываемой заготовки: от 200 мм (не указано в спецификациях)\\n- Ширина обработки: 18-210 мм (не указано в спецификациях)\\n- Высота обработки: 8-140 мм (не указано в спецификациях)\\n- Скорость подачи: 6-36 м/мин (не указано в спецификациях)\\n- Частота вращения шпинделей: 6500 об/мин (не соответствует требуемым 2850 об/мин)\\n- Мощность двигателя подачи: 4 КВт (не указано в спецификациях)\\n- Мощность шпинделей: различные значения (не соответствует требуемым 3,5 КВт)\\n- Суммарная мощность: 43,75 КВт (значительно превышает требуемые 3,5 КВт)\\n- Диаметр шпинделей: 40 мм (не указано в спецификациях)\\n- Диаметр инструмента: различные значения (не соответствует требуемым 400 мм)\\n- Габаритные размеры: 3500х1620х1850 мм (не соответствует требуемым 4500х950х1350±100 мм)\\n- Масса станка: 3400 кг (не указано в спецификациях)\\n- Отсутствие информации о комплекте ЗИП и кабелях питания.\\n- Отсутствие информации о возможности интеграции в вентиляционную систему.\\n- Отсутствие информации о доставке, упаковке и документации.\\nТаким образом, продукт не соответствует спецификациям поперечного настольного станка.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (476, 31508069, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В описании продукта указано, что процессор неплохой, но не уточняется, что это Intel Core i5. Это может быть как соответствие, так и несоответствие, так как точная модель процессора не указана. \\n2. ОЗУ: В описании продукта нет информации о количестве оперативной памяти. \\n3. SSD: В описании продукта нет информации о наличии и объеме SSD. \\n4. Операционная система: В описании продукта нет информации об установленной операционной системе. \\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке. \\n6. Компактный корпус и достаточное количество портов: Эти характеристики соответствуют спецификациям, но они не являются ключевыми требованиями.\""');
