INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (481, 31508017, 'Линия по производству клееного щита производительностью 90-100 м3', 'Линия по производству мебельного щита производительностью 90-100 м3 готового щита в месяц при 8 часовом режиме работы. Размеры помещения - оборудование для изготовления мебельного щита: 48х18 м (ДхШ). Производство клееных деревянных щитов стоимость от 107.500 у.е.', '1. Четырехсторонний станок с пильным шпинделем V-HOLD VH-M521SAW

