INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (493, 31507519, 'Реле контроля уровня РКУ-02 230/400В, наполнение или дренаж, 3 датчика (без датчиков) TDM SQ1507-0003', 'Реле контроля уровня жидкости РКУ-02 ТДМ, режим наполнение или дренаж, 2 контролируемых уровня. Назначение: Для контроля и поддержки заданного уровня токопроводящих жидкостей, управления электродвигателями насосных установок, управления электромагнитными клапанами, задфижками и вентилями. Применение: Автоматический контроль уровня воды в водонапорной башне. Контроль уровня жидкости в источнике с малым дебитом. Поочередное или суммарное включение двух насосов в колодцах, в которых недопустимо их переполнение. Материалы: Корпус реле выполнен из не поддерживающего горение пластика. Датчики контроля уровня изготовлены из нержавеющей стали. Конструкция: Работа реле базируется на кондуктометрическом методе определения наличия жидкости, который основан на электрической проводимости жидкостей и возникновении микротока между электродами датчиков. Реле используют для контроля уровней следующих жидкостей: вода (водопроводная, родниковая, дождевая, морская), жидкости с низким содержанием алкоголя (пиво, вино и др.), молоко, кофе, сточные воды, жидкие удобрения. Реле нельзя использовать для следующих жидкостей: дистиллированная вода, бензин, керосин, масло, этиленгликоль, краски, сжиженный газ. Преимущества: Реле имеют переключающие контакты, что позволяет использовать их для работы как в режиме наполнения, так и в режиме слива. РКУ-02, РКУ-03, РКУ-04 могут питаться как от напряжения 230 В, так и от 400 В.', 'Номинальное напряжение, В: 230/400 В АС, Номинальный ток контактов, А: 10, Количество контролируемых уровней: 2, Количество используемых датчиков контроля уровня: 3, Максимальная длина провода (от реле до датчика), м: 100, Напряжение питания датчика, не более, В: 10, Ток потребления датчика, не более, мА: 2, Потребляемая мощность, ВА: 2, Чувствительность, кОм: 50, Задержка переключения контакта при срабатывании, мс: 20, Задержка переключения контакта при возврате, мс: 20, Типы жидкостей: вода (водопроводная, родниковая, дождевая), жидкости с низким содержанием алкоголя (пиво, вино и др.), молоко, кофе, сточные воды, жидкие удобрения, Количество индикаторов состояния: 3, Механическая износостойкость, циклов: 10 000 000, Электрическая износостойкость, циклов: 100 000, Диапазон рабочих температур, °С: от -10 до +50, Тип контакта: 1р (переключающий), Способ установки: DIN-рейка, Масса, кг: 0,15', 'https://shop220.ru/sq1507-0003-rele-kontrolya-urovnya-rku-02-230-400v-napolnenie-ili-drenazh-3-datchika-bez-datchikov-tdm.htm', 2433.89, 'шт', 'RUB', NULL, 10, '"\"Продукт соответствует большинству спецификаций. Номинальное напряжение (230/400 В АС), номинальный ток контактов (10 А), количество контролируемых уровней (2), количество используемых датчиков контроля уровня (3), максимальная длина провода (100 м), напряжение питания датчика (10 В), ток потребления датчика (2 мА), потребляемая мощность (2 ВА), чувствительность (50 кОм), задержка переключения контакта при срабатывании и возврате (20 мс), количество индикаторов состояния (3), электрическая износостойкость (100 000 циклов), диапазон рабочих температур (от -10 до +50 °С), тип контакта (1 переключающий) и вес (0,15 кг) полностью соответствуют спецификациям. Продукт также соответствует требованиям по типам жидкостей, с которыми он может работать. Механическая износостойкость (10 000 000 циклов) не указана в спецификациях, но это не является критическим несоответствием.\""');
