INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (502, 31504621, 'Компьютер для дома и офиса / Офисный компьютер / Системный блок ( intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W )', 'Компьютер для дома и офиса с процессором intel core i5 2400, 8 ГБ оперативной памяти, SSD накопителем на 512 ГБ и блоком питания на 400W.', 'intel core i5 2400 / 8 ГБ ОЗУ / SSD 512 ГБ / 400W', 'https://boxberry.ru/market/product/sistemnyy-blok-royal-office-i58gb240gb-2440026333/', 18415, 'шт', '₽', NULL, 7, '"\"1. Процессор: Intel Core i5 2400 соответствует требованию Intel Core i5.\\n2. ОЗУ: 8 ГБ соответствует требованию 8 ГБ.\\n3. SSD: 512 ГБ превышает требование 256 ГБ.\\n4. Операционная система: информация отсутствует.\\n5. Гарантийный срок: информация отсутствует.\""');
