INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (506, 31503824, 'Центр поддержки', 'Центр поддержки предоставляет различные услуги для помощи пользователям в решении проблем и получении необходимой информации.', 'Центр поддержки предоставляет услуги по диагностике, чату, уведомлениям, заказу звонка, отправке писем, поиску по помощи и другим видам обратной связи.', 'https://zakupki.kontur.ru/RQ0346300079724000002', 0, 'service', 'USD', NULL, 0, '"\"Предоставленные детали продукта не соответствуют указанным спецификациям. Описание продукта относится к услугам центра поддержки, тогда как спецификации касаются катка поддерживающего 50-21-394СП Т-170. Нет информации о соответствии ГОСТ 27.507-2015, годе выпуска, гарантийном сроке, состоянии товара, заводской упаковке, разгрузке товаров и согласовании даты и времени поставки. Также отсутствуют контактные данные для технических вопросов.\""');
