INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (510, 31502836, 'Моторное масло GNV Standard Force 15w40 180л', 'Всесезонное минеральное моторное масло для высокомощных дизельных двигателей с высочайшими эксплуатационными характеристиками. Минеральное моторное масло, произведенное с применением синтетических технологий, специально разработанное для высоконагруженных дизельных двигателей с турбонаддувом и без него, удовлетворяющее нормам Euro V и ниже. Масло GNV Standard Force 15W-40 способствует продлению срока службы современных двигателей, обеспечивая их отличное смазывание и передовую защиту в автомобилях, оборудованных системами очистки отработанных газов EGR (система рециркуляции выхлопных газов) и SCR (каталитическая система нейтрализации отработанных газов). При производстве масла GNV Standard Force 15W-40 используется уникальная технология, которая не только обеспечивает соответствие масла широчайшему спектру спецификаций отрасли и мировых производителей двигателей, но и превосходит их исключительные эксплуатационные показатели. Его высочайшие эксплуатационные свойства подтверждены на практике в самых разнообразных отраслях и условиях, в том числе и в смешанных автомобильных парках. ПРИМЕНЕНИЕ: ● GNV Standard Force 15W-40 рекомендуется для широкого ряда шоссейных и внедорожных грузовых автомобилей с дизельными двигателями без сажевых фильтров (DPF), применяемых в таких отраслях, как коммерческий транспорт, горнорудная промышленность, строительство и сельское хозяйство. ● Подходит для двигателей тяжелых грузовиков, автобусов, специальной и внедорожной техники, отвечающих требованиям Euro-4 и ниже, а также для некоторых типов двигателей, оснащенных системой рециркуляции отработанных газов EGR. ● Разработано в соответствии с требованиями производителей техники, где необходим уровень эксплуатационных свойств ACEA E7. ● Отличные вязкостно-температурные характеристики масла обеспечивают легкий запуск двигателя при температурах до -20 °С.', '● GNV Standard Force 15W-40 рекомендуется для широкого ряда шоссейных и внедорожных грузовых автомобилей с дизельными двигателями без сажевых фильтров (DPF), применяемых в таких отраслях, как коммерческий транспорт, горнорудная промышленность, строительство и сельское хозяйство. ● Подходит для двигателей тяжелых грузовиков, автобусов, специальной и внедорожной техники, отвечающих требованиям Euro-4 и ниже, а также для некоторых типов двигателей, оснащенных системой рециркуляции отработанных газов EGR. ● Разработано в соответствии с требованиями производителей техники, где необходим уровень эксплуатационных свойств ACEA E7. ● Отличные вязкостно-температурные характеристики масла обеспечивают легкий запуск двигателя при температурах до -20 °С.', 'https://bochkamaslo.ru/motornoe-maslo/motornoe-maslo-gnv-standard-force-15w40-180l/', 180, 'л', 'RUB', NULL, 8, '"\"Продукт GNV Standard Force 15W-40 соответствует большинству предоставленных спецификаций. Он предназначен для дизельных двигателей, включая двигатели тяжелых грузовиков и специальной техники, что соответствует требованиям спецификаций. Продукт также подходит для использования в различных отраслях, таких как коммерческий транспорт, горнорудная промышленность, строительство и сельское хозяйство, что также соответствует спецификациям. Масло имеет отличные вязкостно-температурные характеристики, обеспечивающие легкий запуск двигателя при температурах до -20 °С, что является плюсом. Однако, в спецификациях указано, что масло должно быть минеральным с применением синтетических технологий, а в описании продукта это не упоминается. Это может быть недостатком, если продукт не соответствует этому требованию.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (511, 31503706, 'Ультрабук Asus Vivobook Go 15 Ryzen 5 7520U / 8ГБ / 512SSD / 15.6/ DOS / (E1504FA-BQ414)', 'Диагональ дисплея, дюйм 15.6 Серия процессора AMD Ryzen 5 Объем оперативной памяти, ГБ 8', 'Объем оперативной памяти, ГБ 8 Интегрированное графическое ядро AMD Radeon Graphics Тактовая частота процессора Turbo Boost, ГГц 4.3 Диагональ дисплея, дюйм 15.6 Частота обновления экрана 60 Hz HDMI, Jack 3.5 mm, USB 2.0, USB 3.2, USB Type C', 'https://www.technodom.kz/p/ultrabuk-156-asus-vivobook-go-15-e1504fa-bq414-269947', 6147, 'шт', '₸', NULL, 4, '"\"1. Объем оперативной памяти: 8 ГБ (несоответствие, требуется не менее 16 ГБ).\\n2. Интегрированное графическое ядро: соответствует (требуется встроенная видеокарта).\\n3. Тактовая частота процессора Turbo Boost: 4.3 ГГц (соответствует, требуется не менее 3.9 ГГц).\\n4. Диагональ дисплея: 15.6 дюймов (соответствует, требуется не менее 15.6 дюймов).\\n5. Частота обновления экрана: 60 Hz (соответствует, требуется не менее 60 Hz).\\n6. Интерфейсы: HDMI, Jack 3.5 mm, USB 2.0, USB 3.2, USB Type C (соответствует).\\n7. Отсутствует информация о частоте процессора, количестве ядер, типе накопителя, объеме SSD накопителя, встроенной вебкамере, разрешении дисплея, яркости, типе матрицы экрана, операционной системе, сетевых подключениях (Bluetooth, Wi-Fi).\""');
