INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (513, 31502122, 'О внесении дополнения в приказ Министра национальной экономики Республики Казахстан от 3 февраля 2015 года № 71 "Об утверждении Правил оказания инжиниринговых услуг в сфере архитектурной, градостроительной и строительной деятельности"', 'Правила дополнены пунктом 27-1 в соответствии с приказом и.о. Министра индустрии и инфраструктурного развития РК от 04.05.2022 № 252 (вводится в действие по истечении десяти календарных дней после дня его первого официального опубликования).', 'Сноска. Глава 2 дополнена пунктом 3-1 в соответствии с приказом Министра национальной экономики РК от 30.06.2016 № 296 (вводится в действие с 10.10.2016).', 'https://adilet.zan.kz/rus/docs/V1500010401/links', 0, 'item', 'KZT', NULL, 2, '"\"Продукт представляет собой сноску, указывающую на дополнение главы 2 новым пунктом 3-1 в соответствии с приказом Министра национальной экономики РК от 30.06.2016 № 296, который вводится в действие с 10.10.2016. Спецификации требуют, чтобы оказываемый авторский надзор соответствовал действующему законодательству РК об архитектурной, градостроительной и строительной деятельности, а также Правилам оказания инжиниринговых услуг в этой сфере. В предоставленных деталях продукта нет информации, подтверждающей соответствие этим требованиям. Продукт не описывает, как осуществляется авторский надзор и соответствует ли он указанным нормативным актам.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (514, 31502573, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Популярный отзыв', 'Компактный корпус, неплохой процессор, Достаточное количество портов.', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 5100, 'шт', 'RUB', NULL, 2, '"\"1. Процессор: В спецификациях указан Intel Core i5, но в описании продукта процессор не уточнён, что снижает оценку.\\n2. ОЗУ: В описании продукта нет информации об объёме оперативной памяти, что снижает оценку.\\n3. SSD: В описании продукта нет информации о наличии и объёме SSD, что снижает оценку.\\n4. Операционная система: В описании продукта нет информации об операционной системе, что снижает оценку.\\n5. Гарантийный срок: В описании продукта нет информации о гарантийном сроке, что снижает оценку.\\n6. Компактный корпус и достаточное количество портов соответствуют спецификациям, но это не ключевые параметры.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (515, 31501651, 'Комплект Yamaha NS-555', 'напольная фронтальные колонки, комплект для домашнего кинотеатра, Hi-Fi пассивная фазоинверторного типа позолоченные разъемы, съемная решетка, магнитная защита, монополярная Dolby Pro Logic II, Dolby Pro Logic, DTS, DTS-HD', '3 полосы, Номинальная мощность: 100 Вт, Максимальная мощность: 250 Вт, Минимальная частота: 35 Гц, Максимальная частота: 35000 Гц, Импеданс: 6 Ом, Способ проводного подключения: bi-wiring, Тип разъема колонок: винтовой, Проигрыватель в комплекте: воспроизведение с карты памяти', 'https://top10tech.ru/trekhpolosnye-akusticheskie-sistemy/', 43632, 'шт.', 'руб.', NULL, 3, '"\"1. Количество полос: продукт имеет 3 полосы, в то время как спецификации требуют 2 полосы. Это прямое несоответствие.\\n2. Номинальная мощность: продукт имеет номинальную мощность 100 Вт, что ниже требуемых 112 Вт. Это несоответствие.\\n3. Максимальная мощность: продукт имеет максимальную мощность 250 Вт, что выше требуемых 112 Вт. Это несоответствие.\\n4. Минимальная частота: продукт имеет минимальную частоту 35 Гц, что лучше, чем требуемые 39 Гц. Это соответствие.\\n5. Максимальная частота: продукт имеет максимальную частоту 35000 Гц, что лучше, чем требуемые 24000 Гц. Это соответствие.\\n6. Импеданс: продукт имеет импеданс 6 Ом, что не указано в спецификациях. Это несоответствие.\\n7. Способ проводного подключения: продукт поддерживает bi-wiring, в то время как спецификации требуют bi-amping. Это несоответствие.\\n8. Тип разъема колонок: продукт имеет винтовой разъем, в то время как спецификации требуют балансный вход. Это несоответствие.\\n9. Проигрыватель в комплекте: продукт соответствует спецификации по воспроизведению с карты памяти. Это соответствие.\\n10. Материал корпуса, размеры и другие конструктивные особенности не указаны для продукта, поэтому их соответствие невозможно оценить.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (516, 31502896, 'Office Pro+', 'Intel-Core i5 - 10400 2.9 GHz | ОЗУ 8GB DDR4 | SSD 256 GB', 'Материнская плата: ASUS | PRIME | H510M-K | LGA 1200
