INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (535, 31503771, 'Поршень КМЗ 51-03-40-01 (конвейер ЧТЗ ∅150) Д160 (покрытие олово)', 'Поршень на тракторы Т-170,-108, -180 с двигателем ЧТЗ Д-160, Д-180.', 'Диаметр 150 мм. Поршень к двигателю Д160. Две канавки под маслосъемные кольца. Три канавки под компрессионные кольца (наклонные и прямоугольные). Камера сгорания тороидальная, без рассекателя. Материал: алюминиевый сплав АК12М2МгН. Покрытие: олово.', 'https://moscow.ressora74.ru/catalog/porshnevye-gruppy-kamskogo-motornogo-zavoda/porshnevye-gruppy-k-dvigatelyam-chtz/porshni-gilzy-paltsy-chtz/porshen-kmz-51-03-40-01-konveyer-chtz-150-d160-pokrytie-olovo-/', 1, 'шт', 'RUB', NULL, 5, '"\"1. Диаметр 150 мм: соответствует.\\n2. Поршень к двигателю Д160: соответствует.\\n3. Две канавки под маслосъемные кольца: соответствует.\\n4. Три канавки под компрессионные кольца (наклонные и прямоугольные): соответствует.\\n5. Камера сгорания тороидальная, без рассекателя: соответствует.\\n6. Материал: алюминиевый сплав АК12М2МгН: соответствует.\\n7. Покрытие: олово: соответствует.\\n8. ГОСТ 27.507-2015: не указано.\\n9. Год выпуска – Не ранее 2023 года: не указано.\\n10. Гарантийный срок (в месяцах) - 12 месяцев с момента поставки товара: не указано.\\n11. Товар должен быть новым, не бывшим в эксплуатации, поставляется в заводской упаковке: не указано.\\n12. На заводской упаковке должно быть указано наименование товара, технические характеристики товара, завод изготовитель: не указано.\\n13. Поставщик обязуется осуществлять разгрузку товаров в пункте назначения за счет собственных сил и средств: не указано.\\n14. Поставщик обязан согласовать с Заказчиком дату и время поставки товаров за 3 (три) рабочих дня до отгрузки товаров: не указано.\\n15. По техническим вопросам обращаться к начальнику УТТиМ Нурсеитову Г.М. тел. + 7(705)-751-3109, механику УТТиМ Плаксину Н.В.тел. +7(777)-354-6706: не указано.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (536, 31503762, 'Рукав для воды всас. В-1 Ф 125 мм (0,8 атм) (4 м) ГОСТ 5398-76', 'Класс: В - вода техническая
Группа: 1- всасывающий
Внутренний диаметр рукава: 125 мм (±2)
Рукава герметичны при гидравлическом давлении: 0,2 МПа
Рабочий вакуум: 0,08 МПа
Рабочая температура: от - 35 °С до + 90 °С в условиях умеренного климата
Вес 1 пог.м.: 6,3 кг
Минимальная партия: 4 метра (отпускается кратно 4-м метрам)

Рукава состоят из внутренней резиновой камеры, текстильного слоя, проволочной спирали, промежуточного резинового слоя и наружного текстильного слоя.
На концах рукавов мягкие манжеты длиной не менее 150 мм для присоединения их к арматуре. Внешняя поверхность рукава гофрированная. Рукав имеет трехкратный запас прочности при разрыве гидравлическим давлением.
Маркировка: на каждом рукаве на одном конце имеется рельефная или другая маркировка с указанием:
- товарного знака или наименования предприятия-изготовителя и его товарный знак;
- класса рукава;
- группы рукава;
- внутреннего диаметра;
- рабочего давления;
- длины;
- даты изготовления: месяц (квартал) и год;
- штампа технического контроля.
Не допускается прямой длительный контакт манжеты с рабочей средой!
Минимальный радиус изгиба: 600 мм
Стандарт: ГОСТ 5398-76
Сертификат: Не подлежит обязательной сертификации

Произведено в России', 'Внутренний диаметр, мм. 125
Рабочее давление, МПа 0.08', 'https://rusbelt.ru/catalog/rukava-promyshlennye/rukava-naporno-vsasyvayushchie-gost-5398-76-s-tekstilnym-karkasom-i-metallicheskoy-spiralyu/rukav-dlya-vody-vsas-v-1-f-125-mm-0-8-atm-4-m-gost-5398-76/', 1485, 'м', 'руб.', NULL, 2, '"\"1. Внутренний диаметр: Продукт имеет внутренний диаметр 125 мм, что не соответствует спецификации (100 мм ± 2 мм). Это прямое несоответствие.\\n2. Рабочее давление: Продукт имеет рабочее давление 0.08 МПа, что не соответствует спецификации (0.2 МПа). Это прямое несоответствие.\\n3. Класс и группа: Спецификации не содержат информации о классе и группе продукта.\\n4. Рабочий вакуум: Продукт соответствует спецификации (0.08 МПа).\\n5. Температурный диапазон: Спецификации не содержат информации о температурном диапазоне продукта.\\n6. Конструкция: Спецификации не содержат информации о конструкции продукта.\\n7. Год выпуска: Спецификации не содержат информации о годе выпуска продукта.\\n8. Гарантийный срок: Спецификации не содержат информации о гарантийном сроке продукта.\\n9. Состояние и упаковка: Спецификации не содержат информации о состоянии и упаковке продукта.\\n10. Разгрузка и согласование поставки: Спецификации не содержат информации о разгрузке и согласовании поставки.\\n11. Контактные данные: Спецификации не содержат информации о контактных данных.\\n\\nИтог: Продукт не соответствует ключевым спецификациям по внутреннему диаметру и рабочему давлению.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (537, 31504199, 'ТОО СПУТНИК-МЕД', 'Оптовая торговля широким ассортиментом товаров без какой-либо конкретизации', 'Основным видом деятельности ТОО ''СПУТНИК-МЕД'' заявлено Оптовая торговля широким ассортиментом товаров без какой-либо конкретизации (код 46909)', 'https://allcompanies.by/kz/company?query=180840018650', 0, '', '', NULL, 2, '"\"1. Основной вид деятельности ТОО ''СПУТНИК-МЕД'' - оптовая торговля широким ассортиментом товаров без конкретизации. Это не противоречит спецификациям, но и не подтверждает их выполнение.\\n2. Нет информации о размере пакетов, их толщине, объеме и количестве пакетов в рулоне. Это прямое несоответствие спецификациям.\\n3. Нет информации о наличии документов, подтверждающих соответствие товара требованиям технических регламентов и стандартов Республики Казахстан. Это также прямое несоответствие спецификациям.\""');
