INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (539, 31502653, 'Компьютер iRU 310SC, Intel Core i5 12400, DDR4 8ГБ, 256ГБ(SSD), Intel UHD Graphics 730, Windows 11 Professional, черный [1969067]', 'Компьютер iRU 310SC с процессором Intel Core i5 12400, оперативной памятью DDR4 8ГБ и накопителем 256ГБ(SSD). Графика Intel UHD Graphics 730. Установлена операционная система Windows 11 Professional. Цвет черный.', 'Процессор: Intel Core i5 12400, Оперативная память: DDR4 8ГБ, Накопитель: 256ГБ(SSD), Графика: Intel UHD Graphics 730, Операционная система: Windows 11 Professional, Цвет: черный', 'https://www.citilink.ru/product/kompyuter-iru-310sc-intel-core-i5-12400-ddr4-8gb-256gb-ssd-intel-uhd-g-1969067/', 49990, 'piece', 'RUB', NULL, 8, '"\"1. Процессор: Соответствует (Intel Core i5 12400).\\n2. Оперативная память: Соответствует (8 ГБ DDR4).\\n3. Накопитель: Соответствует (256 ГБ SSD).\\n4. Графика: Не указана в спецификациях, но наличие Intel UHD Graphics 730 не противоречит требованиям.\\n5. Операционная система: Не соответствует (Windows 11 Professional вместо Windows 10).\\n6. Цвет: Не указан в спецификациях, но наличие черного цвета не противоречит требованиям.\\n7. Гарантийный срок: Не указан в деталях продукта.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (540, 31503879, 'Рубашки', 'Техническая спецификация для рубашек с длинными и короткими рукавами, а также для кительшей, свитеров и фуражек', 'Рубашки должны соответствовать стандартам и требованиям по изготовлению форменной одежды для военнослужащих и сотрудников противопожарной службы. Включают в себя детальные описания конструкции, материалов, отделки, маркировки, упаковки и требований к технологичности.', 'https://pandia.ru/text/80/337/90573.php', 0, 'item', 'USD', NULL, 6, '"\"Продукт представляет собой рубашки, предназначенные для военнослужащих и сотрудников противопожарной службы. Спецификации включают детальные описания конструкции, материалов, отделки, маркировки, упаковки и требований к технологичности. Продукт должен соответствовать стандарту СТ РК 2907 - 2016 «РУБАШКА ДЛЯ ВОЕННОСЛУЖАЩИХ ЖЕНЩИН. Технические условия». Однако, в предоставленных деталях продукта отсутствует информация о конкретных материалах, используемых в рубашках, а также о маркировке и упаковке. Это снижает оценку соответствия, так как невозможно полностью оценить соответствие всем требованиям стандарта.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (541, 31474543, 'POWERWIN BT100 LifePO4 12V 100Ah/1280Wh HI5500 5500W 48V Hybrid Solar Inverter 100A MPPT Pure Sine Wave Standalone LCD 48V Battery', 'POWERWIN BT100 LifePO4 12V 100Ah/1280Wh HI5500 Hybrid Solar Inverter 5500W 48V Pure Sine Wave 100A MPPT Standalone Battery LCD 48V', '12V 100Ah/1280Wh HI5500 Hybrid Solar Inverter 5500W 48V Pure Sine Wave 100A MPPT Standalone Battery LCD 48V', 'https://aliexpress.ru/item/1005006917201765.html?sku_id=12000038720329517&_randl_currency=RUB&_randl_shipto=RU&src=googlefree&aff_short_key=brxT3bLh&aff_platform=true&acnt=176900129&feed_id=30', 1000, 'piece', 'USD', NULL, 7, '"\"Продукт имеет следующие характеристики: 12V 100Ah/1280Wh, что соответствует спецификациям аккумулятора POWERWIN BT100 (12,8 В, 100 Ач, 1280 Втч). Продукт также включает автономный инвертор, что соответствует спецификациям. Однако, в спецификациях упоминается встроенный радар-детектор BMS и 4000+ глубоких циклов, что не указано в деталях продукта. Также, продукт имеет инвертор на 5500W 48V и MPPT на 100A, что не упоминается в спецификациях.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (542, 31512250, 'Принтер струйный Canon PIXMA G1416 СНПЧ A4', 'Струйный принтер Canon PIXMA G1416 с СНПЧ формата A4.', 'Подача бумаги стандартная, листов: 100; Система непрерывной подачи чернил (СНПЧ): Да; Фотобумаге, Глянцевой бумаге, Конвертах, Матовой бумаге; Ресурс ч/б картриджа/тонера, стр: 12000; Максимальная плотность бумаги, г/м²: 275; Минимальная плотность бумаги, г/м²: 64; Ресурс цветного картриджа/тонера, стр: 7000; Совместимые модели картриджей: GI-490 PGBK, GI-490C, GI-490M, GI-490Y; Windows 10, Windows 7, Windows 8, Windows 8.1; Возможность работы без ПК: Нет; Возможность работы от аккумулятора: Нет; Устройство для чтения карт памяти: Нет; Максимальная скорость цветной печати, стр/мин: 5; Время печати фото 10x15 см (цветн.), с: 60; Поддержка двусторонней печати: Нет; Максимальное разрешение печати: 4800x1200; Максимальная скорость монохромной печати, стр/мин: 8.8', 'https://www.technodom.kz/p/printer-strujnyj-canon-pixma-g-1416-snpch-a4-2314c037-222024', 0, 'шт', '₸', NULL, 6, '"\"1. Подача бумаги стандартная, листов: 100 - соответствует спецификации.\\n2. Система непрерывной подачи чернил (СНПЧ): Да - соответствует спецификации.\\n3. Поддержка печати на фотобумаге, глянцевой бумаге, конвертах, матовой бумаге - соответствует спецификации.\\n4. Ресурс ч/б картриджа/тонера, стр: 12000 - соответствует спецификации.\\n5. Максимальная плотность бумаги, г/м²: 275 - соответствует спецификации.\\n6. Минимальная плотность бумаги, г/м²: 64 - соответствует спецификации.\\n7. Ресурс цветного картриджа/тонера, стр: 7000 - соответствует спецификации.\\n8. Совместимые модели картриджей: GI-490 PGBK, GI-490C, GI-490M, GI-490Y - соответствует спецификации.\\n9. Поддержка ОС: Windows 10, Windows 7, Windows 8, Windows 8.1 - соответствует спецификации.\\n10. Возможность работы без ПК: Нет - соответствует спецификации.\\n11. Возможность работы от аккумулятора: Нет - соответствует спецификации.\\n12. Устройство для чтения карт памяти: Нет - соответствует спецификации.\\n13. Максимальная скорость цветной печати, стр/мин: 5 - соответствует спецификации.\\n14. Время печати фото 10x15 см (цветн.), с: 60 - соответствует спецификации.\\n15. Поддержка двусторонней печати: Нет - соответствует спецификации.\\n16. Максимальное разрешение печати: 4800x1200 - соответствует спецификации.\\n17. Максимальная скорость монохромной печати, стр/мин: 8.8 - соответствует спецификации.\\n18. Габариты и вес (Высота, мм 135, Ширина, мм 445, Глубина, мм 330, Вес, кг 4.8) - отсутствует информация.\\n19. Уровень шума, дБ 54.5 - отсутствует информация.\\n20. Потребление энергии, Вт 11 - отсутствует информация.\\n21. Интерфейсы USB Type B - отсутствует информация.\\n22. Технология печати: Струйная - отсутствует информация.\\n23. Тип печати: Цветная - отсутствует информация.\\n24. Поддержка Wi-Fi: Нет - отсутствует информация.\\n25. Максимальный формат: A4 - отсутствует информация.\\n26. Печать фотографий: Да - отсутствует информация.\\n27. Размещение: Настольный - отсутствует информация.\\n28. Область печати: 216×297 - отсутствует информация.\\n29. Печать без полей: Да - отсутствует информация.\\n30. Количество цветов: 4 - отсутствует информация.\\n31. Количество картриджей: 4 - отсутствует информация.\\n32. Гарантия не менее 12 месяцев - отсутствует информация.\\n33. Модель согласовать с Заказчиком - отсутствует информация.\\n34. Товар должен быть новым, не восстановленным, без каких либо наружных и внутренних дефектов - отсутствует информация.\\n35. Поставка товара и разгрузка товара за счёт сил и средств поставщика - отсутствует информация.\\n36. При поставке товара поставщик должен предоставить документы: Если товар Казахстанского происхождения сертификат СТ– КЗ. Если товар импортного производства, то предоставляет сертификат о происхождении товара, выданного соответствующим уполномоченным органом страны происхождения - отсутствует информация.\\n37. Доставка бесплатно - отсутствует информация.\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (543, 31509766, 'Мешок для строительного мусора, полипропилен, 55*95 см, зеленый, 1000 шт/уп.', 'Полипропиленовые мешки - это прочная и легкая тара, изготовленная из вторичного полипропилена. Универсальные в применении изделия способны выдерживать вес до 50 кг. Материал не теряет свойств при повышенной влажности и выдерживает большую механическую нагрузку при транспортировке острых и негабаритных грузов. Мешки из полипропилена активно используют в промышленности и в быту. Высокая прочность и устойчивость к истиранию.', 'Количество товара на складе
Цена
9 75 руб.
Цена за шт. — 9 75 руб.
Цена
975 руб.
Цена за шт. — 975 руб.', 'https://www.shop.gold-pack.ru/catalog/tovary-dlya-stroitelstva-remonta-i-otdelki/meshki-dlya-stroitelnogo-musora-/meshki-dlya-stroitelnogo-musora-polipropilenovye/meshok-dlya-stroitelnogo-musora-polipropilen-55-95-sm-zelenyy-1000-sht-up_3/?region=818', 975, 'шт.', 'руб.', NULL, 0, '"\"Продукт не соответствует спецификациям. В спецификациях указаны мешки для мусора полипропиленовые размером 95*55, однако в предоставленных деталях продукта нет информации о материале, размере или типе продукта. Указаны только цены, которые также противоречат друг другу (9 75 руб. и 975 руб.).\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (544, 31506364, 'Стеллаж металлический (1800*1000*800мм)', 'Металлический стеллаж с размерами 1800*1000*800мм. В комплекте 4 полки и дополнительная полка за 8707 тенге.', 'Высота: 1800 мм, Ширина: 1000 мм, Глубина: 800 мм. Нагрузка на каждую полку 140 кг. Стойка МС-750 позволяет выдерживать равномерно распределенную нагрузку до 750 кг.', 'https://mts-asia.kz/p96678376-stellazh-metallicheskij-18001000800mm.html', 8707, 'piece', 'KZT', NULL, 8, '"\"1. Высота: 1800 мм - соответствует спецификации (не менее 1800 мм).\\n2. Ширина: 1000 мм - соответствует спецификации (не менее 1000 мм).\\n3. Глубина: 800 мм - соответствует спецификации (не менее 800 мм).\\n4. Нагрузка на каждую полку: 140 кг - соответствует спецификации (не менее 140 кг).\\n5. Стойка МС-750 выдерживает нагрузку до 750 кг - соответствует спецификации (не менее 750 кг).\\n6. Количество стоек: не указано - несоответствие спецификации (должно быть не менее 4 штук).\\n7. Количество полок: не указано - несоответствие спецификации (должно быть не менее 4 штук).\""');
INSERT INTO public.recommended_products (id, lot_id, product_name, product_description, product_specifications, source_url, price, unit_of_measure, currency, image_url, compliance_score, compliance_details) VALUES (545, 31502210, 'N/A', 'N/A', 'N/A', 'https://satypalu.gov.kz/kz/registry/show_plan/64778726/3427089', 0, 'N/A', 'N/A', NULL, 0, '"\"Невозможно провести анализ соответствия продукта спецификациям, так как детали продукта не предоставлены.\""');


